-- =====================================================
-- Migration 022: Module 1-2 Redesign (v2 Curriculum)
-- =====================================================
-- Replaces the old Module 1 (Love's Foundation) and Module 2
-- (Invisible Chains) with the redesigned v2 curriculum:
--   Module 1: The Seven Devils (4 parent lessons, 24 sub-lessons)
--   Module 2: The Devils Up Close (4 parent lessons, 20 sub-lessons)
--
-- Structure follows the Module 7 parent/child pattern from seed.sql.
-- Each parent lesson has parent_lesson_id = NULL.
-- Each sub-lesson points to its parent via parent_lesson_id.
--
-- Source: Mind Vault v2 markdown, converted via md_to_content_json.py
-- =====================================================

BEGIN;

-- =====================================================
-- STEP 1: Delete old Module 1 and 2 lessons
-- =====================================================
-- Sub-lessons first (foreign key), then parents.
-- Modules 1 and 2 rows are preserved and updated.

-- Delete all lessons under Module 1
DELETE FROM lessons
WHERE module_id = (
  SELECT m.id FROM modules m
  JOIN courses c ON c.id = m.course_id
  WHERE m.module_number = '1'
    AND c.slug = 'healing-hearts-journey'
);

-- Delete all lessons under Module 2
DELETE FROM lessons
WHERE module_id = (
  SELECT m.id FROM modules m
  JOIN courses c ON c.id = m.course_id
  WHERE m.module_number = '2'
    AND c.slug = 'healing-hearts-journey'
);

-- =====================================================
-- STEP 2: Update module titles and descriptions
-- =====================================================

UPDATE modules
SET title = 'The Seven Devils',
    description = 'Name the patterns that run your relationship. Understand why your body hijacks conversations. Learn the SPARK Method. Build your first week of practice.'
WHERE module_number = '1'
  AND course_id = (SELECT id FROM courses WHERE slug = 'healing-hearts-journey');

UPDATE modules
SET title = 'The Devils Up Close',
    description = 'Face each Devil honestly. Criticism and Contempt. Defensiveness and Stonewalling. Avoidance and Unhealthy Coping. Build your Devil Audit and practice plan.'
WHERE module_number = '2'
  AND course_id = (SELECT id FROM courses WHERE slug = 'healing-hearts-journey');

-- =====================================================
-- STEP 3: Insert parent lessons and sub-lessons
-- =====================================================

DO $$
DECLARE
  mod1_id uuid;
  mod2_id uuid;
  parent_id uuid;
BEGIN
  -- Get module IDs
  SELECT m.id INTO mod1_id FROM modules m
  JOIN courses c ON c.id = m.course_id
  WHERE m.module_number = '1' AND c.slug = 'healing-hearts-journey';

  SELECT m.id INTO mod2_id FROM modules m
  JOIN courses c ON c.id = m.course_id
  WHERE m.module_number = '2' AND c.slug = 'healing-hearts-journey';

  -- ─── Lesson 1.1: The Seven Devils ───
  INSERT INTO lessons (module_id, title, sort_order, content_json)
  VALUES (
    mod1_id,
    'The Seven Devils',
    1,
    '{"estimated_minutes":42,"blocks":[{"type":"heading","content":"The Seven Devils"},{"type":"text","content":"Name the seven patterns that quietly dismantle relationships."}]}'::jsonb
  ) RETURNING id INTO parent_id;

  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, content_json) VALUES
    (mod1_id, parent_id, 'The Pattern Nobody Talks About', 101, '{"estimated_minutes":7,"blocks":[{"type":"audio","title":"1:30, Trisha — coaching story in her natural spoken voice"},{"type":"text","content":"She sat on the edge of the couch, hands wrapped around a mug like she was holding herself together. He sat across from her, shoulders pulled in, already bracing for whatever came next."},{"type":"text","content":"\"I just want to talk things through,\" she said. \"When something''s bothering me, I need to get it out. But the minute I bring it up, he feels attacked. He shuts down. And then we don''t talk for days.\""},{"type":"text","content":"He was quiet for a moment. Then: \"I don''t mean to shut down. But when she comes at me, I just feel like I''ve already failed. So I go away. I know it feels like punishment to her. Honestly, it''s more like I''m punishing myself.\""},{"type":"text","content":"She nodded slowly. \"And then I stew. I replay it over and over — what I should have said, what he should have done. I can''t get my system to stop.\""},{"type":"text","content":"I had been sitting with couples for a long time by the day I met them. And in less than five minutes, I could see at least four separate patterns working at once — each one feeding the next, none of them visible to the people living inside them. They weren''t bad people. They weren''t even doing anything intentionally harmful. They were stuck in a pattern that had been running their marriage for years, quiet as a slow leak in the wall."},{"type":"text","content":"That is what I want to talk about in this lesson."},{"type":"heading","content":"The Patterns That Nobody Names"},{"type":"text","content":"Most couples who come to me have tried everything they can think of. They''ve had the hard conversations — or tried to. They''ve apologized. They''ve promised to do better. They''ve read articles, listened to podcasts, maybe even done a weekend retreat. And then, within a few weeks, they''re back in the same place. Same fight. Different Tuesday."},{"type":"text","content":"The reason it keeps coming back isn''t a lack of effort. It isn''t a lack of love. It''s that nobody ever named the pattern."},{"type":"text","content":"You can''t change what you can''t see. And most of what destroys a relationship is invisible — not because it''s hidden, but because it''s so familiar it feels like furniture."},{"type":"text","content":"I call them the Seven Devils. I borrowed the name from Dr. John Gottman''s decades of research on what actually predicts whether a relationship survives or falls apart. Gottman didn''t guess. He watched thousands of couples — in what he called the Love Lab — and tracked exactly what they did when they were fighting, recovering, reaching for each other, and pulling away. He measured stress hormones. He watched facial expressions frame by frame. He could predict, with over ninety percent accuracy, whether a couple would divorce. Not by how much they fought. By which patterns showed up when they fought."},{"type":"text","content":"The first four of the Seven Devils come directly from Gottman''s research. He calls them the Four Horsemen, and the name fits — they ride in together, and they do damage. The final three are patterns I''ve watched in my own work: the slow erosions that happen between the fights, in the quiet days when nothing seems to be wrong except that something feels off."},{"type":"text","content":"Together, all seven form a picture. And when you can see the whole picture, something shifts."},{"type":"heading","content":"You''re Going to Recognize Something in Here"},{"type":"text","content":"I want to say this plainly before we go any further."},{"type":"text","content":"Every single couple I have ever worked with — every one — has shown up with at least two or three of these Devils already running. That includes Jeff and me. It includes couples who seem totally fine from the outside. It includes couples who genuinely love each other deeply and cannot figure out why they keep ending up in the same ditch."},{"type":"text","content":"Recognizing these patterns is not a verdict on your character. It is not proof that your relationship is broken. It is not a reason to feel ashamed of the years you''ve already spent inside them."},{"type":"text","content":"It''s a map. And maps don''t judge you for being lost."},{"type":"text","content":"What matters is that you''re here, and you''re looking."},{"type":"text","content":"In the next few sub-lessons, we''re going to go through each of the Seven Devils — not to diagnose everything at once, but to give each pattern a name. Recognition is the first move. Once you can name it, you can catch it. And once you can catch it, you can do something different."},{"type":"text","content":"There''s something else I want to mention — something that comes up again and again in my work with couples who are ready to make real change. The moment a conversation turns, something shifts in your body before your mind even catches up. Your system makes a decision in a matter of seconds — and by the time you''re choosing your words, that decision is already made."},{"type":"text","content":"We''ll dig into that biology in Lesson 1.2. But I want you to hold it lightly as we go through the Seven Devils: these patterns aren''t happening because you''re weak or unkind. They''re happening because your body learned, at some point, that this conversation is not safe. And your body is very good at protecting you from things that don''t feel safe."},{"type":"text","content":"That changes everything about how we approach this work."},{"type":"text","content":"Let''s start with the first two."}]}'::jsonb),
    (mod1_id, parent_id, 'The Attack: Criticism and Contempt', 102, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"Devil 1 and Devil 2 are the ones I see in almost every struggling relationship. They''re also the ones that are hardest to recognize from the inside, because they feel so much like just... being honest."},{"type":"heading","content":"Devil 1: Criticism"},{"type":"text","content":"Criticism is not the same as a complaint. That distinction matters."},{"type":"text","content":"A complaint focuses on a specific moment: \"I was frustrated this morning when the kitchen was left messy — I need help keeping up with it.\" That''s fair. That''s honest. That is you telling your partner that something bothered you."},{"type":"text","content":"Criticism does something different. It takes a moment and turns it into a verdict on who your partner is as a person."},{"type":"text","content":"\"You never help around the house. You''re so selfish.\"* *\"Why would you say that? You''re so thoughtless sometimes.\"* *\"I can''t believe you forgot again — you''re just not reliable.\""},{"type":"text","content":"Hear the difference? One describes a behavior. The other describes the person. And when your partner hears a permanent label attached to their character, they don''t think: I should try harder. They think: Why bother? You''ve already decided who I am."},{"type":"text","content":"I worked with a woman — I''ll call her Rachel — who couldn''t figure out why her husband had gone so quiet over the years. He used to share things with her. He used to tell her about his day, ask for her opinion, loop her in on what he was thinking. But gradually, across years, he''d pulled back. One day she asked him directly: why don''t you talk to me anymore?"},{"type":"text","content":"He said: \"Because every time I say something, I feel like you''re looking for what''s wrong with it.\""},{"type":"text","content":"She was devastated. She''d had no idea."},{"type":"text","content":"Here''s what he was describing: the slow accumulation of criticism. Not the big dramatic blowups. Not cruelty. Just a steady undercurrent of small corrections, gentle suggestions, and \"helpful\" observations — all of which, over time, had taught him that sharing himself with her wasn''t safe. Not because she was a bad person. But because the pattern had been running long enough that it felt like the truth."},{"type":"text","content":"Criticism makes the person on the receiving end feel defective. And when someone feels defective around you, they stop bringing themselves into the room."},{"type":"text","content":"Watch for the \"always\" and \"never.\" Those are the fingerprints. You always do this. You never think about me. You''re always late. You never listen. Every always and never takes a single moment and turns it into a permanent character flaw. That''s the thing to catch."},{"type":"heading","content":"Devil 2: Contempt"},{"type":"text","content":"If criticism is a splinter, contempt is a wound."},{"type":"text","content":"Gottman''s research is unambiguous on this: contempt is the single greatest predictor of divorce. Not how often you fight. Not how loud you get. Not whether you have money problems or in-law problems or different values about how to raise kids. Contempt. It outpredicts everything else."},{"type":"text","content":"Contempt is what happens when criticism hardens into superiority. It''s the eye roll. The sigh that says I can''t believe I have to deal with this. The sarcasm that''s too sharp to be funny. The tone that communicates, clearly, that you don''t respect the person you''re talking to."},{"type":"text","content":"It sounds like: \"Oh please. Like you actually know anything about this.\" \"Are you seriously telling me you didn''t figure that out? It''s not that complicated.\" \"I''m not surprised. This is exactly what you always do.\""},{"type":"text","content":"Contempt doesn''t just hurt feelings. Gottman''s research found that contempt actually suppresses the immune system of the person on the receiving end. That''s how deep it lands. The body registers contempt as a genuine threat."},{"type":"text","content":"Here''s what makes contempt particularly tricky: it almost always grows slowly. It starts as unspoken frustration. That frustration turns into a habit of noticing everything your partner does wrong. That habit builds a mental highlight reel of failures, disappointments, and proof that your partner is less than. And then, one day, it starts coming out in the way you look at them. In your tone. In the comments you make that you''d tell yourself were \"just honest.\""},{"type":"text","content":"The soil contempt grows in is unappreciation. When we stop seeing what our partner does right — when we stop saying thank you, stop noticing the effort, stop acknowledging what''s working — resentment moves in. And resentment, over time, curdles into something that looks like your partner through a lens of disdain."},{"type":"text","content":"The antidote isn''t a single compliment. It''s building a daily culture of noticing what''s good. That muscle gets stronger with practice. The more you use it, the harder it becomes for contempt to take root."},{"type":"divider"},{"type":"reflection","content":"After reading this section, pause and think about your last significant disagreement."},{"type":"text","content":"Which of these showed up in your last argument — criticism (attacking the person, not the behavior) or contempt (communicating superiority or disdain)?"},{"type":"text","content":"You don''t need to answer out loud. Just notice what comes up when you sit with the question honestly."}]}'::jsonb),
    (mod1_id, parent_id, 'The Shield: Defensiveness and Stonewalling', 103, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"Devil 3 and Devil 4 are the patterns that feel most like self-protection. And in a way, they are. That''s exactly what makes them so hard to catch."},{"type":"heading","content":"Devil 3: Defensiveness"},{"type":"text","content":"When your partner brings up a concern, what''s your first instinct?"},{"type":"text","content":"For a lot of us — myself included, at certain seasons of my marriage — the instinct is to defend. To explain. To point out what they''re missing, or remind them of the context, or bring up the time they did the same thing. It feels like protecting yourself. It feels like making sure you''re not blamed for something that isn''t entirely your fault."},{"type":"text","content":"But here''s what defensiveness actually does in the moment: it tells your partner that their concern doesn''t matter as much as your need to be right."},{"type":"text","content":"Defensiveness sounds like: \"I only said that because you were being dramatic.\" \"Well, what about when YOU forgot last week?\" \"I was trying to help. You''re so sensitive.\""},{"type":"text","content":"Every one of those responses redirects the conversation away from your partner''s experience and back onto yours. And when someone brings you a hurt and gets a counter-argument back, they learn something. They learn that reaching for you leads to a wall. Over time, they stop reaching."},{"type":"text","content":"I hear this constantly in my work. A partner — almost always exhausted, almost always trying not to sound like they''re complaining — will say some version of this: \"I''ve just stopped bringing things up. What''s the point? It always turns into a conversation about what I did wrong.\""},{"type":"text","content":"That''s the quiet cost of defensiveness. It doesn''t block one conversation. It teaches your partner that bringing themselves to you isn''t safe."},{"type":"text","content":"This doesn''t mean accepting blame for everything. It means learning to say: \"You''re right — I did miss that. I''m sorry. What can I do differently?\" Even if the complaint feels only ten percent fair, own that ten percent. Letting your partner''s experience matter to you more than being right is one of the most powerful things you can do in a relationship."},{"type":"heading","content":"Devil 4: Stonewalling"},{"type":"text","content":"Stonewalling is when you leave. Not necessarily physically — though sometimes that too. But emotionally."},{"type":"text","content":"The monosyllable answers: Fine. Whatever. Sure. The eyes that have gone somewhere else. The wall that comes down mid-conversation, usually when things have gotten too intense."},{"type":"text","content":"I want to say something important about stonewalling before we name it as a problem, because the people who do it are almost always suffering as much as the people on the receiving end."},{"type":"text","content":"Stonewalling is almost always a response to being overwhelmed. The person who shuts down isn''t doing it to be cruel. Their system has flooded — heart rate spiking, thoughts scattering, that feeling of not being able to form a sentence, let alone a kind one. The shutdown is protective. It''s an attempt to stop something from getting worse."},{"type":"text","content":"But for the partner on the other side, it feels like abandonment. Like being in the middle of something important and having the door close in their face."},{"type":"text","content":"I worked with a couple — I''ll call them Mark and Laura — who''d been in this cycle for years. He would shut down when conversations got intense; she would escalate, trying to break through the silence; the more she escalated, the further he''d withdraw. Neither of them was the villain. Both of them were in pain."},{"type":"text","content":"The shift came when Mark learned to name it instead of just disappearing. \"I''m starting to shut down. I need ten minutes. I''m not leaving this — I''ll come back.\" Laura didn''t get a wall. She got a door with a doorknob. And over time, that changed everything."},{"type":"text","content":"The key is the return. Taking a break from an overwhelming conversation is not stonewalling — as long as you come back. The difference is whether you''re managing your system so you can reconnect, or whether you''re just escaping."},{"type":"divider"},{"type":"reflection","content":"Think about how your system responds when you feel attacked or overwhelmed in a conversation."},{"type":"text","content":"When conflict gets intense, which direction does your body go — into the fight, or into the freeze?"},{"type":"text","content":"Neither is wrong. Both are your system doing exactly what it learned to do. The question is just: what do you do next?"}]}'::jsonb),
    (mod1_id, parent_id, 'The Escape: Avoidance and Coping', 104, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"Devils 5 and 6 are the quietest ones. They don''t show up in the argument. They show up in the space between arguments — in the things that never get said, the conversations that keep not happening, and the ways we reach for relief when the pressure inside gets too high."},{"type":"heading","content":"Devil 5: Avoidance"},{"type":"text","content":"There is a couple I think about often. I''ll call them Diane and Tom."},{"type":"text","content":"They came to me after years of low-grade tension they couldn''t quite name. They argued, but not dramatically. They loved each other, but something felt off — like a table with one short leg. You can function around it for a long time before you notice how many times a day you''ve been quietly compensating."},{"type":"text","content":"When I started asking about what they didn''t talk about, a silence came into the room that was different from their usual ones."},{"type":"text","content":"There was something they hadn''t spoken about in years. Not because they''d forgotten. Because it was too painful, and neither of them knew how to open the door without breaking something. So they''d built their life carefully around it — never touching it directly, never naming it, just quietly circling the absence every day."},{"type":"text","content":"\"It just brings up feelings and emotions that have never been talked about,\" she finally said. \"Ever.\""},{"type":"text","content":"That word — ever — landed in the room like a stone."},{"type":"text","content":"Avoidance is the conscious decision to not engage with what''s real. It looks like changing the subject. Deciding it''s not the right time — again. Saying \"I''ll deal with that later\" and building an entire lifestyle around not dealing with it. It''s different from stonewalling in a specific way: stonewalling is checking out in the moment. Avoidance is the longer choice. The months-long choice. The years-long choice."},{"type":"text","content":"And here''s what avoidance does that people don''t expect: it doesn''t make the problem disappear. It makes the problem grow roots. Unspoken things don''t dissolve — they go underground, where they come back up sideways. In irritability. In distance. In the sharp edge on a Tuesday evening that has nothing to do with what''s actually happening and everything to do with ten years of a conversation that never happened."},{"type":"text","content":"Name one conversation you''ve been avoiding. You probably already know which one it is."},{"type":"heading","content":"Devil 6: Unhealthy Coping"},{"type":"text","content":"Every person has a way of handling pressure when it builds too high. That''s not a problem — that''s human. The question is what you reach for when the pressure comes."},{"type":"text","content":"Some of what we reach for helps: exercise, time with people we trust, creative work, prayer, being outside. These are the things that actually process the stress instead of just covering it."},{"type":"text","content":"Some of what we reach for just turns the volume down for a while: screens, alcohol, work, food, anything that creates enough noise to stop hearing the thing underneath. This isn''t always dangerous — everyone numbs occasionally. But when numbing becomes the primary way you manage the pressure inside your marriage, it starts creating a second problem. You''re not just dealing with the original stress. You''re also creating distance. You''re also modeling to your partner that this is how you handle difficulty. And you''re also, quietly, choosing the thing you reach for over the person you''re with."},{"type":"text","content":"The question isn''t whether you cope. It''s whether your coping is building anything, or just buying time."},{"type":"text","content":"And sometimes the coping is so woven into your daily life that you don''t see it as coping at all. It just looks like who you are. That''s the version worth examining."},{"type":"divider"},{"type":"reflection","content":"Take a moment with this one."},{"type":"text","content":"Name one conversation you''ve been avoiding with your partner."},{"type":"text","content":"You don''t have to plan to have it right now. Just name it. Acknowledgment is always the first move."}]}'::jsonb),
    (mod1_id, parent_id, 'The Silence: When Intimacy Disappears', 105, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"The seventh Devil is the one people mention last. Sometimes they don''t mention it at all, even though it''s been quietly aching for a long time."},{"type":"text","content":"I''m talking about physical intimacy. The closeness. The reaching for each other not because you need something resolved, but because you want to be near. The thread of physical connection that, when it''s present, holds a lot of other things together — and when it''s gone, leaves a specific kind of loneliness that is hard to describe to someone who hasn''t felt it."},{"type":"text","content":"The Devil of Intimacy Loss is not just about sex, though for many couples that''s part of it. It''s about touch. Warmth. The small things — a hand on the back, a moment of genuine closeness at the end of a long day — that signal to both of you that you''re still in this together."},{"type":"text","content":"When the other six Devils have been running for a while, this one usually follows. Not because anyone decided to withhold anything. But because safety erodes. Because reaching out has gotten complicated. Because there''s a low current of unresolved tension running through the house, and physical closeness requires feeling safe enough to be vulnerable, and vulnerability requires trust, and trust has been quietly chipping away."},{"type":"text","content":"I''m not going to go deep on this one right now. That comes later in the program, and there''s a lot worth knowing — more than this naming lesson can hold. What I want to do here is simply plant a marker."},{"type":"text","content":"If you''ve been feeling a kind of quiet distance — a pulling away from closeness that neither of you planned and neither of you knows exactly how to reverse — you''re not imagining it. That''s the seventh Devil, and it''s real, and it''s workable."},{"type":"text","content":"We''ll come back to it. For now, just notice whether it''s present."}]}'::jsonb),
    (mod1_id, parent_id, 'Which Devils Do You Recognize?', 106, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"You''ve just met all seven."},{"type":"text","content":"Criticism. Contempt. Defensiveness. Stonewalling. Avoidance. Unhealthy Coping. The Loss of Intimacy."},{"type":"text","content":"Before we move forward, I want to give you a moment to sit with them — not as abstract concepts, but as your specific life. Because the work we''re doing here is always, underneath the frameworks and the research, about you and your partner and the particular shape of what''s been running between you."},{"type":"heading","content":"Self-Assessment: Your Seven Devils Inventory"},{"type":"text","content":"Read each item below and mark honestly. No one sees this but you."},{"type":"divider"},{"type":"text","content":"Devil 1 — Criticism When I''m frustrated with my partner, I tend to:"},{"type":"list","items":["Describe the specific behavior that bothered me","Describe my partner as the problem (\"you always,\" \"you never\")","Both, depending on how activated I am"],"ordered":false},{"type":"text","content":"Devil 2 — Contempt In conflict, I sometimes:"},{"type":"list","items":["Roll my eyes or use a tone that communicates superiority","Make sarcastic comments I''d describe as \"just being honest\"","Hold a running mental log of my partner''s failures","None of these feel like me — I tend to criticize outward, not look down"],"ordered":false},{"type":"text","content":"Devil 3 — Defensiveness When my partner brings up a concern, my first move is usually:"},{"type":"list","items":["To listen and acknowledge, even if it''s uncomfortable","To explain why they''re wrong or missing context","To bring up something they did","It depends entirely on how it''s brought up"],"ordered":false},{"type":"text","content":"Devil 4 — Stonewalling When a conversation gets too intense, I tend to:"},{"type":"list","items":["Stay present, even when it''s hard","Go quiet and wait for it to pass","Leave the room, physically or emotionally","Give one-word answers until it''s over"],"ordered":false},{"type":"text","content":"Devil 5 — Avoidance Right now, there is a conversation I have been putting off having with my partner."},{"type":"list","items":["Yes — I know exactly what it is","Maybe — there''s something I keep almost bringing up","Not that I''m aware of"],"ordered":false},{"type":"text","content":"Devil 6 — Unhealthy Coping When the pressure inside my marriage gets high, I reach for:"},{"type":"list","items":["Something that actually processes the stress (movement, connection, reflection)","Something that turns the volume down without resolving anything","I''m honestly not sure — I haven''t examined it closely"],"ordered":false},{"type":"text","content":"Devil 7 — Intimacy Loss The physical closeness between me and my partner right now feels:"},{"type":"list","items":["Warm and present","Reduced — not dramatically, but there''s a pulling away","Almost absent — this is one of the harder things in our relationship right now"],"ordered":false},{"type":"divider"},{"type":"heading","content":"What You Just Did"},{"type":"text","content":"I want to name what just happened here, because it matters."},{"type":"text","content":"You looked. Clearly and honestly. At patterns that most people spend years living inside without ever examining."},{"type":"text","content":"That is not a small thing."},{"type":"text","content":"You may have recognized one Devil. You may have recognized five. Either way, what you''re holding right now is information — not a verdict. These patterns are not proof of who you are as a partner. They are not proof that your relationship is damaged beyond repair. They are what happens when two people who love each other have been under pressure long enough, without the tools to respond differently."},{"type":"text","content":"That changes."},{"type":"heading","content":"Implementation Intention"},{"type":"text","content":"Before you move to the next lesson, take a moment to write this down — or just hold it clearly in your mind."},{"type":"divider"},{"type":"text","content":"The one Devil I want to notice this week is \\_\\_\\_\\_\\_\\_\\_\\_\\_\\_\\_."},{"type":"text","content":"When it shows up, I will \\_\\_\\_\\_\\_\\_\\_\\_\\_\\_\\_."},{"type":"divider"},{"type":"text","content":"Don''t try to fix it yet. Just notice. Catching the pattern in real time — even once — is worth more than a hundred plans made in calm moments. Awareness is always the first move."},{"type":"heading","content":"A Note Before You Go"},{"type":"text","content":"If this lesson brought up something heavier than you expected — if looking at these patterns landed somewhere deeper than recognition — I want you to know that this makes sense. You may be carrying a lot. Some of what you''re carrying may be too large for a course to hold on its own. If that''s true, please consider reaching out to a therapist or counselor. This work matters, and so do you."},{"type":"text","content":"For the rest of you: what you''ve done here is look honestly at patterns that most couples don''t name until a lot of damage has already been done. You didn''t wait that long. And that means something."},{"type":"divider"},{"type":"text","content":"These patterns are not character flaws. They are what happens when your body decides the conversation is no longer safe. In the next lesson, I''m going to show you why."},{"type":"divider"},{"type":"reflection","content":"A Gratitude and a Takeaway"},{"type":"text","content":"Before you close this lesson, take one minute."},{"type":"text","content":"What''s one thing you''re grateful for as you sit with what you learned today — even if it''s just that you showed up and looked honestly?"},{"type":"text","content":"And what''s one thing you''re taking with you?"}]}'::jsonb);

  -- ─── Lesson 1.2: Your Critter Brain and Your CEO Brain ───
  INSERT INTO lessons (module_id, title, sort_order, content_json)
  VALUES (
    mod1_id,
    'Your Critter Brain and Your CEO Brain',
    2,
    '{"estimated_minutes":48,"blocks":[{"type":"heading","content":"Your Critter Brain and Your CEO Brain"},{"type":"text","content":"The nervous system foundation. Why the Seven Devils have so much power over your body."}]}'::jsonb
  ) RETURNING id INTO parent_id;

  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, content_json) VALUES
    (mod1_id, parent_id, 'The Four-Second Window', 201, '{"estimated_minutes":8,"blocks":[{"type":"text","content":"Remember the Seven Devils from our last lesson? The criticism, the contempt, the defensiveness, the stonewalling, the avoidance, the unhealthy coping, the loss of intimacy? You saw them. You named the ones living in your relationship. Maybe you even had that unsettling moment of recognition — that''s us."},{"type":"text","content":"Good. That recognition matters."},{"type":"text","content":"But here is the question the Seven Devils leave behind: Why? Why does a sigh from your partner send your heart racing? Why can a single look undo an entire evening? Why do two people who genuinely love each other keep ending up in the same fight, saying the same words, feeling the same helplessness — over and over again?"},{"type":"text","content":"The answer is not in your head. It is in your body."},{"type":"divider"},{"type":"text","content":"I asked her what happened when she tried all those things — the replaying, the rehearsing, the figuring out exactly what she''d say differently next time."},{"type":"text","content":"She laughed, but it wasn''t a happy laugh. \"None of it works. I know it doesn''t work. But it''s like I can''t get my body to stop.\""},{"type":"text","content":"She paused, surprised by what she''d just said. Like she''d been running this program for years without ever naming it out loud."},{"type":"text","content":"\"It just goes into this fight-or-flight thing,\" she said. \"My chest gets tight, my thoughts start racing, and I''m up at two in the morning going over every word. I know it''s not helping. I know I should just sleep. But my body won''t let me.\""},{"type":"text","content":"Her mind knew better. Her body didn''t care."},{"type":"divider"},{"type":"text","content":"That moment — the one where your body makes a decision without asking you first — happens in about four seconds. Four seconds between \"we''re having a conversation\" and \"we''re in a fight.\" Four seconds between a raised eyebrow and a racing heart. Four seconds between \"I was going to stay calm this time\" and \"I just said something I didn''t mean.\""},{"type":"text","content":"The fight does not start when the voices rise. The fight starts about four seconds earlier, in your body, in a place you cannot see."},{"type":"text","content":"By the time the words come out, the decision has already been made. You were not choosing to snap or to shut down or to go cold. Some older, faster part of you made the call, and your mouth caught up with it. You cannot out-communicate a decision your nervous system made four seconds ago — no matter how good you are with words, no matter how much you love the person across the table from you."},{"type":"text","content":"That is not a failure of love. That is how bodies work."},{"type":"text","content":"And that is why this lesson exists. Before we can change anything about the way you fight, we have to understand the system that is actually running the show — the part of you that decides, in a fraction of a second, whether a conversation is safe or dangerous."},{"type":"text","content":"Once you see it, everything changes. Not because the system goes away, but because you finally understand what you are working with."},{"type":"reflection","content":"Take a quiet moment with these: 1. Think of a recent moment when your body seemed to decide something before your mind caught up. What happened in your chest, your stomach, your hands? 2. What was the conversation about — and was the reaction your body had actually proportional to what was said?"}]}'::jsonb),
    (mod1_id, parent_id, 'Meet Your Critter Brain', 202, '{"estimated_minutes":10,"blocks":[{"type":"text","content":"So who is making the decision in that four-second window?"},{"type":"text","content":"It is not you. Not the you who planned to have a calm conversation this evening. Not the you who loves this person and has loved them for years. Not the you who knows better."},{"type":"text","content":"The you who is running the show in that moment is older than all of that. It is a part of your nervous system that was installed before you had language. Its whole job is to keep you alive, and it has exactly one question it is always asking: Am I safe, or am I in danger?"},{"type":"text","content":"If the answer is \"danger, even a little,\" it grabs the wheel and drives. No permission. No pause. No consultation with the wiser, more thoughtful parts of you."},{"type":"text","content":"My husband Jeff and I have a nickname for this part of you. We call it the Critter Brain."},{"type":"text","content":"I''ve had the privilege of studying under Leah Davidson, one of the leading voices in nervous-system resilience and trauma recovery, and Thais Gibson, whose work on attachment and the subconscious mind has shaped how I understand the deeper patterns that keep people stuck. The teachings in this lesson are tailored from their frameworks and layered with my own practiced experience and additional learning over the years."},{"type":"heading","content":"The Critter Brain — Your Survival Driver"},{"type":"text","content":"Your Critter Brain, sometimes called the dinosaur brain or brainstem, has many nicknames. It''s your in-house security guard: loyal, reactive, and definitely not a fan of taking risks."},{"type":"text","content":"It lives deep in your brainstem and limbic system and runs your automatic survival systems:"},{"type":"list","items":["Heartbeat","Breathing","Reflexes","Digestion","Hormones and Adrenaline"],"ordered":false},{"type":"bold_text","content":"Your Critter Brain:"},{"type":"list","items":["Doesn''t like to take risks or try new things","Avoids growth because it feels unpredictable","Pulls you back to your lowest, most familiar state because it knows you can survive there","Believes safety equals familiarity, even if what''s familiar is miserable","Prefers comfort over courage","Doesn''t plan ahead"],"ordered":false},{"type":"text","content":"It protects. It''s the part of your nervous system that says, \"Nope, too scary, stay small so you can stay comfortable.\""},{"type":"text","content":"That''s why people stay stuck in patterns they hate, not because they''re weak, but because their Critter Brain equates change with danger."},{"type":"text","content":"The Critter Brain is like a smoke alarm. It is quick to react and terrible at distinguishing between burnt toast and a house fire. So when your partner sighs or your child slams a door, your Critter Brain might send the full emergency crew racing to the scene."},{"type":"text","content":"It''s always asking one question: \"Am I safe or am I in danger?\" And if there''s even a chance of pain, panic, or uncertainty, it slams on the brakes."},{"type":"heading","content":"When the Amygdala Hijacks the Wheel"},{"type":"text","content":"You may have heard the phrase, \"your amygdala is being hijacked.\" That''s exactly what''s happening when your Critter Brain takes control."},{"type":"text","content":"The amygdala is the alarm center deep inside your Critter Brain. Its job is to detect threat, danger, or emotional risk and instantly alert your entire body to respond."},{"type":"text","content":"The moment it senses something unsafe — a sharp tone, a disapproving look, or even a familiar memory — your amygdala hits the panic button before your CEO Brain has a chance to weigh in."},{"type":"text","content":"It''s lightning fast. It bypasses logic. \"We''re not safe. Do something now!\""},{"type":"text","content":"That''s an amygdala hijack, but we''ll keep it simple and call it your Critter Brain. It''s that moment when your body floods with stress hormones, your thoughts narrow, and your words become sharper or quieter. You can''t \"just calm down\" because your Critter Brain has grabbed the wheel and sent your CEO Brain to the backseat."},{"type":"text","content":"The good news is that you can train your body to notice the hijack sooner and recover faster. That''s what we are here to help you do."},{"type":"heading","content":"Critter Brain in Action — Relationships"},{"type":"list","items":["Critter Brain''s Move: Fight | What it Looks Like: \"You never listen!\" — sharp tone, high energy, heart pounding","Critter Brain''s Move: Flight | What it Looks Like: \"Forget it.\" — walks away, shuts down, escapes to work or phone","Critter Brain''s Move: Freeze | What it Looks Like: Blank stare, numbness, can''t think or speak","Critter Brain''s Move: Fawn | What it Looks Like: \"It''s fine!\" — appeases, over-apologizes, tries to keep the peace"],"ordered":false},{"type":"text","content":"When your Critter Brain is in charge you can''t think straight, not because you''re broken, but because your body has chosen survival over logic."},{"type":"text","content":"Now look at that table again — and think about the Seven Devils. Criticism lives in fight. Stonewalling lives in freeze. Avoidance lives in flight. Fawning is where resentment is born, because every \"It''s fine!\" that isn''t fine adds another layer. The Devils are not personality flaws. They are your Critter Brain''s survival playbook."},{"type":"audio","title":"1:30, Trisha — personal aside about her own Critter Brain in her marriage with Jeff"},{"type":"reflection","content":"Think of one time your Critter Brain took over this past week. 1. What did your body do? 2. What did your mind say? 3. Looking at the table above — which move did your Critter Brain choose?"}]}'::jsonb),
    (mod1_id, parent_id, 'Your CEO Brain', 203, '{"estimated_minutes":9,"blocks":[{"type":"text","content":"Inside each of us lives a dynamic duo, the two drivers of your emotional life. They''re both brilliant, but they have very different jobs."},{"type":"text","content":"Your Critter Brain is your Survival Driver. And the wiser, more thoughtful part — the one that got its keys taken away during that four-second window — we call the CEO Brain."},{"type":"heading","content":"The CEO Brain — Your Wise Driver"},{"type":"text","content":"Your CEO Brain lives in your prefrontal cortex, the planner, problem-solver, and compassionate leader. If your Critter Brain''s motto is \"Survive,\" your CEO Brain''s motto is \"Thrive.\""},{"type":"text","content":"It''s the part of you that loves to:"},{"type":"list","items":["Learn new things","Take healthy risks","Dream, plan, and problem-solve","Explore new experiences","See the bigger picture"],"ordered":false},{"type":"text","content":"While your Critter Brain avoids discomfort, your CEO Brain thrives on challenge and change. It loves growth, creativity, and learning from mistakes."},{"type":"bold_text","content":"Your CEO Brain:"},{"type":"list","items":["Stays curious instead of critical","Responds with empathy instead of reactivity","Makes decisions that align with your values","Stays open to feedback instead of defensive","Listens with your heart and stays present through hard conversations"],"ordered":false},{"type":"text","content":"But the moment your Critter Brain senses threat, it yanks the wheel away. Your body reroutes blood flow away from your CEO Brain and into survival mode. That''s why, mid-argument, your IQ seems to drop and your CEO has been temporarily \"fired.\""},{"type":"text","content":"The key is not to shame the Critter Brain but to gently recruit your CEO Brain through awareness, curiosity, and safety."},{"type":"heading","content":"The Vagus Nerve — Your Superhighway of Safety"},{"type":"text","content":"Running quietly through your body is a long, wandering nerve called the Vagus Nerve — the word vagus actually means \"wanderer.\" And wander it does."},{"type":"text","content":"This nerve connects your brain to your face, heart, lungs, and gut, traveling through nearly every major organ in your torso. It''s the ultimate mind-body messenger — your built-in communication superhighway that keeps every system in sync."},{"type":"text","content":"When it''s working well, you feel safe, connected, calm, and grounded. When it''s disrupted, you may feel anxious, numb, reactive, or shut down."},{"type":"text","content":"Imagine the Vagus Nerve like a five-lane interstate:"},{"type":"list","items":["Four lanes (80%) send messages from your body up to your brain","One lane (20%) sends messages from your brain down to your body"],"ordered":false},{"type":"text","content":"That means most communication is bottom-up. Your body is constantly whispering to your brain: \"Are we safe? Is this familiar? Can I rest, or do I need to protect myself?\""},{"type":"text","content":"This is why you can''t \"think\" your way into calm when your body is signaling danger. If you only rely on logic or willpower from the brain, you''re driving against traffic."},{"type":"text","content":"To truly regulate your nervous system, you have to speak your body''s language: breath, movement, sound, and connection."},{"type":"text","content":"Each time you:"},{"type":"list","items":["Take a slow, intentional breath","Unclench your jaw or shoulders","Make gentle eye contact with someone you trust","Hug, sing, laugh, or even hum softly"],"ordered":false},{"type":"text","content":"...your Vagus Nerve sends a signal to your Critter Brain that says: \"Stand down, the fire''s out, we''re safe now.\""},{"type":"text","content":"When that happens, your CEO Brain — the part responsible for clarity, empathy, and decision-making — can finally come back online."},{"type":"heading","content":"Why This Matters for Your Relationship"},{"type":"text","content":"Your Vagus Nerve isn''t just about your individual calm; it''s also about co-regulation."},{"type":"text","content":"When your nervous system feels safe, you can help your partner''s system feel safe too. You breathe slower, speak softer, and your tone, face, and presence tell them: \"It''s okay, you''re safe with me.\""},{"type":"text","content":"This is one of the greatest gifts you can give each other — to become a safe harbor for one another''s nervous system."},{"type":"text","content":"And this is exactly why the Seven Devils do so much damage. Each Devil disrupts co-regulation. Criticism tells your partner''s Critter Brain: \"You are being evaluated.\" Contempt says: \"You are less than me.\" Stonewalling says: \"You are not worth responding to.\" Every Devil sends the same message to your partner''s nervous system: \"You are not safe here.\""},{"type":"text","content":"Understanding the Vagus Nerve is understanding why your relationship lives or dies in the body — not in the conversation."},{"type":"audio","title":"1:00, Jeff — medical perspective on why nervous system science matters for relationships"}]}'::jsonb),
    (mod1_id, parent_id, 'The 90-Second Wave', 204, '{"estimated_minutes":10,"blocks":[{"type":"text","content":"Here is something that changes everything once you really hear it:"},{"type":"text","content":"A fully felt emotion lasts about 90 seconds."},{"type":"text","content":"That''s it. Ninety seconds from the first surge to the moment it begins to fade. The biochemical wave — the adrenaline, the cortisol, the heat, the tightness — rises, crests, and falls in about a minute and a half."},{"type":"text","content":"The hours or days of spiraling that follow? Those are powered by the story your mind attaches to the emotion. The emotion is not the problem. The meaning you attach to it is."},{"type":"text","content":"Stories like:"},{"type":"list","items":["\"Something must be wrong\"","\"I shouldn''t feel this way\"","\"I think he''s mad at me\"","\"She''s ignoring me\"","\"They don''t care\"","\"I''m failing\"","\"I must be too much\""],"ordered":false},{"type":"text","content":"Sound familiar? Those are your Critter Brain''s greatest hits — the stories it plays on repeat to keep you in protection mode long after the actual wave has passed."},{"type":"heading","content":"Mastery vs. Control"},{"type":"text","content":"Mastering your emotions has nothing to do with controlling them."},{"type":"text","content":"Trying to control your emotions is like shaking a bottle of Coca-Cola and then stuffing Mentos inside before tightening the lid. What happens when you keep that sealed up too long? It EXPLODES!"},{"type":"text","content":"It was never really about the dog or the mess. It''s about everything that''s been quietly stacking up underneath the surface."},{"type":"bold_text","content":"Suppressed emotions don''t disappear; they just build pressure."},{"type":"text","content":"When I say \"mastering your emotions,\" I mean understanding your emotional landscape:"},{"type":"list","items":["Knowing the territory and terrain","Where the cliffs and valleys reside","What changes the weather","How to find your way back home to safety"],"ordered":false},{"type":"text","content":"It''s about understanding what''s happening inside you and learning to work with your emotions instead of against them."},{"type":"heading","content":"Let It Rise. Let It Crest. Let It Fall."},{"type":"text","content":"Mastering your emotions begins by fully experiencing them. This means releasing the judgment, labels, and the running commentary in your mind."},{"type":"text","content":"It means anchoring yourself in your heart and allowing the emotion to wash over you, roll through you, vibrate through your cells, and then complete its biological cycles. That moment where your nervous system finally signals: \"I''m safe again.\""},{"type":"text","content":"When you allow emotions to rise and fall like waves with curiosity and compassion, your nervous system learns an important truth. It''s safe to feel."},{"type":"text","content":"You don''t need to cry dramatically, yell, throw things, or explain your emotions like a TED talk. This isn''t about performing or proving anything."},{"type":"text","content":"It''s about permission — quiet, steady permission to simply be human. Your only job is to let the emotion do what it came to do: Move."},{"type":"heading","content":"The 90-Second Wave Practice"},{"type":"text","content":"When you feel a strong emotion rising, try this:"},{"type":"list","items":["Pause — stop fixing or analyzing","Place one hand on your chest or belly","Inhale slowly ... exhale slowly","Name what''s here — \"This is sadness,\" \"This is anger\"","Notice where you feel it — chest, throat, stomach","Stay with it for 90 seconds","Watch it shift, soften, or move"],"ordered":true},{"type":"text","content":"That''s the wave. That''s mastery in motion."},{"type":"heading","content":"A Real-Life Moment"},{"type":"text","content":"Imagine you wake up already tired. You spill orange juice down your white shirt. You step on Legos (which, frankly, should count as a weapon). A text comes in that hits the wrong nerve."},{"type":"text","content":"You feel the heat rising: frustration, overwhelm, irritation."},{"type":"text","content":"Old training says: \"Push it down. Act fine. Keep moving.\""},{"type":"text","content":"New training says: Place a hand on your chest. \"Pause. Breathe. Let the wave move for 90 seconds.\" \"I''m overwhelmed. My body is overloaded.\""},{"type":"text","content":"No fixing. No drama. No story. Just presence."},{"type":"text","content":"As the Critter Brain relaxes, the CEO Brain returns. Clarity comes back. Breath evens out. Words soften."},{"type":"text","content":"Think about how this connects to the Seven Devils. Every Devil thrives on what happens after the 90-second wave — in the story, not the surge. Criticism is a story about what your partner should have done. Contempt is a story about what they are. Resentment is a story that has been building for months or years. If you can ride the wave without feeding the story, the Devils lose their grip. Not all at once. But one wave at a time."},{"type":"heading","content":"Guided Practice"},{"type":"text","content":"Choose one emotion you expect to feel this week — frustration, sadness, overwhelm, or another — and commit to riding the 90-second wave the next time it appears. Afterward, notice:"},{"type":"list","items":["What happened in your body during the 90 seconds?","Did the feeling shift on its own?","What story was your mind trying to attach?"],"ordered":false}]}'::jsonb),
    (mod1_id, parent_id, 'The Zones You Live In', 205, '{"estimated_minutes":10,"blocks":[{"type":"text","content":"Now that you understand the 90-second wave — the weather system inside you — it''s time to explore the bigger landscape: your nervous system itself. This is about learning the geography of your system: where emotions live, how they travel, and how to find your way back home when the storm hits."},{"type":"text","content":"Every person''s map looks different."},{"type":"list","items":["Some have wide valleys of calm, where stress passes easily and repair feels natural.","Others live near steep cliffs, where one wrong step (or tone of voice) can send things spiraling downward fast."],"ordered":false},{"type":"text","content":"There''s no \"good\" or \"bad\" map, only awareness. When you understand your landscape, you stop judging your reactions and start guiding them."},{"type":"heading","content":"Your Emotional Landscape Map"},{"type":"text","content":"Hold your hands out in front of you, one about six inches above the other."},{"type":"text","content":"This space between your hands represents your Green Zone — your home base of calm and safety. It sits right in the middle, between the highs of stress and the lows of shutdown."},{"type":"list","items":["Above it lies the Hyper Zones — where your system revs up and energy rises.","Below it is the Hypo Zones — where everything begins to slow or even shut down completely for protection."],"ordered":false},{"type":"text","content":"Your nervous system is always shifting along this map. Learning to recognize where you are on it is the beginning of every healing choice you make."},{"type":"heading","content":"The Five Zones"},{"type":"divider"},{"type":"bold_text","content":"Red Zone — Team Hyper (Full Activation)"},{"type":"text","content":"\"Your body hits the gas to survive.\""},{"type":"text","content":"When stress keeps coming and your system doesn''t feel safe, your Critter Brain jumps into overdrive. Adrenaline floods your system, and your CEO Brain goes offline because logic and love don''t matter when your body thinks it''s in danger. Your body prepares for protection, not connection."},{"type":"text","content":"You''re not choosing to lose control — you''re just trying to stay alive."},{"type":"text","content":"What it feels like: Anger, panic, urgency, racing thoughts. Heart racing, tense, hot. The moment you storm out or slam the door. It''s not you being dramatic (well... maybe a little bit). It''s your Critter Brain yelling, \"I''m not safe!\" even though your partner is just trying to talk to you."},{"type":"divider"},{"type":"bold_text","content":"Yellow Hyper Zone — Going into Team Hyper (Early Activation)"},{"type":"text","content":"\"You can feel your system starting to rev up.\""},{"type":"text","content":"This is that subtle moment before full activation — when something small suddenly starts to feel big. Maybe it''s a tone, a look, a text that feels a little off, or the sting of being ignored. You''re not in full fight-or-flight yet, but your Critter Brain has perked up and your CEO Brain just dimmed the lights a little."},{"type":"text","content":"It''s like your foot''s on the brake, but with each breath, you''re pressing harder on the gas. The engine''s heating up fast — and at this point, you can go either way: ease off the gas and settle your system, or keep pressing and feel it start to spiral."},{"type":"text","content":"What it feels like: Irritated, tense, restless, annoyed, shorter fuse, sarcasm. Your partner walks in late, heads straight to the fridge, and doesn''t even say hello. That quick spark — the one that flares up after waiting all day to connect — turns into \"Are you kidding me right now?\" energy bubbling up inside."},{"type":"divider"},{"type":"bold_text","content":"Green Zone — Team Resilient (Home Base)"},{"type":"text","content":"\"This is where safety, clarity, and connection live.\""},{"type":"text","content":"Your body is steady and grounded; your mind is clear; your heart is open. This is your optimal state. You are calm yet alert, peaceful yet engaged."},{"type":"text","content":"Your CEO Brain is back at the wheel, calm and in control. Meanwhile, your Critter Brain can finally kick back in the back seat, take a nap, and stop singing off-key to the radio while trying to grab the wheel."},{"type":"text","content":"What it feels like:* Connection, humor, empathy, playfulness. This is where you say things like, *\"Hey, I know things got a little heated earlier... can we take a breath and try again?\"* and *\"I can tell you''re having a rough day. Do you want space or a hug?\""},{"type":"text","content":"When both partners are in Green, connection feels natural and repair happens faster. This is home base — the space where you both remember, \"We''re on the same team.\""},{"type":"divider"},{"type":"bold_text","content":"Yellow Hypo Zone — Going into Team Hypo (Early Shutdown)"},{"type":"text","content":"\"When your system quietly whispers, ''I''ve had enough,'' a deep sense of fatigue begins to set in.\""},{"type":"text","content":"After too much stress or stimulation, your nervous system begins pressing the brakes. You''re not fully shut down yet, but you''re definitely slowing — like your internal battery is flashing low power mode."},{"type":"text","content":"You might sigh more often. Zone out mid-conversation. Scroll your phone instead of replying. Say, \"I''m fine,\" when you''re clearly not. Everything feels heavier — like you''re moving through molasses. You crave quiet but don''t know how to ask for it."},{"type":"text","content":"What it feels like: Foggy, tired, disengaged, disinterested. Your partner starts sharing something emotional, and you catch yourself nodding, but your brain is quietly buffering. You care deeply, but you simply don''t have the bandwidth."},{"type":"divider"},{"type":"bold_text","content":"Blue Zone — Team Hypo (Full Shutdown)"},{"type":"text","content":"\"When everything inside you just... stops.\""},{"type":"text","content":"This is the place beyond exhaustion. Beyond overwhelmed. Where your system finally says, \"I''m done.\""},{"type":"text","content":"It''s not sadness exactly — it''s the absence of feeling. You''re not running, not fighting, not even thinking. You''re just... numb. Your Critter Brain has hit the emergency brake and pulled you into hibernation. It''s not a choice — it''s protection."},{"type":"text","content":"What it feels like: Numb, heavy, disconnected, checked out. Your partner asks, \"Are you okay?\" and you can barely find words. Thoughts thick like mud. Shame for \"checking out.\" But you''re not broken — you''re offline."},{"type":"divider"},{"type":"heading","content":"The Five Zones — Summary"},{"type":"list","items":["Zone: Red (Hyper) | State: Full Activation / Fight-Flight | Driver: Critter Brain driving | Feels Like: Anger, panic, urgency, racing thoughts | Reset Strategy: Step away, move or shake your body, cold water/ice, deep breathing, gentle self-talk","Zone: Yellow Hyper | State: Early Activation / Mild Dysregulation | Driver: Critter Brain alert, CEO Brain dimming | Feels Like: Irritated, tense, restless, annoyed, shorter fuse, sarcasm | Reset Strategy: Name it out loud, long exhales, unclenching jaw, 5 senses","Zone: Green | State: Home Base / Regulation / Team Resilient | Driver: CEO Brain driving | Feels Like: Connection, humor, empathy, playfulness | Reset Strategy: Maintain routines, rest, gratitude, laughter, connection, mindful movement","Zone: Yellow Hypo | State: Early Shutdown / Fatigue / Withdrawal | Driver: Critter Brain alert, CEO Brain dimming | Feels Like: Foggy, tired, disengaged, disinterested | Reset Strategy: Light movement, hydration, sunlight, gentle connection, music, gratitude check-in","Zone: Blue (Hypo) | State: Full Shutdown | Driver: Critter Brain driving | Feels Like: Numb, heavy, disconnected, checked out | Reset Strategy: Gentle warmth, safe presence, movement, soft conversation, celebrate tiny wins"],"ordered":false},{"type":"text","content":"Your job isn''t to stay in the Green Zone constantly. (If you figure that out, please call me immediately — you can teach and I''ll bring snacks.)"},{"type":"text","content":"It''s to notice more quickly when you''ve left it and to know how to find your way back home to safety."},{"type":"heading","content":"Assessment: Where Do You Live?"},{"type":"text","content":"Answer honestly — there are no wrong answers here. Think about the last seven days."},{"type":"list","items":["When I wake up, my body usually feels: (a) tense and buzzing, (b) calm and steady, (c) heavy and slow","In conversation with my partner, I most often feel: (a) on edge or ready to react, (b) open and present, (c) checked out or far away","When something goes wrong, my first instinct is to: (a) fight or fix it immediately, (b) pause and figure it out, (c) withdraw or go quiet","My energy at the end of the day is usually: (a) wired, hard to wind down, (b) tired but peaceful, (c) drained, empty","If my partner said something that stung, I would most likely: (a) fire back or get defensive, (b) take a breath and ask about it, (c) say nothing and stew"],"ordered":true},{"type":"text","content":"Mostly (a): You''ve been spending a lot of time in the Hyper Zones — Yellow Hyper or Red. Your system is running hot. The reset strategies in the top half of the table are built for you."},{"type":"text","content":"Mostly (b): You''re living in or near the Green Zone. This is your home base. The work now is about staying aware so you can catch the moments you start to drift."},{"type":"text","content":"Mostly (c): You''ve been spending time in the Hypo Zones — Yellow Hypo or Blue. Your system is running low. The reset strategies in the bottom half of the table are built for you."},{"type":"text","content":"One more question: Over the last seven days, when you''ve felt \"off,\" which direction does your body tend to go?"},{"type":"list","items":["Hotter, faster, more reactive (hyper direction)","Slower, heavier, more withdrawn (hypo direction)","Both, depending on the day"],"ordered":false},{"type":"text","content":"This tells you your default direction — the way your Critter Brain prefers to protect you. Neither direction is better or worse. Both are your body doing its job. Knowing your direction is how you start choosing the right reset."}]}'::jsonb),
    (mod1_id, parent_id, 'The 30-Second Reset', 206, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"Your nervous system isn''t fixed; it''s trainable. Every breath, every pause, every time you choose safety over reactivity, you are changing the circuitry in your brain."},{"type":"text","content":"Neuroscience calls this neuroplasticity — your brain''s lifelong ability to rewire, rebuild, and relearn new patterns."},{"type":"text","content":"It''s taken your nervous system a lifetime to get where it is today, shaped by your genetics, experiences, stress, and relationships. It''s completely normal that it will take time, repetition, and compassion to change it."},{"type":"text","content":"The beautiful truth is that it can absolutely change."},{"type":"text","content":"It''s not about forcing your nervous system; it''s about inviting it. Each small act of regulation is a quiet vote for healing."},{"type":"text","content":"So here is the simplest practice I can give you. It takes thirty seconds. You can do it anywhere — in your car, at your desk, in the bathroom before a hard conversation, lying in bed at two in the morning when your thoughts won''t stop. This is your emergency bridge back to safety."},{"type":"heading","content":"The 30-Second Reset"},{"type":"audio","title":"2:00, Trisha guided — \"Place your hand on your heart. I''ll breathe with you.\""},{"type":"text","content":"Step 1: Place your hand on your heart."},{"type":"text","content":"Feel the warmth of your palm against your chest. Let the weight of your hand tell your body: I''m here. I''m paying attention."},{"type":"text","content":"Step 2: Take a slow inhale through your nose. Fill your lungs about three-quarters of the way. Then take a small top-off inhale — fill the rest of the way up."},{"type":"text","content":"Step 3: Exhale through your mouth with an audible sigh. Let the sound out. Don''t hold it in. The sigh is the signal — it tells your Vagus Nerve to send the \"stand down\" message to your Critter Brain."},{"type":"text","content":"Repeat three times. Three breaths. That''s the whole practice."},{"type":"text","content":"By the third exhale, you will probably notice: softer eyes, a slower heart, shoulders starting to drop, a warmer feeling somewhere in your chest. That is your body coming back online. You have just told your Critter Brain, \"We''re safe now,\" and invited your CEO Brain back into the room."},{"type":"fillable_form","form_id":"your-implementation-intention","title":"Your Implementation Intention","fields":[],"intro":"A practice only works if you remember to use it. So let''s make this specific. Complete this sentence: > \"The next time I feel my body start to ____________, I will place my hand on my heart and take three breaths before I say or do anything else.\" Fill in the blank with your signal — the thing your body does first when your Critter Brain takes the wheel. Maybe it''s your jaw clenching. Maybe it''s the heat in your face. Maybe it''s the urge to check your phone and disappear. Whatever it is, name it. That''s your doorbell. The 30-Second Reset is what you do when you hear it ring."},{"type":"fillable_form","form_id":"fillable-form-my-30-second-reset-plan","title":"Fillable Form: My 30-Second Reset Plan","fields":[{"id":"field_1","label":"My Critter Brain''s favorite move","type":"textarea","rows":2,"placeholder":"fight / flight / freeze / fawn"},{"id":"field_2","label":"The first thing my body does when I''m activated:","type":"textarea","rows":2,"placeholder":""},{"id":"field_3","label":"The place where I''m most likely to need this practice","type":"textarea","rows":2,"placeholder":"kitchen? car? bedroom? work?"},{"id":"field_4","label":"After I practice today, I noticed:","type":"textarea","rows":2,"placeholder":""}]},{"type":"divider"},{"type":"heading","content":"The Power of Repetition"},{"type":"text","content":"Each of these signals safety to your Critter Brain and gently teaches your body that it''s okay to exhale, soften, and trust again."},{"type":"text","content":"When practiced regularly, these small choices begin to add up. Over time, your nervous system learns that safety isn''t just possible, it''s familiar. And when safety becomes familiar, connection begins to flourish."},{"type":"text","content":"With steady practice and patience, you can:"},{"type":"list","items":["Strengthen the pathways of safety and calm","Teach your Critter Brain to stand down faster","Build new wiring for connection, confidence, and resilience"],"ordered":false},{"type":"text","content":"If this lesson is bringing up something larger than these practices can hold, please reach out to a therapist or counselor. This work matters, and so do you."},{"type":"divider"},{"type":"reflection","content":"Before you move on, pause here. 1. What is one thing from this lesson that you are grateful to understand now? 2. What is one thing you learned about your own nervous system that you did not know before? Write them down. Not because you have to — because naming what you''ve learned anchors it in your body, not just your mind."},{"type":"divider"},{"type":"heading","content":"What''s Ahead"},{"type":"text","content":"You now understand the players: the Critter Brain, the CEO Brain, the Vagus Nerve. You know the 90-second wave your body rides when it gets activated. You know the five zones your nervous system moves through every single day. And you have a practice — the 30-Second Reset — that you can use right now, tonight, tomorrow morning."},{"type":"text","content":"This is the foundation everything else is built on."},{"type":"text","content":"In the next lesson, we are going to take this understanding and put it into action. You are going to learn a method — a real, step-by-step method — for what to do when your Critter Brain has taken the wheel and you can feel the conversation heading somewhere you don''t want it to go. It''s called the SPARK Method, and it''s the bridge between understanding your nervous system and actually using that understanding in the moments that matter most."},{"type":"text","content":"But for now, practice the Reset. Just three breaths. Start tonight."}]}'::jsonb);

  -- ─── Lesson 1.3: The SPARK Method ───
  INSERT INTO lessons (module_id, title, sort_order, content_json)
  VALUES (
    mod1_id,
    'The SPARK Method',
    3,
    '{"estimated_minutes":48,"blocks":[{"type":"heading","content":"The SPARK Method"},{"type":"text","content":"A five-step method for interrupting the pattern and choosing connection."}]}'::jsonb
  ) RETURNING id INTO parent_id;

  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, content_json) VALUES
    (mod1_id, parent_id, 'The Repair That Changed Everything', 301, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"They were sitting on their back deck after dinner when she saw him eyeing the hillside — overgrown, weedy, the kind of project that would eat an entire Saturday and leave him sore for a week."},{"type":"text","content":"She felt the old reaction rising. The tightness in her chest. The worry that their weekend plans were about to disappear. The urge to say something sharp before he even opened his mouth."},{"type":"text","content":"Six months earlier, this would have gone badly. She would have said something critical about his stubbornness. He would have heard: You don''t think I can handle it. They would have spent the weekend in cold, thick silence."},{"type":"text","content":"But this time, she caught it."},{"type":"text","content":"She caught the frustration building, caught the worry underneath it, and instead of swallowing it or snapping, she just said it: \"Promise me you''re not going to do the hill this weekend.\""},{"type":"text","content":"He said okay."},{"type":"text","content":"\"No,\" she said. \"I need you to actually promise me.\""},{"type":"text","content":"And they both laughed."},{"type":"text","content":"When I asked him later what had shifted, he said something that stayed with me: \"In the old days, I would have heard that as her saying I can''t do it. Now I hear it as her saying she wants to be with me. And that matters more than what the weeds look like.\""},{"type":"text","content":"That''s repair. Not a dramatic apology. Not a tearful breakthrough. Just two people catching the old pattern and choosing a different one — together."},{"type":"divider"},{"type":"text","content":"If you''ve been reading through this module, you already know some things. You know about the Seven Devils — the patterns that show up uninvited and run your fights for you. You know about your Critter Brain, that ancient protective wiring that senses a threat and takes over before your CEO Brain can even get a word in. You know about the Zones — the Green Zone where connection lives, the Red Zone where survival takes the wheel."},{"type":"text","content":"All of that was the build-up."},{"type":"text","content":"This is the method."},{"type":"text","content":"SPARK is not five separate tricks. It is one sequence — one choreography — that interrupts the Critter Brain, rides the wave without adding fuel, and brings you back to your Green Zone in the only order that actually works. Most couples who try to repair a fight go in the wrong order, and that is why their repairs don''t hold. They try to reconnect before they''ve acknowledged. They try to acknowledge before they''ve paused. They try to pause before they''ve even seen that something shifted. The repair collapses because the foundation wasn''t there yet."},{"type":"text","content":"SPARK is the order."},{"type":"text","content":"S — See P — Pause & Probe A — Acknowledge R — Reconnect K — Kindle"},{"type":"text","content":"That couple on the back deck? They didn''t know they were using SPARK. They hadn''t memorized the steps or practiced them in front of a mirror. But look at what happened: She saw the old pattern rising in her own system. She paused — didn''t snap, didn''t swallow it — and probed what she was actually feeling underneath (worry about losing their time together, not anger about weeds). She named it directly, which was an act of acknowledgment — not of his plan, but of the real thing happening between them. He reconnected by hearing her words through a new lens, choosing the generous interpretation instead of the wounded one. And without knowing it, they kindled — they laughed together, they chose the relationship, and they carried that moment forward as evidence that things really had changed."},{"type":"text","content":"That''s what SPARK looks like when it''s working. Not a script. A way of being with each other when the old pattern tries to run the show."},{"type":"text","content":"I''ve been teaching this to couples for a long time now. Jeff and I use it in our own marriage — badly sometimes, beautifully sometimes, but always eventually. I''m not going to tell you we''ve perfected it. I''m going to tell you it works, even when you don''t."},{"type":"audio","title":"1:00, Trisha — \"Jeff and I use this in our own marriage. Badly sometimes. Beautifully sometimes. But always eventually.\""},{"type":"text","content":"This is everything I know about how to use it."}]}'::jsonb),
    (mod1_id, parent_id, 'See & Pause', 302, '{"estimated_minutes":10,"blocks":[{"type":"heading","content":"S — See"},{"type":"text","content":"The moment the conversation stops being about what it''s about."},{"type":"text","content":"You''ll feel it before you hear it. Your jaw tightens. Heat rises in your chest or your face. Your breathing goes shallow. The first sentence that comes out is sharper than you meant it, or you go quiet — the kind of quiet that isn''t peaceful, it''s loaded."},{"type":"text","content":"That''s the shift. That''s your Critter Brain catching something it reads as a threat and sounding the alarm. Remember — your Critter Brain doesn''t care if the \"threat\" is a comment about the dishes or a tone of voice that reminds your system of something from twenty years ago. It responds the same way to burnt toast as it does to a house fire. It floods your system with stress hormones, shuts down your CEO Brain, and puts you in survival mode: fight, flight, or freeze."},{"type":"text","content":"Your job in this moment is not to stop the activation. You can''t — it''s already happening. Your job is to notice it."},{"type":"text","content":"See your system. What is happening in your body right now? Where is the tension living? Is your heart racing? Are your fists clenching? Is your stomach dropping?"},{"type":"text","content":"See your partner. Not the version your Critter Brain has constructed — the one who''s \"attacking\" you or \"doesn''t care.\" The real person sitting across from you. Look at their face. What''s actually there? Is that anger — or is that fear wearing anger''s mask?"},{"type":"text","content":"See the space between you. This is not you versus them. This is two nervous systems that both feel unsafe, both doing their best with ancient protective wiring that was never designed for an argument about weekend plans."},{"type":"bold_text","content":"In practice, \"See\" sounds like:"},{"type":"list","items":["\"I notice I''m getting activated right now.\"","\"I can see this really hurt you.\"","\"Something just shifted between us. I want to understand what happened.\""],"ordered":false},{"type":"text","content":"The act of naming what you see — out loud — is itself a regulatory act. It moves you from reaction to observation. And observation is where your CEO Brain starts to come back online."},{"type":"text","content":"One sentence. That''s all \"See\" asks of you. One sentence that says: I notice what''s happening."},{"type":"divider"},{"type":"heading","content":"P — Pause & Probe"},{"type":"text","content":"You''ve seen the shift. Now slow it down."},{"type":"text","content":"Pause the escalation. This can be a full pause — using your Pause Number to step away and regulate — or it can be a micro-pause: one full breath before your next sentence. Even three seconds of deliberate silence changes the trajectory. Your Critter Brain runs fast. Anything that introduces a gap between the reaction and the response gives your CEO Brain a chance to come back to the table."},{"type":"subheading","content":"The Pause Number"},{"type":"text","content":"Here''s a tool that''s deceptively simple and profoundly powerful."},{"type":"text","content":"Before you ever need it — right now, tonight, in a calm moment — agree with your partner on a Pause Number."},{"type":"text","content":"On a scale of 1 (calm and connected) to 10 (fully hijacked), choose a number — usually somewhere between 5 and 7 — where you both agree to stop the conversation. No questions asked. No guilt. No \"but I wasn''t done.\" When either of you says the number, the conversation pauses."},{"type":"text","content":"That''s it. That''s the whole tool."},{"type":"text","content":"But here''s why it works: in the heat of conflict, your CEO Brain doesn''t have enough bandwidth to construct a full sentence like \"I''m feeling overwhelmed and I need a break before I say something I regret.\" That requires executive function. That requires nuance. And your Critter Brain just shut all of that down."},{"type":"text","content":"But one word can still get through."},{"type":"text","content":"\"Six.\""},{"type":"text","content":"One word. No explanation needed. And because you agreed on it in advance — when you were both calm and regulated, both in your Green Zone, both thinking clearly — that single number carries the weight of a full conversation. It means: I love you. I''m not leaving. I''m just too activated right now to be the partner you deserve. Give me a few minutes."},{"type":"text","content":"The Pause Number works because it doesn''t require you to be articulate when your system is flooded. It meets you where you actually are in that moment — not where you wish you were."},{"type":"text","content":"Important: Pausing is not stonewalling. Stonewalling is withdrawing without communication — it says I''m done with you. Pausing is an act of courage — it says I care about this relationship too much to keep going right now."},{"type":"text","content":"When you pause:"},{"type":"list","items":["Name it. Use your Pause Number, or say: \"I need 20 minutes.\" Use a hand signal you''ve agreed on. Whatever works — but communicate that you''re pausing, not abandoning.","Regulate your system. Step away and do something that moves you back toward your Green Zone. Breathe (4 seconds in, 4 hold, 4 out). Move (walk outside, stretch, shake your body). Cool down literally (cold water on your face, ice cubes in your hands). These aren''t random suggestions — they work because they signal your nervous system that the threat has passed.","Keep your word. If you said 20 minutes, come back in 20 minutes. Every time you honor the timeline you set, you''re teaching your partner''s nervous system: This person is safe. They leave, and they come back."],"ordered":true},{"type":"audio","title":"2:00, Trisha guided — 30-Second Reset during the Pause step"},{"type":"subheading","content":"The Probe"},{"type":"text","content":"Once you''ve paused — or even in that micro-pause of one breath — probe. Not your partner. Yourself."},{"type":"text","content":"Ask: What am I actually feeling right now?"},{"type":"text","content":"Not what am I reacting to. Not what did my partner do wrong. What am I feeling — underneath the anger, underneath the frustration, underneath the urge to defend myself or shut down?"},{"type":"text","content":"The surface emotion is almost always anger, annoyance, or frustration. The real emotion — the one that''s actually driving the reaction from behind the curtain — is almost always something more tender: hurt, rejection, fear of being unseen, fear of being left, loneliness."},{"type":"text","content":"Your Critter Brain dresses vulnerability in armor. It turns \"I''m scared you don''t see me\" into \"You never listen.\" It turns \"I feel alone\" into \"You''re always on your phone.\" The probe is how you find what''s underneath the armor."},{"type":"text","content":"When you name the real feeling — even just to yourself — something shifts. And when you share it with your partner, you give them something they can actually respond to. \"I''m angry\" invites defense. \"I''m scared you don''t see me\" invites compassion."},{"type":"bold_text","content":"In practice, \"Pause & Probe\" sounds like:"},{"type":"list","items":["\"Hold on — let me think about what I''m actually feeling.\"","\"What felt hardest about that for me was...\"","\"Underneath this frustration, I think what I really need is to feel like I matter to you.\""],"ordered":false},{"type":"divider"},{"type":"heading","content":"Practice: My See & Pause Profile"},{"type":"text","content":"Take a few minutes to fill this out. You''ll use it again in 1.3.5 when you build your SPARK Pact with your partner."},{"type":"text","content":"My Critter Brain fingerprints (check all that apply):"},{"type":"list","items":["Racing heart or pounding chest","Shallow, rapid breathing","Tight jaw, clenched fists, tension in shoulders","Heat rising in face or neck","Sudden urge to move — pace, leave the room","Heavy, frozen feeling — can''t move or speak","Stop listening to understand, start listening to respond","Absolutes appear: always, never, every time","Urge to \"win\" or be \"right\"","Keeping score: \"Well, you did this last week...\"","Other: _______________________________________"],"ordered":false},{"type":"text","content":"My Pause Number (first instinct — you can adjust this with your partner later): ____"},{"type":"bold_text","content":"What usually happens when I hit that number and DON''T pause:"},{"type":"text","content":"_______________________________________"},{"type":"text","content":"One regulation tool I want to try first (breathing, walking, cold water, writing):"},{"type":"text","content":"_______________________________________"}]}'::jsonb),
    (mod1_id, parent_id, 'Acknowledge & Reconnect', 303, '{"estimated_minutes":10,"blocks":[{"type":"heading","content":"A — Acknowledge"},{"type":"text","content":"This is the step most people skip."},{"type":"text","content":"And it''s the one that changes everything."},{"type":"text","content":"Here''s what usually happens after the pause: you''ve both calmed down a little. The adrenaline has eased. You walk back into the room, and the first thing you want to do is explain yourself. Defend your position. Make sure your partner understands where you were coming from."},{"type":"text","content":"That''s your Critter Brain''s last stand. It''s no longer screaming — but it''s whispering: Make sure they know you weren''t wrong."},{"type":"text","content":"Resist it. Because what your partner''s nervous system needs in this moment is not your explanation. It needs to know that you saw them. That what they felt was real. That it mattered to you."},{"type":"text","content":"Acknowledge your partner''s experience. Not to agree with it. Not to concede the argument. Not to say they''re right and you''re wrong. Simply to say: I see you. What you''re feeling is real. It makes sense."},{"type":"text","content":"This makes sense. That''s the phrase. Not \"you''re right,\" not \"I was wrong,\" not even \"I understand.\" Just: this makes sense. Given what you were carrying into that conversation, given what you heard, given what your own Critter Brain was doing to you in that moment — it makes sense that you felt that way."},{"type":"text","content":"Acknowledgment is not agreement. Read that again."},{"type":"text","content":"You can acknowledge that your partner felt hurt by something you said without agreeing that you intended to hurt them. You can honor their reality without abandoning your own."},{"type":"text","content":"Why does this work? Because what your partner''s Critter Brain was really scanning for — underneath all the arguing, the defending, the accusations — was this: Do you see me? Am I safe with you?"},{"type":"text","content":"Acknowledgment answers that question. When your partner''s survival system hears genuine acknowledgment, the threat level drops. The guard comes down. The nervous system begins to settle. Not because you agreed with them. Because you saw them."},{"type":"text","content":"Why the order matters: If you try to acknowledge before you''ve paused, it comes out hollow — you''re still activated, still defending, and your partner''s Critter Brain will read the inauthenticity instantly. If you try to reconnect before you''ve acknowledged, your partner will pull away — because they don''t feel seen yet, and a hug from someone who hasn''t seen you doesn''t feel safe. It feels like being managed."},{"type":"text","content":"The order is the method. SPARK works because each step builds the foundation for the next."},{"type":"bold_text","content":"In practice, \"Acknowledge\" sounds like:"},{"type":"list","items":["\"I hear you. That hurt. I understand why you feel that way.\"","\"I can see how what I said landed for you — and that wasn''t my intention, but your experience matters more than my intention right now.\"","\"It makes sense that you''d feel that way, given what you were carrying into this conversation.\""],"ordered":false},{"type":"divider"},{"type":"heading","content":"R — Reconnect"},{"type":"text","content":"Both systems have calmed. The temperature has dropped. You''ve seen each other, really seen each other. Now reach back toward each other."},{"type":"text","content":"This is the step that says: I''m still here. We''re still us."},{"type":"text","content":"Reconnection doesn''t have to be dramatic. It doesn''t require a grand speech. Sometimes the most powerful repair is the simplest:"},{"type":"list","items":["A softer tone of voice after the tension has passed","A hand on their arm","A shared breath — literally, breathing together for ten seconds","Words that signal you''re still on the same team"],"ordered":false},{"type":"text","content":"The key phrase is \"I''m still here.\" Not \"let''s move on.\" Not \"are we done?\" Not \"so are we good?\" Those phrases rush past the repair. \"I''m still here\" sits in it. It tells your partner''s nervous system: The storm happened, and I didn''t leave. I chose to come back."},{"type":"text","content":"Why does this work before the \"fix\"? Most couples try to fix the problem before they reconnect. They jump straight from the fight into logistics — \"Okay, so next time, how about we...\" But a fix from two people who haven''t reconnected doesn''t hold. It''s two Critter Brains negotiating a ceasefire. The moment the next fight happens, the ceasefire collapses because there was no bond underneath it."},{"type":"text","content":"Reconnect first. The bond before the fix. The \"us\" before the \"it.\""},{"type":"bold_text","content":"In practice, \"Reconnect\" sounds like:"},{"type":"list","items":["\"I''m here. I''m not going anywhere.\"","\"Can I hug you? I need to feel close to you again.\"","\"Thank you for staying in this with me.\"","\"I don''t want to be on opposite sides of this.\""],"ordered":false},{"type":"text","content":"Two people who just hurt each other choosing — consciously, deliberately — to come back. Not because the issue is resolved. Not because someone won. But because the relationship matters more than being right."},{"type":"divider"},{"type":"reflection","content":"Think about a recent conflict — even a small one. Answer honestly. 1. When the tension eased, what did you do first — explain your side, or ask about theirs? _______________________________________ 2. What would it feel like to hear your partner say \"It makes sense that you felt that way\" — even if they didn''t agree with you? _______________________________________ 3. After your last argument, how did you reconnect? Was there a moment where one of you reached back toward the other? What did it look like? _______________________________________ 4. What is the reconnection signal that would feel most meaningful to you — a phrase, a touch, a gesture? _______________________________________"}]}'::jsonb),
    (mod1_id, parent_id, 'Kindle', 304, '{"estimated_minutes":8,"blocks":[{"type":"heading","content":"K — Kindle"},{"type":"text","content":"This is the step that separates repair from growth."},{"type":"text","content":"Most couples, when they manage to get through a conflict and reconnect, feel so relieved that they want to move on immediately. The fight is over. The tension has broken. Everyone can breathe again. Why would you go back?"},{"type":"text","content":"Because the most important work doesn''t happen during the fight. It happens after."},{"type":"text","content":"Kindle means: come back to learn, not to litigate. Not to rehash who said what. Not to re-open the argument from a calmer angle. To learn — from the fight, from each other, and from whatever your Critter Brain was trying to protect when it took the wheel."},{"type":"text","content":"This is the follow-up nobody sees. The conversation the next morning, or the next evening, when the dust has settled and you''re both back in your Green Zone. The one where you sit down and say: \"What happened there? What was that really about? What was my Critter Brain protecting?\""},{"type":"text","content":"That conversation — the Kindle conversation — is where actual change lives. Not the heroic in-the-moment repair. The reflection that follows it. Over time, these conversations are what rewire the pattern."},{"type":"bold_text","content":"In practice, \"Kindle\" sounds like:"},{"type":"list","items":["\"What can we do differently next time we hit that spot?\"","\"I want to remember what just happened here — we fought, and we came back. That''s us.\"","\"One thing I love about how you showed up just now is...\"","\"What was your Critter Brain trying to protect? Mine was protecting against feeling invisible.\""],"ordered":false},{"type":"audio","title":"1:00, Jeff — his perspective on learning to stop fixing and start listening"},{"type":"text","content":"Kindle turns a fight into a data point. It says: we don''t just survive conflict — we learn from it. And every time you Kindle after a repair, you''re building the neural pathways that make the next repair faster, easier, and more natural. You''re training your nervous system that conflict is survivable, that repair is possible, and that the relationship can hold both of you — even when it''s hard."},{"type":"divider"},{"type":"heading","content":"The Full Sequence"},{"type":"text","content":"Let''s put it all together. Here''s SPARK as one continuous flow:"},{"type":"text","content":"S — See. Notice the moment your body decides the conversation is no longer safe. Name it — to yourself or out loud. \"I''m getting activated.\""},{"type":"text","content":"P — Pause & Probe. Buy your CEO Brain time to come back online. Pause the escalation. Then ask yourself: \"What am I actually feeling?\" Find the tender thing underneath the armor."},{"type":"text","content":"A — Acknowledge. Validate your partner''s reality before defending your own. \"It makes sense that you feel that way.\" Validation is not agreement. It''s telling their Critter Brain it''s safe to lower its guard."},{"type":"text","content":"R — Reconnect. Signal \"I''m still here. We''re still us.\" The bond before the fix. Reach toward your partner before you try to solve the problem."},{"type":"text","content":"K — Kindle. Come back to learn, not litigate. What was your Critter Brain protecting? What would you want to try differently? This is where growth lives."},{"type":"text","content":"One sequence. One choreography. The order matters."},{"type":"divider"},{"type":"reflection","content":"1. After your last conflict that resolved, did you go back to talk about what happened — or did you both move on? What would it look like to add a Kindle conversation? _______________________________________ 2. What time of day or setting would feel safest for a Kindle conversation with your partner? (Morning with something warm in your hands? A walk? Before bed?) _______________________________________ 3. Finish this sentence: \"The thing my Critter Brain is usually trying to protect in our arguments is...\" _______________________________________"}]}'::jsonb),
    (mod1_id, parent_id, 'Your SPARK Pact', 305, '{"estimated_minutes":9,"blocks":[{"type":"heading","content":"Building Your SPARK Pact"},{"type":"text","content":"This is the artifact of this lesson — the thing you and your partner create together and keep somewhere visible. Your fridge. Your nightstand. Your phone. The notes app you actually open."},{"type":"text","content":"The SPARK Pact is not a contract. It''s a shared agreement, built in a calm moment, that gives you both a plan for the moments when calm disappears. You''re deciding now — while your CEO Brain is fully online, while you''re both in your Green Zone — what you''ll do when the Critter Brain takes over."},{"type":"text","content":"Before you begin: Both partners should be feeling calm and connected — roughly 1-3 on your Pause Number scale. If either of you is activated, come back to this later. There is no timeline for this practice — only safety."},{"type":"divider"},{"type":"fillable_form","form_id":"your-spark-pact","title":"Your SPARK Pact","fields":[{"id":"field_1","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_2","label":"My Reset Move:","type":"textarea","rows":2,"placeholder":""},{"id":"field_3","label":"Your Partner''s Reset Move:","type":"textarea","rows":2,"placeholder":""},{"id":"field_4","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_5","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_6","label":"","type":"textarea","rows":3,"placeholder":""}],"intro":"Fill this out together, keep it where you''ll see it — like on your fridge or in your phone. Our Pause Number: on a scale of 1 (calm) to 10 (hijacked) — e.g. 6"},{"type":"divider"},{"type":"heading","content":"How to Fill It Out"},{"type":"text","content":"Our Pause Number. If you each filled out the practice in 1.3.2, you already have a first instinct. Share your numbers with each other. If they''re different, pick the lower one — the person who gets activated first sets the pace. This isn''t about who''s more sensitive. It''s about catching the pattern before it catches you."},{"type":"text","content":"My Reset Move / Your Partner''s Reset Move. What helps each of you regulate? Not what sounds good — what actually works for your system. If you don''t know yet, try one from the list in 1.3.2 (breathing, walking, cold water, writing) and see what your body responds to."},{"type":"text","content":"Our SPARK Ritual. This is your version of the Kindle conversation. When will you come back to talk about what happened? Morning? Evening walk? What does it look like for you two specifically?"},{"type":"text","content":"Our Pause Cue. The word, gesture, or signal that means \"I need to pause.\" Your Pause Number is one option. A hand signal works. Some couples use a phrase: \"I need a minute.\" Some use a code word that''s just theirs. The only requirement is that you both know it and both agree to honor it — no questions, no guilt, no \"but I wasn''t done.\""},{"type":"divider"},{"type":"heading","content":"Practice It on Something Small"},{"type":"text","content":"Choose a recent minor frustration — not the biggest issue in your relationship. Something small enough to practice safely."},{"type":"text","content":"Walk through each SPARK step together, out loud:"},{"type":"list","items":["See: One of you names the moment: \"Here''s where it shifted for me.\"","Pause & Probe: Both of you take one breath. Ask yourselves: \"What was I actually feeling?\"","Acknowledge: Reflect what you heard. \"It makes sense that you felt that way because...\"","Reconnect: Reach toward each other. A word, a touch, a look.","Kindle: \"What could we try differently next time?\""],"ordered":true},{"type":"text","content":"After the practice, debrief:"},{"type":"list","items":["Which step was easiest for each of you?","Which step was hardest?","What surprised you?"],"ordered":false},{"type":"text","content":"Close by sharing one specific thing you appreciate about how your partner showed up for this practice. Not \"you did great\" — but \"I felt really seen when you said...\""}]}'::jsonb),
    (mod1_id, parent_id, 'Reflection: What SPARK Means for Us', 306, '{"estimated_minutes":10,"blocks":[{"type":"heading","content":"Individual Reflection"},{"type":"text","content":"These prompts are your space to reflect, uncover, and grow. Reflect individually, once completed meet with your partner for the Couple Reflection."},{"type":"subheading","content":"1. Spotting My Hijack"},{"type":"list","items":["What does my Critter Brain feel like when conflict starts? (e.g. racing heart, tight chest)","When I''m hijacked (scale it: 1-10), what''s the number where I know I need to pause? What stops me from doing it?"],"ordered":false},{"type":"subheading","content":"2. My Pause Power"},{"type":"list","items":["What''s one thing that helps me calm myself during a pause? (e.g. deep breathing, a walk, cold water)","How safe do I feel calling for a pause in our fights? What would make it easier?"],"ordered":false},{"type":"subheading","content":"3. Uncovering the Beneath"},{"type":"list","items":["In our last conflict, what was I really feeling under my reaction? What did I need but couldn''t say?","What story does my Critter Brain tell me when I feel unheard or unseen by my partner?"],"ordered":false},{"type":"subheading","content":"4. Repair That Resonates"},{"type":"list","items":["What would meaningful repair look like for me — a certain phrase, a touch, time to talk?","When I imagine my partner acknowledging and validating my feelings, what words or actions would hit home?"],"ordered":false},{"type":"subheading","content":"5. My Growth Edge"},{"type":"list","items":["What''s one thing I do in conflict (snap, shut down, defend)? How could pausing or SPARK help me change?","How does it feel when I own my part in a fight? What''s one small step I can take to do this more bravely?"],"ordered":false},{"type":"divider"},{"type":"heading","content":"Couple Reflection"},{"type":"text","content":"To be discussed together, or written separately and shared in a safe conversation."},{"type":"subheading","content":"1. Our Conflict Dance"},{"type":"list","items":["What does escalation look like in our relationship? Are there early signs we can spot to pause sooner?","What''s our usual conflict pattern (trigger -> reaction -> disconnect)?","Where in that cycle can we pause or repair to change the outcome?"],"ordered":false},{"type":"subheading","content":"2. Building a Safe Pause"},{"type":"list","items":["How do we each feel about calling for a pause?","What''s one pause cue (word, gesture) we can agree on that feels natural for both of us?"],"ordered":false},{"type":"subheading","content":"3. Regulation as a Team"},{"type":"list","items":["What helps each of us regulate after a fight? (e.g. breathing, moving) How can we support each other''s reset?"],"ordered":false},{"type":"subheading","content":"4. Crafting Our SPARK"},{"type":"list","items":["What would it feel like if we truly saw each other in a fight — really listened, no interruptions?","How can we acknowledge and validate each other better? What words or actions make us feel truly heard?"],"ordered":false},{"type":"subheading","content":"5. Our Vision for Repair"},{"type":"list","items":["What does meaningful repair look like for us as a couple — a hug, a promise, a quiet moment?"],"ordered":false},{"type":"divider"},{"type":"fillable_form","form_id":"your-implementation-intention","title":"Your Implementation Intention","fields":[{"id":"field_1","label":"This week, I will:","type":"textarea","rows":2,"placeholder":""}],"intro":"Before you close this lesson, write one thing down. Not five. Not a plan for overhauling your entire conflict pattern. One thing."},{"type":"divider"},{"type":"fillable_form","form_id":"a-gratitude-and-a-takeaway","title":"A Gratitude and a Takeaway","fields":[{"id":"field_1","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_2","label":"","type":"textarea","rows":3,"placeholder":""}],"intro":"Before you move on, pause here. Just for a moment. One thing I''m grateful for after this lesson:"},{"type":"divider"},{"type":"heading","content":"What''s Next"},{"type":"text","content":"In Lesson 1.4, you''ll take everything you''ve learned in this module — the patterns, the brain science, the SPARK Method — and build it into a practice plan that fits your actual life. Because knowing SPARK and using SPARK are not the same thing. The first three times you try it in a real fight, you''ll probably forget at least one step. Maybe two. That''s normal. The method gets stronger with repetition, and 1.4 is where the repetition starts."},{"type":"text","content":"You''ve got the tool. Now let''s make it yours."},{"type":"divider"},{"type":"text","content":"Go gently — I''ll see you in 1.4."},{"type":"text","content":"— Trisha"}]}'::jsonb);

  -- ─── Lesson 1.4: Your First Week of Practice ───
  INSERT INTO lessons (module_id, title, sort_order, content_json)
  VALUES (
    mod1_id,
    'Your First Week of Practice',
    4,
    '{"estimated_minutes":38,"blocks":[{"type":"heading","content":"Your First Week of Practice"},{"type":"text","content":"Seven days of practice to move from knowing these tools to using them."}]}'::jsonb
  ) RETURNING id INTO parent_id;

  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, content_json) VALUES
    (mod1_id, parent_id, 'Clean Sheets', 401, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"He''d been sick all week. She''d been managing everything — the kids, the school prep, the back-to-school chaos — mostly alone, because he was either traveling or flat on his back with a fever."},{"type":"text","content":"Nobody would have blamed her for being resentful. A year earlier, she probably would have been."},{"type":"text","content":"But on Sunday, while he was at work, she washed his sheets."},{"type":"text","content":"That''s it. She washed his sheets."},{"type":"text","content":"When he told me about it the following week, his voice changed. Got softer. \"That was a big deal,\" he said. \"It just — it makes you feel like you''re not sick anymore. Clean sheets. I told her so many times how thankful I was. I felt like I got better faster just because I felt supported.\""},{"type":"text","content":"She hadn''t read a chapter or filled out a worksheet that week. She hadn''t had some big revelation. She just noticed he was struggling, and she did something small and kind."},{"type":"divider"},{"type":"text","content":"I want to sit with that story for a second before we talk about practice plans and day-by-day assignments, because I think it answers the question most people don''t know they''re asking."},{"type":"text","content":"The question is: What does this actually look like when it''s working?"},{"type":"text","content":"And the answer, from that couple''s season of growth, is: clean sheets on a Sunday afternoon. One quiet choice that said, I see you, and I''m still here."},{"type":"text","content":"Not a breakthrough conversation. Not a tearful acknowledgment. Not a perfectly executed SPARK sequence. Just one small act of care from someone who, not long before, would have been too depleted and too angry to even think of it."},{"type":"text","content":"That''s what practice does. It doesn''t create dramatic transformations. It creates people who are slightly more present, slightly more regulated, slightly more capable of noticing — until one day, the noticing becomes a gesture, and the gesture becomes a habit, and the habit becomes the relationship you actually wanted."},{"type":"divider"},{"type":"text","content":"Here is something I''ve learned after working with plenty of couples over a long time: The method is not the work. The practice is the work."},{"type":"text","content":"You can understand the Seven Devils and still criticize your partner. You can know exactly what your Critter Brain does and still let it run the conversation. You can memorize every step of the SPARK Method and never use it once."},{"type":"text","content":"Knowledge is the beginning. It''s an important beginning. But it doesn''t become anything real until it gets repeated in ordinary moments — the boring Tuesday evenings, the tired Sunday afternoons, the small conversations that don''t feel like practice but are."},{"type":"text","content":"This module has given you the map. This lesson is about the first seven steps."},{"type":"divider"},{"type":"audio","title":"2:00, Trisha — what she sees when couples actually do the practice. Celebration tone."},{"type":"divider"},{"type":"text","content":"Here is what I want you to carry into the next seven days:"},{"type":"text","content":"You are not trying to fix your relationship this week. You are not trying to have the perfect conversation or execute the method flawlessly or prove anything to your partner or yourself. You are just taking seven small steps — one per day — that build the kind of neural pathways no amount of reading can build for you."},{"type":"text","content":"Imperfect practice counts. Interrupted practice counts. Practice you do while exhausted and frustrated counts. The only practice that doesn''t count is the one you don''t do at all."},{"type":"text","content":"Let''s build your first week."},{"type":"divider"},{"type":"text","content":"Before you move to the practice plan, take sixty seconds. What landed for you from that story? Was there a moment in your own relationship that came to mind — a small act of care that mattered more than you expected?"},{"type":"text","content":"You don''t have to write it down. But sit with it."}]}'::jsonb),
    (mod1_id, parent_id, 'Days 1–3: Notice, Name, Reset', 402, '{"estimated_minutes":9,"blocks":[{"type":"text","content":"When you start something new, the first three days are the hardest. Not because the work is the most demanding — but because your system hasn''t yet learned to trust the new pattern. Your Critter Brain is still watching, still skeptical, still waiting for this to feel like the other things you''ve tried."},{"type":"text","content":"The first three days of this plan are designed with that in mind. There is almost nothing to do. There is a lot to notice."},{"type":"divider"},{"type":"heading","content":"Day 1 — Just notice."},{"type":"text","content":"When does your Critter Brain take over? Not during a fight, necessarily — just anywhere in your day."},{"type":"text","content":"Maybe it''s in the car, when your partner says something offhand and you feel your chest tighten. Maybe it''s at dinner, when you realize you''ve been running a quiet internal monologue about something that happened two days ago. Maybe it''s the split second before you answer a question and something in you is already bracing."},{"type":"text","content":"You''re not trying to stop it. You''re not trying to change it. You''re just watching."},{"type":"text","content":"At the end of the day, see if you can remember one moment when your Critter Brain was in the driver''s seat. What was happening? What did your body do? Did you feel it before you thought it, or after?"},{"type":"text","content":"That''s the whole assignment. Notice, and remember."},{"type":"divider"},{"type":"text","content":"There is more power in that single instruction than it looks like on paper. Most of us spend our days inside our reactions, not watching them. We are the Critter Brain. We are the tight chest and the braced shoulders and the conversation we''re already rehearsing. We don''t often step back far enough to say, oh, that''s a pattern, and it has a name."},{"type":"text","content":"Day 1 is the beginning of that distance. And distance — even one small step of it — changes everything."},{"type":"divider"},{"type":"heading","content":"Day 2 — Your Pause Number."},{"type":"text","content":"Pick a number, anywhere from one to ten, that means: I need to pause."},{"type":"text","content":"You get to choose what pause means for you — twenty minutes, an hour, a full reset before returning to a conversation. But the number itself is just a signal: My system is getting too activated to stay in this conversation productively, and I''m going to say so instead of pushing through."},{"type":"text","content":"Today, share it with your partner. In a calm moment — not mid-conflict, not right after something hard. Just bring it up the way you''d mention anything you''d read about. \"I''ve been working through something, and there''s this practice I want to try. My number is four. If I say ''four,'' it means I need twenty minutes to come back to myself before we keep talking. Can you be okay with that?\""},{"type":"text","content":"That''s it. You don''t have to use it today. You''re just making the agreement."},{"type":"divider"},{"type":"text","content":"If your partner asks questions, answer them honestly. If they''re skeptical, let them be skeptical — you don''t need their buy-in to set a pause signal. You just need them to know it''s coming. If they''re open to it, see if they want to pick a number too."},{"type":"text","content":"If the conversation doesn''t go perfectly, that''s okay. You made the offer. The groundwork is laid."},{"type":"divider"},{"type":"heading","content":"Day 3 — The 30-Second Reset."},{"type":"text","content":"You learned this in Module 1.2. Today you''re going to use it — not in a conflict, but in an ordinary moment."},{"type":"text","content":"While you''re waiting for something. Before you send an email that''s been making you anxious. On your lunch break. Sitting in your car before you go inside somewhere. Just do the sequence: hand on heart, three slow breaths, an audible sigh on the exhale."},{"type":"text","content":"Notice how your body is different after. You might feel a small shift — your shoulders drop, your jaw unclenches, your thoughts come a little slower. You might feel almost nothing. Either is fine. Your Critter Brain is receiving a message. It doesn''t always send a receipt."},{"type":"text","content":"What matters is that you sent the signal. You told your system: I can regulate intentionally. I''m not at the mercy of what''s happening around me."},{"type":"text","content":"One time. Ordinary moment. That''s Day 3."},{"type":"divider"},{"type":"bold_text","content":"Your Days 1–3 Practice Plan"},{"type":"text","content":"Use this as your reference. You can check the box in the app, or just work through it in your head at the end of each day."},{"type":"list","items":["Day 1: Notice when your Critter Brain takes over. Write down (or mentally note) one moment. No fixing — just watching.","Day 2: Choose your Pause Number. Share it with your partner in a calm moment.","Day 3: Use the 30-Second Reset once, in an ordinary moment (not in conflict)."],"ordered":false},{"type":"divider"},{"type":"reflection","content":"Reflection: End of Day 3"},{"type":"text","content":"At the end of Day 3, what surprised you? Was there a moment you noticed your Critter Brain that you would have completely missed before this module? That noticing is not small. That''s your CEO Brain coming online."}]}'::jsonb),
    (mod1_id, parent_id, 'Days 4–7: Practice, Reflect, Try', 403, '{"estimated_minutes":9,"blocks":[{"type":"text","content":"Days 1 through 3 were about building awareness. You noticed. You named. You reset."},{"type":"text","content":"Days 4 through 7 are about beginning to act. Not perfectly — there is no version of this where Day 4 goes exactly the way you imagined it. But the difference between awareness and practice is that practice asks you to try, even when you''re uncertain, even when you forget a step, even when the moment passes before you could use it."},{"type":"text","content":"That''s fine. The moment that passed is still useful. You''ll see another one."},{"type":"divider"},{"type":"heading","content":"Day 4 — One SPARK step, low stakes."},{"type":"text","content":"Not the full sequence. Not in a hard conversation. Just one step, used once, in a small moment where the stakes are low."},{"type":"text","content":"Pick the step that feels most natural to you. Maybe it''s See — you catch a small flare of irritation before it becomes a reaction, and you just notice it without acting on it. Maybe it''s Acknowledge — your partner says something about their day and instead of half-listening you say, \"That sounds like it was really hard,\" and you mean it. Maybe it''s Reconnect — you''re both in the kitchen after dinner and you put a hand on their shoulder for no reason."},{"type":"text","content":"One step. One moment. Low stakes."},{"type":"text","content":"If it felt awkward, good. New things always do at first. What you''re doing isn''t changing your behavior in the dramatic moments — you''re building the habit of the method in the quiet ones, so it''s available when you actually need it."},{"type":"divider"},{"type":"heading","content":"Day 5 — Reflect."},{"type":"text","content":"Take ten quiet minutes today. By yourself, not with your partner."},{"type":"text","content":"Ask yourself two questions:"},{"type":"text","content":"What did I notice this week?* *Where did my Critter Brain show up?"},{"type":"text","content":"You''re looking for patterns. Was there a time of day when you were more easily activated? A topic? A tone of voice? A specific kind of silence? Was there a moment when you caught the pattern and responded differently — even slightly?"},{"type":"text","content":"If nothing comes to mind, sit with that. Absence of a memory isn''t the same as absence of growth. You may have been practicing in ways too small to feel like practicing."},{"type":"text","content":"Write your reflections down if you can. Even a few sentences. Your own handwriting has a way of slowing your thoughts down enough to find the thing you didn''t know you were looking for."},{"type":"divider"},{"type":"heading","content":"Day 6 — Try a full sequence."},{"type":"text","content":"If a moment comes — if a real conversation happens today where your Critter Brain starts to take over — try the whole SPARK sequence. S, P, A, R, K, in order, as best you can remember them."},{"type":"text","content":"You will probably forget a step. You will probably get to K and realize you skipped A. You might get through P and then the whole thing falls apart. That is exactly how this is supposed to go."},{"type":"text","content":"What you''re practicing on Day 6 isn''t perfection. You''re practicing the attempt. You''re practicing what it feels like to try something different in the middle of a hard moment, to feel it get clunky, to notice where it got hard. That''s the information. That''s what Day 7 uses."},{"type":"text","content":"If a real moment doesn''t come today, that''s fine too. You can do a practice run in an imaginary conversation — pick a scenario you know is difficult for you, walk yourself through the sequence in your mind, and notice where it would get hard. That''s also useful."},{"type":"divider"},{"type":"heading","content":"Day 7 — Your first Devil Audit."},{"type":"text","content":"This is new. This is not something the 30-Second Reset teaches, or the Pause Number, or even SPARK."},{"type":"text","content":"This is you, one week in, looking back at the week and asking a different question:"},{"type":"text","content":"Which of the Seven Devils showed up this week? And who was carrying them — you, your partner, both of you?"},{"type":"text","content":"Get out the list. Criticism, Contempt, Defensiveness, Stonewalling, Avoidance, Unhealthy Coping, Intimacy Loss. You don''t need all seven. You need the honest ones."},{"type":"text","content":"Maybe it was Defensiveness — you caught yourself explaining and justifying when what your partner needed was to feel heard. Maybe it was Avoidance — there''s a conversation you''ve been sidestepping all week because you don''t know how to start it. Maybe it was Criticism — you said something you meant as feedback and it landed as an attack, and you knew it the moment it left your mouth."},{"type":"text","content":"Write it down. Two or three sentences per Devil you identify. Not as a confession, not as an accusation, but as a map. This is what I''m working with. This is what comes up for me. This is where Module 2 begins."},{"type":"text","content":"The Devil Audit is a tool you''ll return to throughout the full program — a way of checking in on which patterns are active, which are quieting, and which are still doing their work underneath the surface. This is just the first one. It doesn''t have to be comprehensive. It has to be honest."},{"type":"divider"},{"type":"bold_text","content":"Your Days 4–7 Practice Plan"},{"type":"list","items":["Day 4: Use one SPARK step in a low-stakes moment. Which step? Which moment?","Day 5: Ten quiet minutes alone. Reflect on what you noticed. Where did your Critter Brain show up?","Day 6: If a moment comes, try the full SPARK sequence. Note where it got hard.","Day 7: Complete your first Devil Audit. Which Devils showed up this week? Write it down."],"ordered":false},{"type":"divider"},{"type":"reflection","content":"Reflection: End of Your First Week"},{"type":"text","content":"At the end of Day 7, take a moment to look back at the whole week — not to judge how well you did, but to notice how far you traveled. A week ago, you might not have had words for what was happening in your relationship. Now you do. That''s not nothing. That''s huge."},{"type":"text","content":"What''s one thing you want to carry into the next module? And what surprised you most about what you noticed in yourself this week?"}]}'::jsonb),
    (mod1_id, parent_id, 'When You Get Stuck', 404, '{"estimated_minutes":8,"blocks":[{"type":"text","content":"Here is something I''ve learned, and I want to say it plainly before you run into any of these: getting stuck is not a sign that the work isn''t working. It is a sign that you are in the work. The couples who never get stuck are usually the ones who never really started."},{"type":"text","content":"These are the five stall points I see most often. If you recognize yourself in any of them, you''re not behind. You''re right on schedule."},{"type":"divider"},{"type":"bold_text","content":"\"I tried SPARK and my partner didn''t notice.\""},{"type":"text","content":"That''s okay — and it''s actually important to understand why."},{"type":"text","content":"SPARK is not a performance. It''s not something you do at your partner in hopes that they''ll respond differently. It''s something you do inside yourself, in the way you process a moment before you react to it. The first few times, your partner probably won''t notice anything has changed. The conversation may still go sideways. The old pattern may still run its course."},{"type":"text","content":"That''s not failure. That''s accurate."},{"type":"text","content":"What''s actually happening is that you''re beginning to interrupt the pattern on your side. Your partner doesn''t know yet that the dynamic has shifted — their Critter Brain is still running the old script. But over time, when you keep showing up differently, their system starts to notice that the usual triggers aren''t producing the usual results. That''s when they begin to respond differently, often without knowing why."},{"type":"text","content":"Give it time. Give it repetitions. Your job right now is not to get credit for practicing. Your job is to practice."},{"type":"divider"},{"type":"bold_text","content":"\"The 30-Second Reset didn''t calm me down.\""},{"type":"text","content":"Do it again."},{"type":"text","content":"I know that''s not the answer you were hoping for. But here is what''s happening: your nervous system is running a threat response that has been practiced, in some cases, for decades. It has deep grooves. The 30-Second Reset is not a switch — it''s a slow rerouting, and the Critter Brain doesn''t trust new routes on the first pass."},{"type":"text","content":"When the reset doesn''t work the first time, try it again. And again. If you can, do it before you''re fully activated — catch yourself in Yellow and reset then, rather than waiting until you''re deep in Red. The deeper the activation, the more repetitions it takes."},{"type":"text","content":"You are not broken because the first reset didn''t work. You are just beginning to teach your body something new. Bodies are slow learners. They are also, eventually, very good ones."},{"type":"divider"},{"type":"bold_text","content":"\"We''re back in the same fight pattern.\""},{"type":"text","content":"This makes sense. It doesn''t mean you haven''t grown."},{"type":"text","content":"Relationship patterns are some of the most deeply grooved neural pathways in the human brain. They were built by years of repetition — often starting long before this relationship — and they don''t just stop because you learned their names. For a while, maybe a long while, you will find yourself in the middle of the old fight and realize, sometimes halfway through and sometimes only after, that you were there."},{"type":"text","content":"That recognition is not the same as failure. That recognition is the practice."},{"type":"text","content":"The goal right now is not to stop having this fight. The goal is to see it while you''re in it. Then to see it earlier. Then to sometimes catch it before it starts. Each of those phases takes time, and each one requires that you go through the fight again and again — but with slightly more awareness each time. You are not failing by being in the same pattern. You are doing the necessary repetitions."},{"type":"divider"},{"type":"bold_text","content":"\"My partner isn''t reading this and probably won''t.\""},{"type":"text","content":"That''s okay. This work doesn''t require them."},{"type":"text","content":"I want to say that more plainly: one person quietly changing how they show up in a relationship has the power to shift the whole dynamic, even when the other person has no idea what changed. You cannot force a pattern to continue if one of its participants stops feeding it."},{"type":"text","content":"That doesn''t mean it''s easy to work on a relationship alone. It''s one of the harder versions of this work, and I want to honor that. You deserve a partner who''s doing this alongside you. And right now, you have what you have."},{"type":"text","content":"Do the work anyway. Not to fix them, not to prove anything, not to make them notice — but because you want to be different in your relationship. Because you are tired of the pattern. Because some part of you knows there is another way to do this, and you want to find it."},{"type":"text","content":"That''s enough of a reason. You are enough to start this."},{"type":"divider"},{"type":"bold_text","content":"\"I tried all of this and something is still wrong.\""},{"type":"text","content":"Come find us."},{"type":"text","content":"I don''t mean that as a marketing line. I mean it as a plain statement of fact: if you have done this work honestly and something underneath it still feels unmoved — a heaviness that the tools don''t reach, a fear that runs deeper than the patterns — that''s not a sign that you failed. That''s a sign that you''ve found the floor. And the floor is where the deeper work begins."},{"type":"text","content":"A skilled therapist or counselor can go with you into places this course is not designed to go. If this week brought up something larger than this lesson can hold, please reach out to a professional. This work matters, and so do you."},{"type":"text","content":"And if you''re not in crisis but you just want more — more depth, more specificity, more time with each pattern — the full program is built for exactly that. Jeff and I put everything we''ve learned into it. The door is open when you''re ready."},{"type":"divider"},{"type":"reflection","content":"Reflection: Your Likely Stall Point"},{"type":"text","content":"Which of these stall points do you suspect is most likely to be yours? Not as a judgment — just as useful information. Naming the obstacle in advance is one of the best things you can do to get past it."}]}'::jsonb),
    (mod1_id, parent_id, 'Your Module 1 Toolkit', 405, '{"estimated_minutes":6,"blocks":[{"type":"text","content":"I want to pause here and do something I don''t do often enough in this work."},{"type":"text","content":"I want to show you what you have."},{"type":"text","content":"Not what you still need to learn — there''s plenty of that, and Module 2 is waiting. But before we move forward, I want you to see what you''ve actually built in this first module. Because if you''re like most people, you''ve been so focused on absorbing the next concept that you haven''t stopped to look back at how far you''ve come from where you started."},{"type":"text","content":"Look at this list. This is your toolkit. You didn''t have any of it a few weeks ago."},{"type":"divider"},{"type":"bold_text","content":"1. The Seven Devils"},{"type":"text","content":"You know the seven patterns that erode relationships over time: Criticism, Contempt, Defensiveness, Stonewalling, Avoidance, Unhealthy Coping, and Intimacy Loss. You can see them in action — in your relationship, in others''. You have names for what used to be nameless."},{"type":"bold_text","content":"2. Critter Brain / CEO Brain"},{"type":"text","content":"You understand why your body sometimes takes over a conversation your mind was trying to have. You know the difference between the survival response and the reasoning response — and you know that both of them are doing their job. Neither one is the enemy."},{"type":"bold_text","content":"3. The 90-Second Wave"},{"type":"text","content":"You know that the chemistry of emotional activation lasts approximately ninety seconds if you don''t feed it. You know that what extends past ninety seconds is something you''re choosing, usually unconsciously — and that means it can be unchoosen. That''s not a small thing to know."},{"type":"bold_text","content":"4. The 5 Zones of Resilience"},{"type":"text","content":"You have a map of your own nervous system: Red, Yellow Hyper, Green, Yellow Hypo, Blue. You can, with practice, locate yourself on that map — which is the first step to navigating it intentionally instead of being carried wherever it takes you."},{"type":"bold_text","content":"5. The 30-Second Reset"},{"type":"text","content":"You have an emergency practice. Hand on heart, three slow breaths, audible sigh on the exhale. It doesn''t require your partner, it doesn''t require a perfect moment, and it doesn''t require you to be calm to use it. It''s the thing you do when your system is starting to move, before it moves too far."},{"type":"bold_text","content":"6. The SPARK Method"},{"type":"text","content":"You have a conflict navigation sequence: See, Pause & Probe, Acknowledge, Reconnect, Kindle. You know not just the steps but the why behind each one — what each step is doing to the nervous system, why the sequence is designed in this order, what it''s trying to protect. When you understand the why, you use the how."},{"type":"bold_text","content":"7. The Pause Number"},{"type":"text","content":"You have a signal. A number — yours — that means I need twenty minutes without that sentence having to become an explanation or a negotiation in the middle of a hard conversation. That number is an act of care for your relationship. It says: I know myself well enough to know when I need to step back, and I trust us enough to come back."},{"type":"bold_text","content":"8. The SPARK Pact"},{"type":"text","content":"You have an agreement. A standing promise between you and your partner — made in a calm moment, before a hard one — that you''ll reach for the method instead of the pattern. The Pact doesn''t guarantee anything. It just lowers the activation cost of the first move."},{"type":"bold_text","content":"9. The 7-Day Practice Plan"},{"type":"text","content":"And now you have a structure. Seven days, one step each, to move from knowing these tools to using them. Not perfectly. Not dramatically. Just once, then again, then again."},{"type":"divider"},{"type":"text","content":"Look at everything you now have."},{"type":"text","content":"This is not a summary of Module 1. This is a set of real tools — built on research, refined in real relationships, tested in real sessions — that belong to you. Print this list. Put it somewhere you''ll see it. When the next hard moment comes, and it will come, you don''t have to remember all nine things. You just have to remember that you have them."},{"type":"text","content":"That''s what this list is for."},{"type":"divider"},{"type":"reflection","content":"Reflection: Your Toolkit"},{"type":"text","content":"Of these nine tools, which one surprised you most? Which one do you think will be hardest to use consistently? And which one — if you only used one — would change the most for you right now?"}]}'::jsonb),
    (mod1_id, parent_id, 'What Comes Next', 406, '{"estimated_minutes":6,"blocks":[{"type":"text","content":"You did something in this module."},{"type":"text","content":"I want to say that before I say anything about what comes next, because sometimes we move so quickly from one thing to the next that we forget to acknowledge the thing we just did. You didn''t just read about relationship patterns. You looked at your own. You learned why your body does what it does in a hard moment, and you started building the skill to do something different."},{"type":"text","content":"That is not a small thing. Most couples never do it at all."},{"type":"divider"},{"type":"text","content":"Look at where you stand:"},{"type":"text","content":"You met the Seven Devils — the seven patterns that quietly dismantle trust, closeness, and safety over time. You learned why your body hijacks conversations your mind was trying to have. You practiced the method. You built your first seven days."},{"type":"text","content":"And somewhere in this module, if you''re honest with yourself, you recognized something. Maybe it was a Devil you''ve been living with for years. Maybe it was a Zone you keep coming back to. Maybe it was just a moment in the clean sheets story where you thought, I want to be the person who notices that. That recognition — whatever yours was — is worth keeping."},{"type":"divider"},{"type":"text","content":"Module 2 goes deeper."},{"type":"text","content":"It takes each of the Seven Devils and opens them up — the attack patterns, the protect patterns, the way each one evolved, why it worked once, why it''s working against you now. Each Devil gets its own specific tools. Not just \"watch for this pattern\" but \"here is what this Devil is protecting, here is where it usually came from, and here is the specific practice that addresses it at the root.\""},{"type":"text","content":"The work in Module 1 was foundational. The work in Module 2 is diagnostic. You''ll come out of it knowing not just what your patterns are, but why they chose you — and what it takes to choose something different."},{"type":"divider"},{"type":"text","content":"I also want to say one more thing, quietly, before we close."},{"type":"text","content":"If you''re at a place where you want more than a module can give you — more time, more depth, more personal support, more of the harder work done alongside Jeff and me and a community of people doing the same thing — the full Healing Hearts Program is built for that. It''s eight modules and thirty-two lessons, and it''s designed for couples who are ready to go slowly and thoroughly into what''s actually running their relationship. It''s not for everyone, and it''s not an impulse decision. But if it''s something you''ve been thinking about, you can find it at healingheartscourse.com/programs."},{"type":"text","content":"We''re here when you''re ready."},{"type":"divider"},{"type":"text","content":"For now, take one more step before you move to Module 2."},{"type":"text","content":"Write down your implementation intention. Not goals — intentions. Specifically:"},{"type":"text","content":"When will I do my first Devil Audit of Module 2? (Name a day and a time.)"},{"type":"text","content":"Who do I want to be in my relationship after Module 2? (One sentence — not a goal, a vision.)"},{"type":"text","content":"What is the one thing from Module 1 I most want to keep practicing? (Name it. Put it somewhere you''ll see it.)"},{"type":"divider"},{"type":"text","content":"These three sentences are your bridge. They''re the thing you carry out of Module 1 into everything that comes next."},{"type":"divider"},{"type":"audio","title":"1:30, Trisha & Jeff together — warm closing invitation, conversational. NOT a sales pitch."},{"type":"divider"},{"type":"bold_text","content":"Implementation Intention"},{"type":"text","content":"Fill in or type your responses:"},{"type":"text","content":"When I will complete my first Module 2 Devil Audit: `_______________________________________________________`"},{"type":"text","content":"Who I want to be in my relationship after Module 2: `_______________________________________________________`"},{"type":"text","content":"The one practice from Module 1 I''m committing to keep: `_______________________________________________________`"},{"type":"divider"},{"type":"reflection","content":"Reflection: A Gratitude and a Takeaway"},{"type":"text","content":"What''s a gratitude from this first module — something or someone you''re genuinely glad you encountered along the way? And what''s the single most useful thing you''re taking with you into Module 2?"},{"type":"text","content":"Hold those two things. They''re yours."},{"type":"text","content":"We''ll see you there."}]}'::jsonb);

  -- ─── Lesson 2.1: The Words That Wound ───
  INSERT INTO lessons (module_id, title, sort_order, content_json)
  VALUES (
    mod2_id,
    'The Words That Wound',
    1,
    '{"estimated_minutes":37,"blocks":[{"type":"heading","content":"The Words That Wound"},{"type":"text","content":"Criticism and Contempt — the attack patterns that corrode trust."}]}'::jsonb
  ) RETURNING id INTO parent_id;

  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, content_json) VALUES
    (mod2_id, parent_id, 'The Tiny Cut', 101, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"It started with a baseball cap."},{"type":"text","content":"She told him she didn''t want him to wear it backwards. Simple as that. She thought she was being helpful — offering a little opinion, a small nudge. \"You look so much better the other way.\" She meant it as a compliment. She had no idea it was anything else."},{"type":"text","content":"I asked her to stop and actually hear what she''d said."},{"type":"text","content":"Something shifted in her face."},{"type":"text","content":"\"I never even realized,\" she said quietly. \"I thought I was encouraging him.\""},{"type":"text","content":"She looked across at him then. He didn''t say anything. He didn''t need to. His shoulders had done it for him — that slow, familiar sinking of someone who has been hearing some version of you''d be better if for a long time."},{"type":"text","content":"Here''s what she couldn''t see from inside the moment: she wasn''t making one comment about a hat. She was adding one more cut to a collection she didn''t know she was building. Every small correction. Every gentle suggestion. Every \"I think it would look better if...\" Every \"I just meant...\" All of it landing in the same place, over and over, until the place was raw."},{"type":"text","content":"\"Criticism doesn''t always sound like yelling,\" I told her."},{"type":"text","content":"\"Sometimes it sounds like a suggestion. Sometimes it sounds like help.\""},{"type":"text","content":"She was quiet for a long moment. \"That''s the worst part,\" she finally said. \"Because I genuinely thought I was helping him.\""},{"type":"text","content":"That''s exactly the thing I want you to hold as we go into this lesson."},{"type":"text","content":"The most damaging kinds of criticism are usually the ones that arrive in the soft packaging of helpfulness. Not the fights. Not the blowups. The quiet, steady undercurrent of small improvements you''ve been quietly offering your partner — day after day after day — that have been teaching them, without a single raised voice, that you see their flaws more clearly than you see their worth."},{"type":"text","content":"In Module 1, we named all seven Devils. We saw them from a distance — enough to recognize the pattern, enough to start noticing when one walked into the room."},{"type":"text","content":"In Module 2, we go closer. We look each one in the eye."},{"type":"text","content":"The first two — Criticism and Contempt — are the attack patterns. They are the ones that move toward your partner. They are what your Critter Brain reaches for when it decides the best way to feel safe is to make sure the other person knows what''s wrong with them."},{"type":"text","content":"Red Zone. Fight response. The Critter Brain in full forward motion."},{"type":"text","content":"That''s where we''re starting. Not to shame anyone who recognizes themselves here. But because these two Devils are quiet enough to go undetected for years — and devastating enough that Gottman''s research identified one of them as the single greatest predictor of divorce."},{"type":"text","content":"Let''s look honestly."}]}'::jsonb),
    (mod2_id, parent_id, 'Criticism: Making Your Partner Feel Defective', 102, '{"estimated_minutes":10,"blocks":[{"type":"audio","title":"1:30, Jeff — tells the kitchen story, owning his criticism"},{"type":"text","content":"Jeff is a precise person. He has an efficient way of doing things, a preference for order, a deeply held opinion about not doing any task twice. It''s served him well for decades."},{"type":"text","content":"I am not that person."},{"type":"text","content":"When I cook — and I love to cook, it''s one of my favorite ways to spend an afternoon — I spread out. Ingredients across every surface. Bowls stacked and nested. The stovetop involved in at least three things at once. It looks, by the time I''m done, like a kitchen that has survived something significant."},{"type":"text","content":"Jeff has stood in the doorway of that kitchen more than once."},{"type":"text","content":"And more than once, right after I''ve fed him something he loved — something I''d spent actual creative energy thinking up — he has offered a small, carefully worded suggestion about maybe putting one thing away as I go."},{"type":"text","content":"That''s all it takes. One comment. The meal disappears. The afternoon of cooking disappears. What''s left is just the mess, and a quiet sense that the mess is the thing he noticed."},{"type":"text","content":"That is criticism. Not a fight. Not cruelty. Just a single remark, carefully aimed at the one thing that didn''t meet the standard."},{"type":"heading","content":"What Criticism Actually Is"},{"type":"text","content":"Here is the line that matters: a complaint is about a behavior. Criticism is about a person."},{"type":"text","content":"A complaint says: \"I was frustrated this morning when the kitchen was messy — can you help me keep up with it?\" That''s fair. That''s honest. That is one person asking another for something specific."},{"type":"text","content":"Criticism does something different. It takes a moment and turns it into a verdict on character."},{"type":"text","content":"\"You never think about anyone else when you''re in the kitchen.\"* *\"Why would you do it that way? It doesn''t make any sense.\"* *\"You''re always so careless.\""},{"type":"text","content":"Hear the shift? One describes a moment. The other describes the person."},{"type":"text","content":"And when your partner hears a permanent label — \"always,\" \"never,\" \"you''re so...\" — they don''t think: I should try harder. They think: Why bother? You''ve already decided who I am."},{"type":"heading","content":"What Criticism Sounds Like in Real Life"},{"type":"text","content":"And this is what trips most people up: criticism almost never sounds like cruelty from the inside. It sounds like honesty. It sounds like helpfulness. It sounds like the reasonable observations of someone who pays attention."},{"type":"text","content":"It sounds like:"},{"type":"list","items":["\"I''m just trying to help.\"","\"Can you at least...?\"","\"You always forget.\"","\"Did you really think that was a good idea?\"","\"Why can''t you just...?\"","A sigh. A look. An eyebrow raised a fraction of an inch."],"ordered":false},{"type":"text","content":"That last set — the non-verbal list — is where people get surprised. Criticism doesn''t require words. A tone carries it perfectly. So does a sigh timed to land at the exact right moment. So does an expression that says, quietly but clearly, that again?"},{"type":"text","content":"Remember Rachel from Module 1 — the woman whose husband had gone quiet over the years? His words stayed with me: \"Because every time I say something, I feel like you''re looking for what''s wrong with it.\""},{"type":"text","content":"That sentence is worth hearing again, because it captures exactly what chronic criticism does to a person. Rachel loved her husband. She was also a person who had been correcting, adjusting, and offering small improvements for so long that it had become invisible to her — and deafening to him."},{"type":"heading","content":"Critter Brain in Attack Mode"},{"type":"text","content":"When criticism is the pattern, your Critter Brain is running the show. That''s what the Red Zone looks like: not rage, not screaming — just the constant, low hum of your nervous system treating your partner as a problem to be managed."},{"type":"text","content":"The Critter Brain''s logic is straightforward: If I can correct the things that are wrong, I will feel safer. It''s not malicious. It''s not even conscious. It''s a survival strategy wearing the clothing of helpfulness."},{"type":"text","content":"But your partner''s Critter Brain is receiving the signal that criticism sends, regardless of intention. That signal, over time, is unmistakable: You are not quite right as you are."},{"type":"text","content":"I said it in Module 1 and it bears repeating: criticism makes the person on the receiving end feel defective. And when someone feels defective around you, they stop bringing themselves fully into the room. Not all at once. Gradually. The way a plant turns toward light, quietly, until one day you notice it''s turned all the way away from you."},{"type":"text","content":"Watch for the always and never. Those are the fingerprints. Every \"you always\" and \"you never\" takes a single behavior and turns it into a permanent feature of who your partner is. That''s the thing to catch — in your voice, and in your own internal narration about your partner."},{"type":"divider"},{"type":"reflection","content":"Take a moment with this honestly."},{"type":"text","content":"What does criticism sound like in your voice?"},{"type":"text","content":"Not the loud version. The quiet version — the sigh, the correction, the helpfully worded suggestion that lands somewhere it wasn''t meant to land."},{"type":"text","content":"You don''t have to answer out loud. Just notice what comes up."}]}'::jsonb),
    (mod2_id, parent_id, 'Contempt: The Marriage Killer', 103, '{"estimated_minutes":10,"blocks":[{"type":"audio","title":"1:00, Trisha — \"That recognition is not a verdict. It''s an invitation.\""},{"type":"text","content":"You heard me say it in Module 1: if criticism is a splinter, contempt is a wound. Now I want you to feel why."},{"type":"text","content":"Gottman''s research is unambiguous. After observing thousands of couples — tracking their words, their expressions, the chemistry of their bodies during conflict — he identified contempt as the single greatest predictor of divorce. Not the frequency of fights. Not the volume. Not whether you have money problems or blended-family complications or opposite sleep schedules. Contempt. It outpredicts everything else by a significant margin."},{"type":"text","content":"I want you to really let that land before we move forward."},{"type":"text","content":"Not how often you fight. How you look at each other when you fight."},{"type":"heading","content":"What Contempt Actually Is"},{"type":"text","content":"Contempt is what happens when criticism hardens into superiority."},{"type":"text","content":"It''s the eye roll. The sigh that communicates I cannot believe I have to explain this again. The sarcasm that''s just a little too sharp to land as funny. The tone that makes it clear, without saying a word, that you don''t fully respect the person you''re talking to."},{"type":"text","content":"It sounds like:"},{"type":"list","items":["\"Are you seriously telling me you didn''t know that? It''s not complicated.\"","\"Oh, please. Like you would understand.\"","\"I''m not surprised. This is exactly what you always do.\"","\"Whatever. Forget it.\" (said in a way that means: you''re not worth the effort.)"],"ordered":false},{"type":"text","content":"Contempt doesn''t just hurt feelings. Gottman''s research found that the partner on the receiving end of chronic contempt shows measurable immune suppression. Their bodies register it as genuine threat. That''s how deep it lands."},{"type":"heading","content":"Where Contempt Comes From"},{"type":"text","content":"Jeff grew up watching his father work. His father was sharp, capable, the kind of man who always knew the right answer and wasn''t shy about making sure everyone in the room knew it too. When Jeff made mistakes in his father''s shop — scratched a paint job, got something wrong — his father made sure the lesson included a clear communication about who was the smartest person in that building."},{"type":"text","content":"Jeff learned a lot from his father. He learned how to work. He learned precision and craft and the satisfaction of a job done right."},{"type":"text","content":"He also learned contempt. Absorbed it slowly, the way children absorb everything — not as a choice, but as an understanding of how the world works."},{"type":"text","content":"I''m sharing this because it matters: contempt is almost always learned. It''s what it looks like when someone grows up around it long enough that it becomes the default register for handling frustration or insecurity. That doesn''t make it excusable in a marriage. But it does make it something other than a character flaw. It''s a pattern — installed before you had any say in it — and patterns can change."},{"type":"text","content":"Jeff will tell you himself: recognizing where he learned contempt was one of the more uncomfortable discoveries of his adult life. And one of the most useful."},{"type":"heading","content":"Contempt and the Red Zone"},{"type":"text","content":"Contempt lives in the Red Zone — Critter Brain in full activation, but aimed outward in a specific direction. The fight response, turned not just toward conflict but toward the person themselves."},{"type":"text","content":"Where criticism says you did something wrong, contempt says you are less than. It communicates hierarchy. It says, clearly, that the speaker is above the receiver in some important way — in intelligence, in judgment, in worth."},{"type":"text","content":"And your partner''s nervous system knows the difference."},{"type":"text","content":"Criticism activates the Critter Brain into defensiveness. Contempt activates it into something deeper: shame. And shame, unlike defensiveness, doesn''t fight back. It collapses."},{"type":"text","content":"Over time, a partner who has been the steady recipient of contempt doesn''t just get defensive. They get smaller. They qualify their opinions before they offer them. They stop making suggestions. They disappear from the room before they physically leave it."},{"type":"heading","content":"How Contempt Grows"},{"type":"text","content":"You may remember the progression I described in Module 1: frustration turns into a habit of noticing what your partner does wrong, and that habit builds a mental highlight reel of their failures. But here is the part I want to add now that you know the nervous system science: that highlight reel is not just a thinking pattern. It is a Critter Brain strategy. Your system has learned that cataloguing your partner''s shortcomings feels like preparation — like arming yourself for the next disappointment. And the longer the reel runs, the harder it becomes to see your partner as anything other than what the reel shows you."},{"type":"text","content":"Remember what we said in Module 1: the soil contempt grows in is unappreciation."},{"type":"text","content":"When we stop seeing what our partner does right — when we stop saying thank you, stop noticing the effort, stop acknowledging what''s working — something moves in to fill that space. Resentment, first. Then, over time, something colder. A lens of disdain that eventually becomes hard to put down."},{"type":"text","content":"Contempt is resentment that has been left untreated long enough to turn into something that looks like an identity."},{"type":"heading","content":"A Note Before the Reflection"},{"type":"text","content":"If you''re reading this and recognizing contempt in your marriage — whether you''re the one who''s been expressing it or the one who''s been living on the receiving end of it — I want to say something clearly:"},{"type":"text","content":"That recognition is not a verdict. It''s an invitation."},{"type":"text","content":"Contempt is one of the most damaging patterns in a relationship. It is also a pattern with a clear antidote, which we''re about to talk about. Couples come back from contempt. It takes real work, sustained attention, and a willingness to rebuild a culture that was eroded slowly. But it happens. I''ve watched it happen."},{"type":"text","content":"The fact that you''re here, looking at this honestly, already means something."},{"type":"text","content":"If what you''re reading here is landing somewhere heavier than this lesson can hold — if there''s a history of contempt in your relationship that feels too large to work with on your own — please reach out to a therapist or counselor. This work matters, and so do you."},{"type":"divider"},{"type":"reflection","content":"Sit with this honestly."},{"type":"text","content":"Have you ever felt looked down on by your partner? A moment when their words, tone, or expression communicated that you were less than?"},{"type":"text","content":"Or — and this one takes more courage to ask — have there been moments when you communicated that to them?"},{"type":"text","content":"You don''t need to build a case or make a list. Just let yourself feel what comes up."}]}'::jsonb),
    (mod2_id, parent_id, 'The Antidote: Appreciation as Practice', 104, '{"estimated_minutes":9,"blocks":[{"type":"text","content":"Here''s what I want to say plainly before we go any further."},{"type":"text","content":"The antidote to criticism and contempt is not a single compliment. It is not a grand gesture. It is not one good conversation about what''s been building."},{"type":"text","content":"It is a culture."},{"type":"text","content":"A daily, ongoing, ordinary culture of noticing what your partner does right — and saying so. Not once a week. Not on anniversaries. Every day, in the small moments where it costs almost nothing and deposits something significant."},{"type":"text","content":"That muscle gets stronger with practice. Jeff says this in the kitchen all the time now — not because I remind him to, but because he''s spent years building the habit of seeing me before he sees the mess."},{"type":"heading","content":"What Appreciation Does to the System"},{"type":"text","content":"When your partner consistently receives appreciation from you, their Critter Brain receives a very different signal than the one criticism sends. Instead of you are being evaluated, the signal is: you are seen. You are valued here. This is safe ground."},{"type":"text","content":"That signal, repeated day after day, changes the entire relational environment. It makes your partner more likely to try things, share things, stay in the room when conversations get hard. Not because they''ve been trained, but because their nervous system has genuinely learned that being with you is safe."},{"type":"text","content":"This is what Gottman calls the culture of appreciation and respect — and it''s the direct counter to the contempt cycle. You cannot sustain contempt and genuine appreciation at the same time. One crowds out the other. Your job is to make appreciation the habit that runs so deep the contempt has nowhere to take root."},{"type":"heading","content":"The SPARK Connection: Starting with See"},{"type":"text","content":"You''ve already learned the SPARK Method in Lesson 1.3. The S — See — is where the antidote to criticism and contempt lives."},{"type":"text","content":"See means noticing your partner before you assess them. It means looking for what''s present before cataloguing what''s absent. It''s the gentle startup that the S step is designed for: instead of leading with what bothers you, leading with what you notice that''s good."},{"type":"text","content":"\"I saw you stayed up late to finish that thing for the kids. Thank you.\"* *\"You''ve been carrying a lot this week. I see it.\"* *\"I love the way you handled that.\""},{"type":"text","content":"The SPARK method works in conflict. The S step works everywhere else, too — in the daily ordinary moments where appreciation either gets spoken or doesn''t."},{"type":"heading","content":"What Specific Appreciation Sounds Like"},{"type":"text","content":"Here''s the distinction: vague appreciation and specific appreciation do different things in your partner''s body."},{"type":"text","content":"\"You''re great\"* is nice. *\"I love that you remembered the thing I mentioned three weeks ago and you just quietly took care of it\"* is something your partner''s Critter Brain can use. Specificity signals attention. And attention signals: *I see you. Not just a general you — the particular, specific, irreplaceable you."},{"type":"text","content":"Some examples of what specific appreciation sounds like in practice:"},{"type":"list","items":["\"I love this meal. How did you even come up with this combination? It''s incredible.\"","\"You worked a full day and still made dinner. I don''t take that for granted.\"","\"The way you talked to her when she was upset — that was really good. You knew exactly what she needed.\"","\"Thank you for being patient with me this week. I know I''ve been a lot.\""],"ordered":false},{"type":"text","content":"The more specific, the more it lands."},{"type":"heading","content":"Building the Practice"},{"type":"text","content":"Appreciation is a muscle. The more you use it, the stronger it gets, and the more natural it becomes to reach for it first — before the criticism, before the suggestion, before the \"could you maybe...\""},{"type":"text","content":"When gratitude is practiced regularly, something else happens: the things that used to generate criticism start to read differently. The mess in the kitchen becomes context for the meal. The forgotten item becomes a small moment inside a relationship that is fundamentally good. The lens shifts."},{"type":"text","content":"That''s not magical thinking. That''s what happens to a nervous system that has been consistently given evidence that its partner is worth appreciating."},{"type":"divider"},{"type":"bold_text","content":"Fillable Form: Three Things I Appreciate About My Partner"},{"type":"text","content":"Take three minutes. Think about your partner as they actually are — not the best version, not the worst version — just the real, everyday, showing-up version."},{"type":"text","content":"Write down three specific things you genuinely appreciate."},{"type":"text","content":"1. Something they do: _______________________________________________ _______________________________________________"},{"type":"text","content":"2. Something they are — a quality or trait you actually love: _______________________________________________ _______________________________________________"},{"type":"text","content":"3. Something they''ve done recently that you noticed but maybe didn''t say out loud: _______________________________________________ _______________________________________________"},{"type":"divider"},{"type":"text","content":"One more step: which of these are you going to actually say to them today?"},{"type":"text","content":"I will share: _________________________________ with my partner by: _______________________"}]}'::jsonb),
    (mod2_id, parent_id, 'Practice: The Appreciation Exchange', 105, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"Everything we''ve talked about in this lesson has been about understanding the pattern — naming Criticism and Contempt, seeing where they come from, recognizing the nervous system response they generate. That understanding matters. But understanding alone doesn''t change a marriage."},{"type":"text","content":"Practice does."},{"type":"text","content":"This practice is the simplest possible version of building a culture of appreciation. It''s not complicated. It takes about five minutes. And if you do it consistently, it will change something in the way you and your partner see each other."},{"type":"heading","content":"The Appreciation Exchange"},{"type":"text","content":"What you need: Two people, five minutes, a quiet enough space that you can actually hear each other. That''s it."},{"type":"bold_text","content":"What you do:"},{"type":"text","content":"Each partner shares three appreciations. One at a time, face to face. You look at each other when you say them."},{"type":"text","content":"The appreciations should be:"},{"type":"list","items":["Specific (not \"you''re great,\" but what exactly you noticed)","About something real and recent (not a lifetime greatest-hits compilation)","Spoken out loud, not written"],"ordered":false},{"type":"text","content":"The person receiving the appreciation''s only job is to hear it. No deflecting. No \"oh, that wasn''t a big deal.\" No \"well, you do that too.\" Just receive it. Let it land."},{"type":"text","content":"Then the other partner shares theirs."},{"type":"text","content":"That''s the whole practice."},{"type":"heading","content":"A Note on Safety"},{"type":"text","content":"I know some of you are reading this in relationships where there has been a lot of contempt — where appreciation feels fake, or risky, or like it will be met with suspicion. If that''s where you are, that''s worth acknowledging honestly."},{"type":"text","content":"If the contempt has been significant, this practice may feel tender before it feels good. You might find that hearing appreciation from your partner makes you defensive rather than open — because you''ve been braced for the opposite for so long. That''s your Critter Brain doing its job."},{"type":"text","content":"Do it anyway. Start small. Keep it sincere. Give your system time to learn that appreciation here is safe."},{"type":"text","content":"If you''re doing this practice in a place of deep rupture — where the contempt cycle has been running for a long time and the distance between you feels significant — please don''t use this practice as a substitute for professional support. Use it alongside it."},{"type":"fillable_form","form_id":"your-implementation-intention","title":"Your Implementation Intention","fields":[],"intro":"A practice only sticks if it''s attached to something specific. Vague intentions are how practices stay theoretical. So: when, exactly, are you going to do this?"},{"type":"divider"},{"type":"bold_text","content":"Fillable Form: Appreciation Exchange Plan"},{"type":"text","content":"When we will do our first Appreciation Exchange:"},{"type":"text","content":"Day: ________________________________"},{"type":"text","content":"Time: ________________________________"},{"type":"text","content":"Place: ________________________________"},{"type":"text","content":"Who will initiate it: ________________________________"},{"type":"text","content":"Three appreciations I am planning to share:"},{"type":"list","items":["________________________________","________________________________","________________________________"],"ordered":true},{"type":"text","content":"After we complete this practice, I will notice:"},{"type":"text","content":"________________________________ ________________________________"},{"type":"divider"},{"type":"heading","content":"Implementation Intention"},{"type":"text","content":"Complete this before you close this lesson:"},{"type":"text","content":"\"The next time I catch myself starting to criticize or correct my partner, I will pause and ask: what do I appreciate about them right now? And then I will say it.\""},{"type":"text","content":"Write it down. Not because the words are magic — but because writing it makes it real in a way that thinking it doesn''t."},{"type":"divider"},{"type":"reflection","content":"Before you close this lesson, take one quiet minute. What is one thing you''re grateful to understand now that you didn''t understand when you opened this lesson today? And what is one thing you''re taking with you?"},{"type":"divider"},{"type":"heading","content":"What''s Ahead"},{"type":"text","content":"You''ve just done some of the harder work in this course. Looking honestly at Criticism and Contempt requires a particular kind of courage — because these are the Devils that most often live in the space between good intentions and impact, between meaning well and landing wrong."},{"type":"text","content":"The fact that you looked is something to be proud of."},{"type":"text","content":"In the next lesson, we turn to Devils 3 and 4: Defensiveness and Stonewalling. If Criticism and Contempt are the forward-moving attack patterns, Defensiveness and Stonewalling are the shield — what your Critter Brain reaches for when it decides the best way to stay safe is to deflect or disappear. They are the mirror image of what you learned today, and together, these four Devils form the core of the cycle that keeps most couples stuck."},{"type":"text","content":"We''ll see you there."}]}'::jsonb);

  -- ─── Lesson 2.2: The Wall and the Door ───
  INSERT INTO lessons (module_id, title, sort_order, content_json)
  VALUES (
    mod2_id,
    'The Wall and the Door',
    2,
    '{"estimated_minutes":37,"blocks":[{"type":"heading","content":"The Wall and the Door"},{"type":"text","content":"Defensiveness and Stonewalling — the shield and the wall."}]}'::jsonb
  ) RETURNING id INTO parent_id;

  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, content_json) VALUES
    (mod2_id, parent_id, 'The Disappearing Act', 201, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"She wanted him to talk. That was the whole thing — she wanted to know what he was thinking, what he was feeling, what was going on behind the silence. She brought it up over and over. She begged. She pushed. She picked fights just to get a reaction, because at least anger was something."},{"type":"text","content":"He had a different story."},{"type":"text","content":"\"I stopped sharing,\" he told me, months into our work together — once he finally felt safe enough to say it out loud. \"I wanted to. But every time I opened up, it got used against me later. So I just... stopped. It was easier not to say anything.\""},{"type":"text","content":"She was drowning in silence. He was drowning in the fear of what would happen if he spoke."},{"type":"text","content":"This is the cycle I see more than any other. One partner can''t stop talking about the problem. The other can''t start. And the harder she pushes, the further he retreats. The further he retreats, the harder she pushes. Both of them are hurting. Neither one can see the other''s pain, because they''re too deep in their own."},{"type":"text","content":"It''s not that one of them is right. It''s that the pattern itself is the enemy."},{"type":"divider"},{"type":"text","content":"In the last lesson, we looked at the first two Devils — Criticism and Contempt — the ones that attack. They reach across the space between two people and land like blows, sometimes loud, sometimes as quiet as a look or a tone."},{"type":"text","content":"Devils 3 and 4 do something different. They don''t attack. They protect. One builds a shield. The other builds a wall."},{"type":"text","content":"Defensiveness and stonewalling look like opposites, but they are both your Critter Brain protecting you. One presses the gas. The other pulls the brake. And they often show up in the same conversation — one partner defending with everything they''ve got, the other partner shutting down because they''ve got nothing left."},{"type":"text","content":"If Criticism and Contempt are the swords, Defensiveness and Stonewalling are the armor. And that armor has a cost."},{"type":"text","content":"Let''s look at what happens when your Critter Brain decides that the best way to survive a conversation is to stop being in it."}]}'::jsonb),
    (mod2_id, parent_id, 'Defensiveness: The Shield That Blocks Connection', 202, '{"estimated_minutes":10,"blocks":[{"type":"text","content":"When your partner brings up a concern — even a reasonable one, even gently — what happens in your body first?"},{"type":"text","content":"For many of us, the answer is immediate and physical. Chest tightens. Jaw sets. The first thought is not What are they feeling? but How do I protect myself? Your system shifts into Yellow Hyper before the sentence is even finished. Heart rate climbing, thoughts narrowing, that familiar surge of energy that says: I need to explain. I need to defend. I need to make sure they know this isn''t all my fault."},{"type":"text","content":"That''s your Critter Brain in protect mode. And the Devil it summons is Defensiveness."},{"type":"heading","content":"What Defensiveness Actually Looks Like"},{"type":"text","content":"Defensiveness isn''t always loud. It''s not always a counter-attack. Sometimes it shows up in surprisingly quiet clothing. Jeff and I have identified three faces it wears:"},{"type":"text","content":"Victimhood. \"I guess nothing I do is ever good enough.\" This version flips the conversation so that the person who raised the concern is now the one causing harm. The message underneath is: I''m the one who''s hurting here, not you."},{"type":"text","content":"Righteous Indignation. \"I can''t believe you would bring THAT up.\" This version doesn''t address the concern at all. It attacks the fact that the concern was raised. The message: You have no right to say that to me."},{"type":"text","content":"Proclaiming Innocence. \"I would never do that. That''s not what happened.\" This version rewrites the event so thoroughly that your partner starts questioning their own memory. The message: Your experience of what happened is wrong."},{"type":"text","content":"Every one of these moves does the same thing: it redirects the conversation away from your partner''s experience and back onto yours. And every time it works, your partner learns something. They learn that bringing a concern to you leads to a wall, not a bridge. Over time, they stop coming to you at all."},{"type":"heading","content":"The Zone: Yellow Hyper"},{"type":"text","content":"Remember the Zones from Module 1? Defensiveness lives in Yellow Hyper — that place where your system is revving up, your Critter Brain has perked its ears, and your CEO Brain is losing the steering wheel. You''re not in full Red Zone activation. You can still form sentences. But those sentences are being assembled by a part of you that cares more about being right than being close."},{"type":"text","content":"Yellow Hyper is your foot pressing the gas. Your body is heating up. Your thinking is narrowing. And the words that come out are faster, sharper, and more focused on winning than on understanding."},{"type":"text","content":"This is why defensiveness feels so justified in the moment. Your Critter Brain isn''t confused — it genuinely believes you are under attack. And the part of your brain that could slow things down, that could say Wait, what is my partner actually asking for here? — your CEO Brain — has been dimmed. Not gone, but dimmed. Enough that the shield goes up before you even notice you''ve raised it."},{"type":"heading","content":"Jeff''s Daughter"},{"type":"audio","title":"1:30, Jeff — his daughter story, modeling accountability"},{"type":"text","content":"I want to share something from Jeff, because I think it matters to hear this from a man who is willing to say it out loud."},{"type":"text","content":"There was a morning — an ordinary, rushed morning — when one of our daughters needed help with something time-sensitive. The kind of thing that couldn''t wait. Jeff was about to head out the door, and I asked him to handle something else first. He listened to me instead of leaving when our daughter had asked. And when it didn''t turn out well — when our daughter asked him later why he hadn''t just come when she needed him — he felt that old pull."},{"type":"text","content":"The pull to say: Your mother told me to do something else. The pull to redirect. To explain. To make sure everyone knew this wasn''t his fault."},{"type":"text","content":"That pull is defensiveness. It is the most natural thing in the world — to take the weight of a bad outcome and try to set it on someone else''s shoulders, even someone you love."},{"type":"text","content":"But Jeff caught it. He stopped. He took responsibility. He told our daughter: \"I should have done it differently. I should have left when you asked me to. I''m sorry.\""},{"type":"text","content":"He didn''t blame me. He didn''t explain the context. He owned the ten percent — or maybe the fifty percent — that was his. And that was enough."},{"type":"text","content":"I share this not because Jeff is perfect. He would be the first to tell you he is not. I share it because defensiveness is not a character flaw reserved for people who don''t care. It shows up most fiercely in people who care deeply and are terrified of being seen as the one who failed. That''s what makes it so hard to catch. The shield goes up because the heart behind it is tender."},{"type":"reflection","content":"When you feel accused — even slightly, even unfairly — what''s your first move? Think about a recent moment when your partner brought up something that landed like a criticism, whether or not they intended it that way. What did your body do? What was the first sentence your mind assembled? You don''t have to change it right now. Just see it."}]}'::jsonb),
    (mod2_id, parent_id, 'Stonewalling: When the Door Becomes a Wall', 203, '{"estimated_minutes":10,"blocks":[{"type":"audio","title":"1:00, Trisha — to the partner who gets stonewalled: \"Their silence is not about you.\""},{"type":"text","content":"If defensiveness is the shield that blocks connection, stonewalling is the door that becomes a wall."},{"type":"text","content":"It looks like silence. Monosyllable answers. A blank stare. Arms crossed, eyes somewhere else, the person sitting right next to you but a thousand miles away. Fine. Whatever. I don''t want to fight. And then they leave the room — physically, emotionally, or both — without explanation, without a timeline, without any indication that they''re coming back."},{"type":"text","content":"To the partner on the other side of that wall, it feels like abandonment. Like standing in the middle of something important and having the door close in your face. Like your words just stopped mattering."},{"type":"text","content":"But here is what I need you to understand about the person behind the wall: they are not doing this to punish you. Most of the time, they are not making a choice at all."},{"type":"heading","content":"What''s Happening Inside the Wall"},{"type":"text","content":"Stonewalling is almost always a response to being overwhelmed. The person who goes silent isn''t being strategic. Their system has flooded. Heart rate spiking past the point where words can form. Thoughts scattering. That heavy, sinking feeling where everything gets thick and slow and your body simply cannot produce a coherent sentence, let alone a kind one."},{"type":"text","content":"This is your Critter Brain pulling the emergency brake."},{"type":"heading","content":"The Zone: Yellow Hypo to Blue"},{"type":"text","content":"Where defensiveness lives in Yellow Hyper — system revving up, energy rising — stonewalling moves in the opposite direction. It starts in Yellow Hypo, where your system begins to slow. Foggy. Disengaged. That low-power mode where your partner is talking and you can hear the words but your brain is buffering. You care. You just don''t have the bandwidth."},{"type":"text","content":"And if it goes far enough, it drops into Blue — full shutdown. Numb. Heavy. Disconnected. Your Critter Brain has decided that the safest thing to do is stop. Stop talking. Stop feeling. Stop being present. Just... survive until it passes."},{"type":"text","content":"This is why stonewalling and defensiveness look like opposites but come from the same place. Defensiveness is your Critter Brain saying Fight. Stonewalling is your Critter Brain saying There''s nothing left to fight with. One is gas. One is brake. Both are protection. Both are your system doing exactly what it learned to do when the conversation stopped feeling safe."},{"type":"heading","content":"The Pattern in the Room"},{"type":"text","content":"I''ve worked with many couples caught in this cycle. One partner raises a concern — maybe with some heat, maybe not. The other partner goes quiet. Not just pausing. Quiet in the way that has no return ticket."},{"type":"text","content":"The partner who raised the concern feels unheard. So they escalate — louder, sharper, more desperate — trying to break through the silence. And the more they push, the further the other retreats. The further they retreat, the more desperate the pushing becomes. Two people in pain, each one making the other''s pain worse, neither one able to see the exit."},{"type":"text","content":"She says: \"Can you at least respond to me?\""},{"type":"text","content":"He says, after a long silence: \"I don''t want to fight.\""},{"type":"text","content":"And then he gets up and walks to the garage. No explanation. No timeline. No promise to come back."},{"type":"text","content":"He is not yelling. He is not name-calling. But he has completely left. And she is sitting alone in the kitchen, in the middle of a conversation that just evaporated, feeling like the most invisible person in the world."},{"type":"text","content":"Over time, this pattern erodes something fundamental. Not just trust. The belief that reaching for your partner will be met with anything at all."},{"type":"heading","content":"What Changed"},{"type":"text","content":"After they learned about what was happening in their bodies during these moments — after they understood that his silence was not cruelty but a nervous system that had maxed out — something shifted."},{"type":"text","content":"One evening, the same tension started."},{"type":"text","content":"She said: \"It feels like I''m doing everything while you just sit there.\""},{"type":"text","content":"He felt the shutdown coming. The fog, the heaviness, the urge to disappear. But this time, instead of walking away, he said: \"I''m starting to shut down. I need ten minutes to cool off. I''ll come back and talk.\""},{"type":"text","content":"She didn''t love it. But she gave him the ten minutes."},{"type":"text","content":"He stepped outside. He breathed. He let the wave pass. And then he came back."},{"type":"text","content":"\"I hear you,\" he said. \"You''re feeling alone with the housework. I can take the trash out and do dishes twice a week. Does that help?\""},{"type":"text","content":"She didn''t get a wall. She got a partner who came back. And over time, in repeated moments like this one, trust slowly rebuilt."},{"type":"text","content":"A wall turned into a door with a doorknob."},{"type":"heading","content":"The Distinction That Changes Everything"},{"type":"text","content":"I want to be very clear about something, because this is one of the most important things in this entire module."},{"type":"bold_text","content":"Stonewalling is not the same as pausing."},{"type":"text","content":"Stonewalling is emotional withdrawal without communication. No words. No timeline. No indication that you''re coming back. It says to your partner''s nervous system: You are not worth responding to."},{"type":"text","content":"Pausing is the opposite. Pausing is naming the overwhelm. Saying out loud: I''m flooding. I need a few minutes. I will come back. Pausing says to your partner''s nervous system: I care about this too much to keep going when I can''t be the partner you deserve."},{"type":"text","content":"In Module 1, you learned a tool for exactly this moment: the Pause Number. That single number you and your partner agreed on — usually between 5 and 7 on a scale of 1 to 10 — that either of you can say when your system has crossed the line. One word. No explanation needed. Because in that moment of flooding, your CEO Brain doesn''t have the bandwidth for a full sentence. But one word can still get through."},{"type":"text","content":"\"Six.\""},{"type":"text","content":"That''s not stonewalling. That''s courage. That''s using the tool designed for the exact moment when your Critter Brain wants to build a wall."},{"type":"text","content":"The difference between stonewalling and pausing is three things:"},{"type":"list","items":["You name it. You say something — your Pause Number, \"I need ten minutes,\" a hand signal you''ve agreed on. Silence is the wall. Naming is the doorknob.","You set a time. \"Ten minutes.\" \"Twenty minutes.\" \"After the kids go to bed.\" The timeline is the promise.","You keep the promise. You come back. Every time you honor the return, you''re teaching your partner''s nervous system: This person leaves, and they come back. I am safe."],"ordered":true},{"type":"reflection","content":"Have you ever gone silent — not because you didn''t care, but because your body couldn''t find words? Think about the last time you shut down in a conversation. Was that a choice, or was it your system hitting the emergency brake? And for the partner who gets stonewalled: can you see, even a little, that the silence might not be about you?"}]}'::jsonb),
    (mod2_id, parent_id, 'The Antidote: Accept, Pause, Return', 204, '{"estimated_minutes":9,"blocks":[{"type":"text","content":"Now that you''ve seen how these two Devils work — the shield and the wall, the gas and the brake — let''s talk about what to do instead."},{"type":"text","content":"The antidotes for Defensiveness and Stonewalling are different in their mechanics but identical in their foundation. They both require the same terrifying thing: choosing connection over self-protection in the exact moment when your Critter Brain is begging you to do the opposite."},{"type":"heading","content":"The Antidote to Defensiveness: Accept Responsibility"},{"type":"text","content":"When your partner brings you a concern — even one that feels unfair, even one that''s wrapped in frustration or a tone you don''t love — your Critter Brain will want to defend. That''s Yellow Hyper doing its job. Your system is revving up, assembling a counter-argument, pulling evidence from the last six months to prove that you''re not the one at fault here."},{"type":"text","content":"Let it rev. And then, before the counter-argument leaves your mouth, ask yourself one question:"},{"type":"text","content":"What''s the ten percent that''s mine?"},{"type":"text","content":"Not a hundred percent. Not a full confession. Not agreeing that you''re the villain. Just the piece that''s honestly yours. The thing you can look at and say: Yeah, I could have done that differently."},{"type":"text","content":"Accepting responsibility sounds like:"},{"type":"list","items":["\"You''re right — I did drop the ball on that. I''m sorry.\"","\"I hear you. I wasn''t paying attention the way I should have been.\"","\"I can see how that landed for you, even though that wasn''t my intention.\""],"ordered":false},{"type":"text","content":"Notice what these sentences do: they honor your partner''s experience without requiring you to surrender your own. They say Your reality matters to me more than my need to be right in this moment."},{"type":"text","content":"Jeff''s daughter story from earlier in this lesson is the model. He didn''t agree that everything was his fault. He didn''t pretend the morning hadn''t been complicated. He just owned the part that was his. And that was enough to turn a defensive moment into a moment of trust."},{"type":"text","content":"This is not easy. I want to name that plainly. Accepting responsibility when your system is telling you to defend feels like standing in the middle of a fire and putting down your shield. Your Critter Brain will scream that you''re unprotected. But here''s what it doesn''t know: the shield was never protecting you. It was protecting the pattern."},{"type":"heading","content":"The Antidote to Stonewalling: Pause, Name, Return"},{"type":"text","content":"For stonewalling, the antidote isn''t \"just stay in the conversation.\" That would be asking your nervous system to do something it physically cannot do when it''s in Yellow Hypo or Blue. You can''t think your way out of a shutdown. Your CEO Brain has gone offline. Telling yourself to \"be present\" when your system has pulled the brake is like telling yourself to run a sprint with no oxygen."},{"type":"text","content":"The antidote is structured. Three steps."},{"type":"text","content":"1. Name it. Use your Pause Number. Or say: \"I''m flooding. I need a break.\" Or use whatever signal you and your partner agreed on in Module 1. The naming is the door. Without it, you''re just a wall."},{"type":"text","content":"2. Set a return time. \"I''ll be back in fifteen minutes.\" \"Let''s come back to this after the kids are in bed.\" The specific time matters. It gives your partner something to hold onto — a promise they can count on — instead of the open-ended silence that feels like abandonment."},{"type":"text","content":"3. Keep the promise. Come back. Even if you don''t feel perfectly regulated. Even if you''d rather not. Come back. Every kept return builds a neural pathway in your partner''s system that says: When they leave, they come back. That pathway is trust. And trust, once it''s been rebuilt through enough kept promises, is what transforms a wall into a door with a doorknob."},{"type":"fillable_form","form_id":"your-return-commitment","title":"Your Return Commitment","fields":[{"id":"field_1","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_2","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_3","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_4","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_5","label":"","type":"textarea","rows":3,"placeholder":""}],"intro":"Fill this out — not during a fight, but right now, when your CEO Brain is fully online. My Pause signal (Pause Number, phrase, or hand signal):"},{"type":"divider"},{"type":"heading","content":"The Spectrum"},{"type":"text","content":"Before we move to practice, I want you to hold one image."},{"type":"text","content":"Defensiveness and stonewalling sit at opposite ends of the same spectrum. One is your system pressing the gas — Yellow Hyper, energy rising, shield up. The other is your system pulling the brake — Yellow Hypo sliding toward Blue, energy draining, wall going up."},{"type":"text","content":"But they are not enemies of each other. They are the same Critter Brain, protecting the same tender heart, using different strategies. And they often show up in the same relationship — one partner defending while the other shuts down — which is why these conversations can feel so impossible. One system is accelerating. The other is decelerating. And neither one can reach the other."},{"type":"text","content":"The antidotes meet in the middle. Accepting responsibility slows the defensive partner down. Naming the pause and returning brings the stonewalling partner back. Both of them, done well, lead to the same place: two people in their Green Zone, ready to actually hear each other."},{"type":"text","content":"That''s where healing lives. Not in the fight. Not in the silence. In the return."}]}'::jsonb),
    (mod2_id, parent_id, 'Practice: The Return Promise', 205, '{"estimated_minutes":7,"blocks":[{"type":"heading","content":"When to Do This Practice"},{"type":"text","content":"Not during a fight. Not when either of you is activated. This practice is designed for a calm, connected moment — both of you in or near your Green Zone, both CEO Brains online."},{"type":"text","content":"If either of you is above your Pause Number right now, come back to this later. There is no deadline on this practice. Only safety."},{"type":"heading","content":"The Practice"},{"type":"text","content":"Sit together. Have something warm in your hands if you''d like. This should take about ten to fifteen minutes."},{"type":"bold_text","content":"Step 1: Share your default direction."},{"type":"text","content":"Each of you, answer this question:"},{"type":"text","content":"When a hard conversation gets too hard, which direction does my body go — into the fight (defensiveness), or into the freeze (stonewalling)?"},{"type":"text","content":"You may already know this from the Zones assessment in Module 1. Share it with your partner. Not as a confession — as information. \"When things get intense, my system tends to...\""},{"type":"bold_text","content":"Step 2: Agree on your pause signal."},{"type":"text","content":"If you built a SPARK Pact in Module 1, you already have a Pause Number and a Pause Cue. Review them now. If you haven''t set one yet, choose one together:"},{"type":"list","items":["A number on a scale of 1 to 10","A word or phrase (\"I need a pause\")","A hand signal"],"ordered":false},{"type":"text","content":"The only requirement: when either of you uses it, the conversation stops. No questions. No guilt. No \"but I wasn''t done.\""},{"type":"bold_text","content":"Step 3: Set your return time."},{"type":"text","content":"This is the piece that turns a pause into a promise instead of an escape."},{"type":"text","content":"Each of you, fill in:"},{"type":"text","content":"When I need to step away, I typically need ______ minutes to regulate.* *(Most people find 10-30 minutes is enough. More than an hour starts to feel like abandonment to the waiting partner.)"},{"type":"bold_text","content":"Step 4: Agree on the return sentence."},{"type":"text","content":"What will you say when you come back? Choose something that signals: I''m here. I''m ready. I didn''t leave you."},{"type":"text","content":"Examples:"},{"type":"list","items":["\"I''m back. I want to finish what we started.\"","\"Okay, I''m here. Tell me what you need me to hear.\"","\"I''m sorry I needed to step away. I''m ready now.\""],"ordered":false},{"type":"text","content":"Write yours down."},{"type":"bold_text","content":"Step 5: Name the thing you need from each other."},{"type":"text","content":"To the partner who tends toward defensiveness: What would help you put the shield down? What does your partner do that makes it easier to own your part?"},{"type":"text","content":"To the partner who tends toward stonewalling: What would help you come back sooner? What does your partner do that makes the return feel safe?"},{"type":"text","content":"Share these with each other. Listen without defending."},{"type":"fillable_form","form_id":"your-return-promise","title":"Your Return Promise","fields":[{"id":"field_1","label":"Our pause signal:","type":"textarea","rows":2,"placeholder":""},{"id":"field_2","label":"My return time:","type":"textarea","rows":2,"placeholder":""},{"id":"field_3","label":"My partner''s return time:","type":"textarea","rows":2,"placeholder":""},{"id":"field_4","label":"My return sentence:","type":"textarea","rows":2,"placeholder":""},{"id":"field_5","label":"My partner''s return sentence:","type":"textarea","rows":2,"placeholder":""},{"id":"field_6","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_7","label":"","type":"textarea","rows":3,"placeholder":""}],"intro":"Fill this out together. Keep it next to your SPARK Pact — on the fridge, in your phone, wherever you''ll see it."},{"type":"fillable_form","form_id":"your-implementation-intention","title":"Your Implementation Intention","fields":[{"id":"field_1","label":"This week, I will:","type":"textarea","rows":2,"placeholder":""}],"intro":"Before you close this lesson, write one thing down. Not five. One."},{"type":"divider"},{"type":"fillable_form","form_id":"a-gratitude-and-a-takeaway","title":"A Gratitude and a Takeaway","fields":[{"id":"field_1","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_2","label":"","type":"textarea","rows":3,"placeholder":""}],"intro":"Before you move on, pause here. One thing I''m grateful for after this lesson:"},{"type":"divider"},{"type":"heading","content":"A Note Before You Go"},{"type":"text","content":"If this lesson brought up something heavier than you expected — if looking at defensiveness or stonewalling landed somewhere deeper than recognition — I want you to know that this makes sense. These patterns often trace back to much earlier experiences of not being heard, not being safe, not being able to protect yourself. If what you''re carrying feels too large for this lesson to hold, please reach out to a therapist or counselor. This work matters, and so do you."},{"type":"divider"},{"type":"text","content":"Defensiveness builds a shield. Stonewalling builds a wall. But a wall can become a door, and a door can have a doorknob — if you''re willing to name what''s happening, step away with a promise, and come back."},{"type":"text","content":"The return is the whole thing."},{"type":"divider"},{"type":"text","content":"I''ll see you in the next lesson."},{"type":"text","content":"— Trisha"}]}'::jsonb);

  -- ─── Lesson 2.3: The Great Escape ───
  INSERT INTO lessons (module_id, title, sort_order, content_json)
  VALUES (
    mod2_id,
    'The Great Escape',
    3,
    '{"estimated_minutes":37,"blocks":[{"type":"heading","content":"The Great Escape"},{"type":"text","content":"Avoidance and Unhealthy Coping — the escape patterns."}]}'::jsonb
  ) RETURNING id INTO parent_id;

  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, content_json) VALUES
    (mod2_id, parent_id, 'The Things We Don''t Say', 301, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"The car was quiet on the way home from the party."},{"type":"text","content":"Not peaceful-quiet. The other kind. The kind where both of you are looking out the window, and you both know exactly what just happened back there, and nobody says a word because it feels easier to let the night end than to open the thing."},{"type":"text","content":"She had made a comment at the table — the kind that stung a little. He had gone flat. She noticed him go flat and said nothing. He noticed her notice and still didn''t say anything. And then they were in the car, and the moment passed, and they turned into the driveway and the garage door came down."},{"type":"text","content":"They got ready for bed. They were cordial. They said goodnight."},{"type":"text","content":"And both of them lay there in the dark, carrying the weight of the thing that hadn''t been said."},{"type":"divider"},{"type":"text","content":"I have sat with so many couples who live here. Not in crisis, not in open war — but in this particular kind of quiet. The quiet of the thing that keeps almost getting said. The quiet of the text you almost sent. The quiet of the walk-by in the kitchen where one of you wanted to reach for the other and both of you kept walking."},{"type":"text","content":"This is what Avoidance and Unhealthy Coping look like from the outside. Not dramatic. Not obvious. Just this low, steady hum of unspoken things building behind the walls of an otherwise functional life."},{"type":"text","content":"Devil 5 and Devil 6 don''t show up during the argument. They show up in the space between arguments. In what you do when the pressure rises and you don''t know what to do with it. In the way you manage yourself — or don''t — when the weight gets too heavy."},{"type":"text","content":"These are the escape patterns. And they are some of the most quietly destructive forces in a long-term relationship."},{"type":"text","content":"We are going to look at both of them honestly. Because the longer they stay invisible, the more they grow."}]}'::jsonb),
    (mod2_id, parent_id, 'Avoidance: The Problem That Grows in the Dark', 302, '{"estimated_minutes":10,"blocks":[{"type":"text","content":"Let me tell you about the dishwasher."},{"type":"text","content":"Jeff does not like unloading the dishwasher. He will do just about anything else in the kitchen — load it, sweep around it, take out the trash nearby — but unloading it? He would rather not."},{"type":"text","content":"One day I asked him to unload it before dinner. He said he would. He had things to do first, but he''d get to it. And then he went about his day, and the dishwasher stayed loaded, and the evening came, and the next morning I found it exactly as I''d left it."},{"type":"text","content":"When I asked him about it, he didn''t have a good reason. Not a real one. He knew he''d said he''d do it. He just... hadn''t. And somewhere underneath the \"I had things to do,\" was something truer: I knew I wasn''t going to do it, even when I said I would."},{"type":"text","content":"I want to take a beat here, because Jeff tells this story on himself. It''s small. It''s a little funny. And it''s also a perfect picture of what Avoidance actually is — because what Jeff did that day was not procrastination."},{"type":"heading","content":"Avoidance vs. Procrastination — The Distinction That Matters"},{"type":"text","content":"Procrastination has honest intent. \"I''ll do it in a minute\" — and sometimes the thing does get done. The intention is real even when the follow-through falls short."},{"type":"text","content":"Avoidance has no such intent. You say the words, but the decision is already made underneath them. You will not do this thing, engage this conversation, address this problem. Not because you''re lazy or dishonest, but because something about it feels too uncomfortable, too loaded, too risky to touch."},{"type":"text","content":"This is also different from stonewalling. Stonewalling is checking out in the moment — overwhelmed, system flooded, no more words available. It''s reactive. It''s happening now."},{"type":"text","content":"Avoidance is a longer choice. A weeks-long choice. Sometimes a years-long choice. It is the decision to build your daily life around not touching a thing."},{"type":"text","content":"And here is what avoidance does that surprises almost everyone: it doesn''t make the problem disappear. It gives it time to grow roots."},{"type":"heading","content":"What Grows in the Dark"},{"type":"text","content":"There was something one couple I worked with had never talked about."},{"type":"text","content":"It had been there for years — this heavy, quiet presence sitting between them at the dinner table, riding in the backseat on long drives, filling the silence after the lights went out. A family wound. Someone they''d lost. Not to death, but to distance — and neither of them knew how to bring it up without breaking something."},{"type":"text","content":"So they didn''t."},{"type":"text","content":"He couldn''t talk about it because it hurt too much. She couldn''t bring it up because she was afraid of what it would do to him. And year after year, the silence around this one topic bled into everything else. They argued about dishes and schedules and screen time — small, safe things — because the real conversation felt impossible."},{"type":"text","content":"\"It just brings up feelings and emotions that have never been talked about,\" she told me one morning. \"Ever.\""},{"type":"text","content":"That word — ever — landed in the room like a stone."},{"type":"text","content":"This is the accumulation problem. Unspoken things don''t dissolve. They go underground, where they come up sideways — in irritability that seems out of proportion, in distance that nobody planned, in fights about nothing that are really about everything."},{"type":"heading","content":"The Zone Connection"},{"type":"text","content":"When Avoidance has been running long enough, you can feel it in your body. Not the hot charge of the Red Zone or the edge of Yellow Hyper. This is the other end — the quieter, heavier end."},{"type":"text","content":"Your system has moved into the Yellow Hypo Zone. Maybe deeper, into the Blue Zone. Your nervous system is whispering: I''ve had enough of this. I don''t have the capacity. And so it stops reaching. Stops raising the thing. Finds a way to be in the same room as the problem and not see it."},{"type":"text","content":"The Yellow Hypo whisper is \"I''m fine\" when you''re clearly not. It''s the blank nod while your partner is talking. The way a conversation you needed to have keeps getting quietly postponed."},{"type":"text","content":"The Blue is when you stop feeling the weight of it at all. When even the urge to address things has gone quiet. That numbness is not peace. It is your system having pressed the emergency brake all the way down."},{"type":"text","content":"Avoidance does not live in the argument. It lives in the aftermath, in the tired silence, in the thing you decided — once again — was not worth the trouble of saying."},{"type":"heading","content":"The Difference Between Healthy Space and Avoidance"},{"type":"text","content":"A note worth making: not every decision not to talk about something is avoidance. There is such a thing as healthy space — choosing not to push a hard conversation when one or both of you is flooded, when the timing is genuinely wrong, when you need to be in a calmer place before you can hear each other."},{"type":"text","content":"The difference is intention and return."},{"type":"text","content":"Healthy space says: not now, but soon. I''m going to come back to this when we''re both ready."},{"type":"text","content":"Avoidance says: not now — and quietly hopes it never has to be now."},{"type":"text","content":"The question worth asking yourself: is there a conversation you keep almost having? Something that keeps rising and getting pushed back down? That''s not healthy space. That''s the problem growing in the dark."},{"type":"divider"},{"type":"reflection","content":"Reflection Prompt:"},{"type":"text","content":"Name one conversation you''ve been putting off."},{"type":"text","content":"You don''t have to plan to have it this week. You don''t have to know what you''d say. Just name it — even just to yourself, right here."},{"type":"text","content":"The conversation I''ve been avoiding is:"},{"type":"text","content":"_______________________________________________________________"},{"type":"text","content":"Acknowledgment is always the first move. You''ve just made it."}]}'::jsonb),
    (mod2_id, parent_id, 'Unhealthy Coping: What You Reach For', 303, '{"estimated_minutes":10,"blocks":[{"type":"text","content":"Here''s something true about every human being: when the pressure inside gets high enough and there''s no clear way through, your system starts searching."},{"type":"text","content":"It doesn''t ask permission. It doesn''t consult your values or your best intentions for your marriage. It just goes looking — for something that will lower the volume. Something that will make the next hour bearable. Something that takes the edge off what''s building inside."},{"type":"text","content":"That''s not a flaw. That is a nervous system doing exactly what it was designed to do: find relief."},{"type":"text","content":"The question is what you''re finding."},{"type":"heading","content":"What We Reach For — Named Honestly"},{"type":"text","content":"Let''s name these plainly, because the whole point of looking at this is to see it clearly."},{"type":"text","content":"When the pressure rises — after the argument that didn''t resolve, during the slow accumulation of a week where nothing feels connected, in the evenings when you''re sitting in the same room and miles apart — people reach for things like:"},{"type":"list","items":["Food. Not because they''re hungry. Because eating something is immediate, available, and gives the nervous system a brief moment of comfort and relief.","Screens. Scrolling, streaming, disappearing into a phone or a show. The passive consumption that asks nothing of you and gives you a temporary reprieve from the thing you can''t stop thinking about.","Alcohol. A glass that becomes two. The specific appeal is the way it softens the edges — the ease of conversation, the quieting of the thing underneath.","Work. The coping that looks the most acceptable from the outside. If you''re busy, you''re productive. If you''re buried in tasks, you''re not required to feel what''s happening at home. Work has the additional feature of being socially praised, which makes it especially easy to miss.","Over-exercise. Not the kind that builds health, but the kind that punishes — or that becomes the primary outlet for feelings that have nowhere else to go."],"ordered":false},{"type":"text","content":"None of these things are categorically wrong. Food is good. Rest is necessary. Work has to happen. Exercise builds resilience. And occasionally disconnecting is human."},{"type":"text","content":"The question is not whether you do any of these things. It''s what role they''re playing in your life — and in your relationship."},{"type":"heading","content":"Engages vs. Numbs: The Real Distinction"},{"type":"text","content":"This is the framework that actually matters."},{"type":"text","content":"Some coping engages your system. It brings your body and mind into something that requires real attention — something that processes what you''re carrying instead of just covering it. Your nervous system moves through something. On the other side, you feel clearer, not just quieter."},{"type":"text","content":"Some coping numbs your system. It turns down the volume without resolving the frequency. You feel better temporarily. The thing is still there when the screen goes dark or the glass is empty or the workday ends. And sometimes you''re further from addressing it than when you started, because now you''re also carrying the vague unease of having avoided it again."},{"type":"text","content":"The distinction between engages and numbs is not about the activity itself. It''s about what the activity is doing for you — and whether you are present in it, or hiding inside it."},{"type":"text","content":"Here is how you can tell the difference from the inside:"},{"type":"text","content":"After you''re done, do you feel genuinely lighter — like something moved? Or do you feel temporarily distracted — like the volume got turned down, but the song is still playing?"},{"type":"heading","content":"Why This Becomes a Relationship Problem"},{"type":"text","content":"Unhealthy coping starts as a personal strategy. But it doesn''t stay personal."},{"type":"text","content":"When your primary way of managing pressure is to reach for something that takes you out of the room — emotionally, physically, or both — your partner registers that absence. They may not name it. They may not even consciously notice it. But their nervous system picks it up."},{"type":"text","content":"Every time you go to the screen instead of the conversation, you are sending a signal — not intentionally, not cruelly, but clearly. And over time, that signal teaches your partner something: that when things get hard, you go somewhere else."},{"type":"text","content":"What you reach for also has a way of creating its own weight. The drinking that was once occasional becomes expected. The work that was once a busy season becomes the permanent season. The coping strategy that was supposed to manage the marriage pressure starts generating its own pressure — and now there are two problems instead of one."},{"type":"text","content":"The Marriage Mastery response here is not willpower or sudden self-discipline. It''s the honest look. What are you actually reaching for? And is it building anything — or just buying time?"},{"type":"divider"},{"type":"bold_text","content":"Fillable Form:"},{"type":"text","content":"My go-to when I''m overwhelmed:"},{"type":"text","content":"_______________________________________________________________"},{"type":"text","content":"I would describe it as:"},{"type":"list","items":["Engages — it actually processes something, I feel genuinely clearer after","Numbs — it turns the volume down, but the thing is still there when it''s over","Depends — sometimes one, sometimes the other"],"ordered":false},{"type":"text","content":"One honest thing I notice about how I cope:"},{"type":"text","content":"_______________________________________________________________"}]}'::jsonb),
    (mod2_id, parent_id, 'Finding What Actually Works', 304, '{"estimated_minutes":9,"blocks":[{"type":"text","content":"A few years ago, after most of the kids were out of the house, Jeff learned to fly."},{"type":"text","content":"He is the first to admit that the process was not simple. Getting a private pilot''s license while running a full-time medical practice stretched what should have taken months into something closer to a year. And I''ll be honest: it was not my first choice of how he might spend his time."},{"type":"text","content":"But here is what I have watched happen in my husband when he flies."},{"type":"text","content":"Everything else fades. The weight of the practice, the weight of the patients he carries home with him, the weight of the accumulated hard things — it recedes. Not because flying is easy. Because flying is demanding. It requires everything. You cannot be thinking about anything else when you are responsible for an aircraft. Your attention is entirely required, and so your nervous system has no bandwidth left for the worry loop. The prefrontal cortex — Jeff''s CEO Brain — is fully engaged and running the show."},{"type":"text","content":"And when he sticks the landing — something he still gets genuinely excited about — there is this particular quality to the hours and days that follow. A lightness. An aliveness. Something that is the opposite of the flat exhaustion he carries home on his hardest days."},{"type":"text","content":"That is not numbing. That is engagement."},{"type":"audio","title":"2:00, Jeff — his coping journey, most personal audio in Module 2"},{"type":"heading","content":"The Principle, Separated from the Plane"},{"type":"text","content":"I want to be clear: flying is Jeff''s thing. The specific activity is his. I''m not suggesting you need to learn to fly an airplane."},{"type":"text","content":"The principle is what matters: the activity that actually works is the one that asks everything of you."},{"type":"text","content":"Not the kind of everything that depletes. The kind of everything that organizes. When your whole system — body, attention, skill — is recruited into something that genuinely demands it, you don''t have cognitive or emotional surplus left for the spiral. The worry doesn''t have room to run. And when you come out the other side, you haven''t just paused the feeling — you''ve actually moved something."},{"type":"text","content":"This is the difference between engagement and numbing at its clearest."},{"type":"text","content":"What lights you up that way? Not what relaxes you into passivity — what recruits you? What demands your full attention in a way that feels alive rather than depleting?"},{"type":"text","content":"For some people it''s movement — not grinding out cardio to escape, but the kind of physical activity where you have to be present because your body is fully occupied. A competitive game. Rock climbing. A long trail run where the terrain requires your eyes and your feet."},{"type":"text","content":"For others it''s creative work — the kind where you''re genuinely making something, problem-solving in real time, fully inside the challenge."},{"type":"text","content":"For others still it''s connection — a real conversation with a friend who knows you. Not the kind where you vent and they sympathize and nothing moves. The kind where you leave feeling known and clearer."},{"type":"text","content":"The specifics are yours to find. The question is just: does this thing engage your whole brain, or does it only manage the noise?"},{"type":"heading","content":"Coming Back Ready"},{"type":"text","content":"There is a relational piece that often gets missed."},{"type":"text","content":"Healthy coping isn''t just good for you individually. It''s good for your relationship — but only if it actually sends you back into the relationship."},{"type":"text","content":"The person who goes running and comes home with space for their partner is using healthy coping. The person who goes running and uses it as a daily excuse to avoid the house is using running the way another person uses screens. The activity isn''t the thing. The intention — and the return — is the thing."},{"type":"text","content":"When you find what genuinely engages your system, it creates two things: a way to process what you''re carrying, and a capacity to show up for your partner that you didn''t have before. That is the full loop. The coping isn''t the end. It''s the preparation."},{"type":"text","content":"This is the SPARK Method''s final step in practice — Kindle. Coming back to the relationship with something in your hands. Not just having survived the week, but having tended to yourself well enough to be genuinely present."},{"type":"heading","content":"What Healthy Coping Sounds Like in a Relationship"},{"type":"text","content":"Healthy coping sounds like: \"I need an hour to go do this thing. I''ll be back, and I''ll actually be here when I come back.\""},{"type":"text","content":"It sounds like naming what you need before you reach for it, so your partner isn''t left guessing why you''ve disappeared."},{"type":"text","content":"It sounds like being honest about what isn''t working, even when honesty is harder than just continuing to reach for the same thing."},{"type":"text","content":"And sometimes it sounds like asking your partner to do it with you — because some of the most regulating things humans can do, they can do together. A walk. A meal made from scratch. Something that requires both of you to be present and asks nothing of the argument."},{"type":"divider"},{"type":"reflection","content":"Reflection Prompt:"},{"type":"text","content":"What makes your whole brain light up? Not what calms you into quiet — what recruits you?"},{"type":"text","content":"One thing that genuinely engages me — body, attention, and all:"},{"type":"text","content":"_______________________________________________________________"},{"type":"text","content":"After I do this, I feel:"},{"type":"text","content":"_______________________________________________________________"},{"type":"text","content":"My honest assessment: does this send me back into my relationship with more capacity, or does it pull me away from it?"},{"type":"text","content":"_______________________________________________________________"}]}'::jsonb),
    (mod2_id, parent_id, 'Practice: The Honest Inventory', 305, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"This is not a confession. It is a map."},{"type":"text","content":"The work you''re doing right now — looking honestly at what you avoid and what you reach for — is not about building a case against yourself. It''s about finally seeing the terrain you''ve been navigating. You can''t make better choices in the dark. This is how you turn the lights on."},{"type":"fillable_form","form_id":"the-avoidance-audit","title":"The Avoidance Audit","fields":[],"intro":"Read each question below and answer honestly. There are no wrong answers, and no one sees this but you."},{"type":"divider"},{"type":"bold_text","content":"Part 1: Naming the Avoided Things"},{"type":"text","content":"In my relationship right now, there is something I''ve been not saying. (Name it if you can, even one word or phrase.)"},{"type":"text","content":"_______________________________________________________________"},{"type":"text","content":"There is a conversation we''ve had pieces of but never finished. (What is it about?)"},{"type":"text","content":"_______________________________________________________________"},{"type":"text","content":"There is something I''ve been pretending is resolved when I actually don''t feel like it is. (What comes to mind?)"},{"type":"text","content":"_______________________________________________________________"},{"type":"text","content":"If I''m honest, I avoid this topic because:"},{"type":"list","items":["It feels too big to open without knowing how it will go","I''m afraid of how my partner will react","I''m afraid of how I will react","I''ve tried before and it didn''t go anywhere","I don''t have words for it yet","Other: _______________________________________________"],"ordered":false},{"type":"divider"},{"type":"bold_text","content":"Part 2: Naming the Coping Patterns"},{"type":"text","content":"When the pressure in my relationship builds and I don''t know what to do with it, I usually:"},{"type":"text","content":"_______________________________________________________________"},{"type":"text","content":"I would describe what I reach for as:"},{"type":"list","items":["Primarily engages (I feel genuinely different on the other side)","Primarily numbs (I feel better temporarily, but nothing has moved)","A mix — depends on the day and how depleted I already am"],"ordered":false},{"type":"text","content":"One thing my coping might be costing me or my partner:"},{"type":"text","content":"_______________________________________________________________"},{"type":"divider"},{"type":"bold_text","content":"Part 3: The One Thing"},{"type":"text","content":"The one avoidance I most want to address — not today necessarily, but eventually — is:"},{"type":"text","content":"_______________________________________________________________"},{"type":"text","content":"The one coping shift I most want to make is:"},{"type":"text","content":"_______________________________________________________________"},{"type":"divider"},{"type":"audio","title":"1:00, Trisha — gentle encouragement"},{"type":"divider"},{"type":"fillable_form","form_id":"the-couples-practice-name-the-thing-you-haven-t-named","title":"The Couples Practice: Name the Thing You Haven''t Named","fields":[],"intro":"This is a practice to do together, when you both feel ready and neither of you is flooded. Sit somewhere quiet. Not the kitchen with dishes in the sink, not in bed where it''s easy to turn away. Somewhere that feels neutral and low-stakes — the living room, a walk outside. Each of you completes this sentence, and the other person only listens: \"Something I''ve been carrying that I haven''t said out loud is _______________.\" No response yet. No problem-solving, no defending, no follow-up questions. Just receive it. Then switch. When both of you have said it: \"Thank you for trusting me with that.\" That''s it — the full practice. You are not solving it today. You are not required to have a plan. You are simply removing something from the dark and placing it in the light between you — where it can finally be seen by both of you. This is not the hard conversation. This is the first sentence of it. Sometimes the first sentence is enough to change the weight."},{"type":"divider"},{"type":"fillable_form","form_id":"implementation-intention","title":"Implementation Intention","fields":[{"id":"field_1","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_2","label":"","type":"textarea","rows":3,"placeholder":""}],"intro":"Complete this before you close this lesson. One thing I will do differently this week when I feel the urge to avoid:"},{"type":"divider"},{"type":"reflection","content":"Before you close this lesson, take one minute. What is one thing you''re grateful to have named — even if it was uncomfortable to look at? And what is one thing you''re taking with you from this lesson? _______________________________________________________________ _______________________________________________________________"}]}'::jsonb);

  -- ─── Lesson 2.4: The Path Back ───
  INSERT INTO lessons (module_id, title, sort_order, content_json)
  VALUES (
    mod2_id,
    'The Path Back',
    4,
    '{"estimated_minutes":35,"blocks":[{"type":"heading","content":"The Path Back"},{"type":"text","content":"Integration, the Devil Audit, and building your Module 2 practice."}]}'::jsonb
  ) RETURNING id INTO parent_id;

  INSERT INTO lessons (module_id, parent_lesson_id, title, sort_order, content_json) VALUES
    (mod2_id, parent_id, 'Where Are You Now?', 401, '{"estimated_minutes":6,"blocks":[{"type":"text","content":"They''d been in the program about eight months when it happened."},{"type":"text","content":"Friends of theirs were going through a rough patch — really rough. The kind where you sit at their kitchen table for three hours just trying to keep things from catching fire. And somewhere in the middle of it, watching this other couple go back and forth — the accusations, the defensiveness, the shutting down, the desperate bid to be heard — he leaned back in his chair and thought: That was us."},{"type":"text","content":"\"I kept recognizing it,\" he told me. \"Not just one thing. The whole pattern. The way she''d push and he''d go quiet. The way he''d try to say something and she''d cut him off. The way they both wanted the exact same thing but couldn''t stop tearing each other apart trying to get it. I''m sitting there thinking, I''m literally looking at us seven months ago.\""},{"type":"text","content":"He wasn''t gloating. He wasn''t judging his friends. He was startled — startled by how clearly he could see the system now, when seven months earlier he''d been trapped inside it without any idea it was even running."},{"type":"text","content":"That''s the shift I want to name for you right now. Because you are standing in it."},{"type":"divider"},{"type":"text","content":"Think about where you were when you started this program."},{"type":"text","content":"Module 1 gave you a language. You met the Seven Devils — Criticism, Contempt, Defensiveness, Stonewalling, Avoidance, Unhealthy Coping, and the Loss of Intimacy — and for probably the first time, you had names for the things that had been running your relationship. You learned why your body hijacks conversations your mind was trying to have. You practiced the 30-Second Reset. You built your first seven days. You started to see."},{"type":"text","content":"Module 2 took you deeper. You sat with the attack patterns — the way Criticism and Contempt corrode trust one sentence at a time. You faced the protect patterns — the way Defensiveness walls off connection, and the way Stonewalling makes your partner feel like they''re talking to an empty room. You met the escape patterns — the way Avoidance lets problems grow in the dark, and the way Unhealthy Coping turns the volume down without resolving anything underneath."},{"type":"text","content":"That is serious work."},{"type":"text","content":"You''ve gone from \"something is wrong in my relationship\" to \"I can name the specific patterns that are running and I understand why my body fuels them.\" That is a different kind of knowing than you had two modules ago. It''s not theoretical anymore. You''ve started to feel it in real time — the moment your Critter Brain takes the wheel, the Zone you land in, the Devil that shows up."},{"type":"text","content":"So now I want to ask you a question, and I want you to sit with it before we move on."},{"type":"text","content":"Where are you now?"},{"type":"text","content":"Not where you think you should be. Not where your partner is. Where are you — honestly, specifically, with whatever tools you''ve built so far?"},{"type":"text","content":"This lesson is about answering that question. We''re going to build a map of your specific patterns, practice sharing that map with your partner, and set up the next seven days so that what you''ve learned actually moves from your head into your hands."},{"type":"text","content":"But first, the map."}]}'::jsonb),
    (mod2_id, parent_id, 'The Devil Audit', 402, '{"estimated_minutes":10,"blocks":[{"type":"text","content":"I use the word \"audit\" on purpose. Not because this is cold or clinical — it isn''t. But because the word means something specific: to look carefully at what''s actually there, instead of what you wish was there or what you''re afraid is there."},{"type":"text","content":"This is not a test. It is not a grade. It is a map — and maps are only useful when they are honest."},{"type":"text","content":"You did a brief Devil Audit at the end of Module 1 — a first pass, naming which Devils you recognized. This one goes further. You''ve spent the last three lessons sitting with each pattern in detail. You''ve seen how Criticism and Contempt work as attack patterns. You''ve watched how Defensiveness and Stonewalling function as protection. You''ve faced how Avoidance and Unhealthy Coping operate as escape routes. Now it''s time to take that understanding and aim it squarely at your own relationship."},{"type":"text","content":"There are three sections. Take your time with each one. Be honest. Nobody sees this but you — unless you choose to share it in the practice that follows."},{"type":"divider"},{"type":"heading","content":"Section 1: Your Devils"},{"type":"text","content":"For each of the six Devils we''ve covered in Module 2, rate how often this pattern shows up in your relationship. Not how often it \"should\" or \"shouldn''t\" — how often it actually does."},{"type":"divider"},{"type":"text","content":"Devil 1 — Criticism Turning a specific behavior into a verdict on who your partner is as a person. The \"you always\" and \"you never.\""},{"type":"text","content":"How often does this pattern show up in your relationship?"},{"type":"list","items":["Rarely — it''s not a significant part of our dynamic","Sometimes — it surfaces when I''m stressed or activated","Often — it''s a regular feature of how we argue","Almost Always — this is one of our primary patterns"],"ordered":false},{"type":"divider"},{"type":"text","content":"Devil 2 — Contempt The eye roll. The sigh that says \"I can''t believe I have to deal with this.\" The tone that communicates superiority or disdain. The running mental highlight reel of your partner''s failures."},{"type":"text","content":"How often does this pattern show up in your relationship?"},{"type":"list","items":["Rarely — I don''t recognize this in us","Sometimes — it flares in the worst moments","Often — there''s an undercurrent of it in how I (or my partner) relate","Almost Always — this has become a persistent part of our dynamic"],"ordered":false},{"type":"divider"},{"type":"text","content":"Devil 3 — Defensiveness Explaining, justifying, counter-attacking, or bringing up what your partner did instead of sitting with what they''re telling you. Redirecting the conversation away from their hurt and back onto your need to be right."},{"type":"text","content":"How often does this pattern show up in your relationship?"},{"type":"list","items":["Rarely — I can usually receive feedback without deflecting","Sometimes — it depends on how the feedback is delivered","Often — my first instinct is usually to defend","Almost Always — nearly every concern brought to me turns into a debate"],"ordered":false},{"type":"divider"},{"type":"text","content":"Devil 4 — Stonewalling Going quiet. Leaving the room — physically or emotionally. Monosyllable answers. The wall that comes down when things get too intense."},{"type":"text","content":"How often does this pattern show up in your relationship?"},{"type":"list","items":["Rarely — I tend to stay present even when it''s hard","Sometimes — I shut down when I''m overwhelmed, but I come back","Often — my system checks out regularly during conflict","Almost Always — going silent is my primary response to difficult conversations"],"ordered":false},{"type":"divider"},{"type":"text","content":"Devil 5 — Avoidance The conversations that keep not happening. The topics you''ve circled around for months or years. The conscious decision to not engage with what''s real because it feels too hard or too risky."},{"type":"text","content":"How often does this pattern show up in your relationship?"},{"type":"list","items":["Rarely — we tend to address things as they come up","Sometimes — there are one or two topics we keep sidestepping","Often — avoidance has become a habit in our relationship","Almost Always — we have built our daily life around the things we don''t say"],"ordered":false},{"type":"divider"},{"type":"text","content":"Devil 6 — Unhealthy Coping Reaching for something that turns the volume down without processing the stress: screens, alcohol, overwork, food, shopping, anything that creates enough noise to stop hearing the pressure underneath."},{"type":"text","content":"How often does this pattern show up in your relationship?"},{"type":"list","items":["Rarely — my coping strategies tend to be ones that process the stress","Sometimes — I notice myself reaching for numbing when things get hard","Often — unhealthy coping is a regular part of how I manage pressure","Almost Always — I have a default numbing behavior I reach for most days"],"ordered":false},{"type":"divider"},{"type":"heading","content":"Section 2: Your Zone Pattern"},{"type":"text","content":"You learned the five Zones of Resilience in Module 1 — Red, Yellow Hyper, Green, Yellow Hypo, and Blue. You''ve seen how each Devil maps to specific Zones: Criticism and Contempt live in the Red and Yellow Hyper Zones. Stonewalling and Unhealthy Coping pull you toward Yellow Hypo and Blue. Defensiveness can go either direction. Avoidance often lives in the space between — that quiet, chronic Yellow that never quite reaches Green."},{"type":"text","content":"Now think about your own pattern."},{"type":"bold_text","content":"When conflict starts in your relationship, which direction does your body tend to go?"},{"type":"list","items":["A: Hotter, faster, louder — my system revs up. My heart races, my voice gets sharper, my thoughts speed up. (Red / Yellow Hyper direction)","B: Slower, heavier, quieter — my system shuts down. I go foggy, I pull away, I feel like I can''t access my words. (Yellow Hypo / Blue direction)","C: Both, depending on the day — sometimes I run hot, sometimes I go cold, and I can''t always predict which one it will be"],"ordered":false},{"type":"bold_text","content":"When your system moves out of the Green Zone, how long does it usually take you to notice?"},{"type":"list","items":["Quickly — I can usually feel it within a few minutes","Eventually — I notice partway through, once I''m already in the pattern","After — I usually realize what happened once the conversation is over","Rarely — I don''t often catch it in real time"],"ordered":false},{"type":"text","content":"This second question matters. The speed at which you notice is one of the best indicators of where you are in this work. If you''re catching yourself faster than you were two modules ago — even slightly — that''s real progress. If you''re still realizing after the fact, that''s okay too. That still means you''re looking."},{"type":"divider"},{"type":"fillable_form","form_id":"section-3-your-partner-guess-then-verify","title":"Section 3: Your Partner (Guess, Then Verify)","fields":[],"intro":"This section is different. You''re not assessing yourself here. You''re making your best guess about your partner''s patterns. Which 2-3 Devils do you think show up most for your partner? Write or select up to three: 1. `_______________________________________________` 2. `_______________________________________________` 3. `_______________________________________________` When conflict starts, which direction does your partner''s body tend to go? - [ ] Hotter, faster, louder (Red / Yellow Hyper direction) - [ ] Slower, heavier, quieter (Yellow Hypo / Blue direction) - [ ] Both, depending on the day"},{"type":"divider"},{"type":"text","content":"Hold these answers. Do not share them yet."},{"type":"text","content":"In the next sub-lesson, you''re going to sit across from your partner and compare notes. What you guessed about them, what they guessed about you, where you saw each other clearly, and where you were surprised."},{"type":"text","content":"That conversation — done with care and safety — is one of the most powerful things two people can do for their relationship. You''re not just talking about patterns anymore. You''re seeing each other inside the patterns. And that changes everything."},{"type":"divider"},{"type":"reflection","content":"Look at your completed audit for a moment. Not to judge it. Not to fix it. Just to see it. What stands out? Is there a Devil you expected to be more present than it was? One you didn''t expect to find?"}]}'::jsonb),
    (mod2_id, parent_id, 'The Devil Dialogue', 403, '{"estimated_minutes":9,"blocks":[{"type":"audio","title":"1:30, Trisha — safety framing before the Devil Dialogue: \"This is not about blame. This is about two people choosing to see the pattern instead of each other as the problem.\""},{"type":"text","content":"What you''re about to do is one of the bravest things this program will ask of you. Not the hardest. Not the most complex. The bravest."},{"type":"text","content":"You''re going to sit down with your partner and share what you found in the Devil Audit. Not as an accusation. Not as a confession. As two people looking at a map of what''s been running between you, together, for the first time."},{"type":"text","content":"Before we begin, I want to say something plainly: this conversation has the potential to bring you closer than almost anything else in this course. It also has the potential to go sideways fast if you skip the safety framing. So don''t skip it. Read every word of this section before you sit down together."},{"type":"divider"},{"type":"heading","content":"Safety Rules for the Devil Dialogue"},{"type":"text","content":"These are not suggestions. These are the conditions that make this conversation safe enough to actually work."},{"type":"bold_text","content":"1. Both partners must be in their Green Zone before starting."},{"type":"text","content":"If either of you is tired, activated, stressed, or still carrying heat from an earlier conversation — wait. This practice does not work from Yellow or Red. Check in with each other before you begin: \"Are you in Green right now? Am I?\" If the answer is no, choose a different time. This conversation will be here when you''re ready."},{"type":"bold_text","content":"2. Use \"I noticed\" language, not \"You always\" language."},{"type":"text","content":"Everything you share from your audit should start with yourself. \"I noticed that Criticism is one of my stronger patterns.\" \"I noticed my body tends to go hot when conflict starts.\" When you share what you guessed about your partner''s patterns, frame it as observation, not verdict: \"I think I see Defensiveness showing up for you sometimes — does that feel accurate?\""},{"type":"bold_text","content":"3. If either partner''s system starts to activate, use the Pause Number."},{"type":"text","content":"You built this tool in Module 1. This is exactly the moment it was designed for. If you feel your chest tighten, your voice get sharp, your thoughts start racing, or your partner''s face change in a way that tells you they''re leaving the Green Zone — say your number. Take the break. Come back. The conversation can handle a pause. It cannot handle a fight."},{"type":"bold_text","content":"4. This is a conversation about PATTERNS, not a list of complaints about each other."},{"type":"text","content":"The moment this becomes \"here''s everything you do wrong,\" it stops working. The Devils are not your partner. They are not you. They are the patterns that run between you — and the whole point of this conversation is to stand side by side and look at the patterns together, instead of across from each other looking for blame."},{"type":"divider"},{"type":"heading","content":"The Devil Dialogue: Four Steps"},{"type":"bold_text","content":"Step 1: Share your top Devils."},{"type":"text","content":"Each partner shares the 2-3 Devils from their own audit that showed up as \"Often\" or \"Almost Always.\" Start with yourself. Name them plainly."},{"type":"text","content":"\"The Devils I see most in myself are Criticism and Avoidance. When I''m stressed, I tend to go after the specific words you use instead of hearing what you''re trying to tell me. And there are conversations I''ve been putting off because I don''t know how to start them.\""},{"type":"text","content":"The other partner listens. That''s it. Just listens."},{"type":"bold_text","content":"Step 2: Validate what you heard."},{"type":"text","content":"After your partner shares, respond with one sentence that starts with: \"That makes sense to me because...\""},{"type":"text","content":"\"That makes sense to me because I''ve noticed you get sharp when you''re overwhelmed, and I know there are things we haven''t talked about.\""},{"type":"text","content":"You are not agreeing that they''re a bad partner. You are saying: I see the pattern you''re naming, and it lines up with what I''ve experienced too. That validation — \"I see what you see\" — is more powerful than most people expect."},{"type":"bold_text","content":"Step 3: Share what you guessed about your partner''s Devils."},{"type":"text","content":"Now share the answers from Section 3 of your audit — the patterns you think you see in your partner. Use the \"I noticed\" frame."},{"type":"text","content":"\"When I filled this out, I guessed that your top Devils might be Defensiveness and Stonewalling. When I bring something up, it sometimes feels like you''re explaining instead of hearing me, and when it gets really hard, you go quiet. Does that feel right to you?\""},{"type":"bold_text","content":"Step 4: Compare notes."},{"type":"text","content":"This is where it gets interesting."},{"type":"text","content":"Where did you see each other clearly? Where were you surprised? Did your partner name a Devil in themselves that you hadn''t noticed? Did they guess something about you that you hadn''t seen?"},{"type":"text","content":"Talk about it. Stay in Green. Stay curious. The goal is not to be right about each other''s patterns. The goal is to see the system you''re both living inside — and to start seeing it together."},{"type":"divider"},{"type":"fillable_form","form_id":"if-this-conversation-doesn-t-go-perfectly","title":"If This Conversation Doesn''t Go Perfectly","fields":[],"intro":"It probably won''t. And that''s fine. Maybe one of you gets activated and needs to pause. Maybe the conversation only gets through Steps 1 and 2 before someone''s Critter Brain takes the wheel. Maybe you sit down to start and realize tonight isn''t the night. All of that is okay. The Devil Dialogue is not a one-time event. It is a practice you can return to — next week, next month, after the next hard conversation. What matters is that you tried. What matters is that you sat across from someone you love and said, \"Here''s what I see in myself.\" That sentence, spoken honestly, is worth more than a perfect conversation."},{"type":"divider"},{"type":"fillable_form","form_id":"fillable-form-our-devil-dialogue-notes","title":"Fillable Form: Our Devil Dialogue Notes","fields":[{"id":"field_1","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_2","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_3","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_4","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_5","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_6","label":"","type":"textarea","rows":3,"placeholder":""}],"intro":"Complete together during or after the conversation. My top 2-3 Devils:"},{"type":"divider"},{"type":"text","content":"If this conversation brought up something larger than these tools can hold — if it touched a wound that runs deeper than the patterns you named — please reach out to a therapist or counselor. This work matters, and so do you."},{"type":"divider"},{"type":"reflection","content":"After the Devil Dialogue, take a minute with this: What was it like to hear your partner name their own patterns? Did anything shift in how you see them — or how you see the two of you together?"}]}'::jsonb),
    (mod2_id, parent_id, 'Your Module 2 Practice Plan', 404, '{"estimated_minutes":9,"blocks":[{"type":"text","content":"In Module 1, your first practice plan was about building a foundation. You learned to notice your Critter Brain. You picked a Pause Number. You practiced the 30-Second Reset. You tried one SPARK step, then the whole sequence. You completed your first Devil Audit."},{"type":"text","content":"That plan was about awareness. Can I see what''s happening?"},{"type":"text","content":"This plan is different. This plan is about precision. Can I name the specific Devil, catch it in real time, and respond differently?"},{"type":"text","content":"You''re no longer building the foundation. You''re standing on it."},{"type":"divider"},{"type":"fillable_form","form_id":"day-1-spot-the-devil","title":"Day 1 — Spot the Devil","fields":[],"intro":"Your only job today is to catch one Devil, in real time, as it happens. Not after the conversation. Not in reflection that evening. In the moment. Maybe you feel Criticism rising — that tightness in your chest, the \"you always\" forming in your throat before you''ve even decided to say it. Maybe you notice Defensiveness — the instant pivot to \"well, what about when you...\" before your partner has finished their sentence. Maybe you catch Avoidance — the decision, made quietly between one breath and the next, to change the subject instead of going where the conversation actually needs to go. You don''t have to do anything about it yet. Just catch it. Name it to yourself: That''s Criticism. That''s Defensiveness. That''s Avoidance. The catch is the practice. - [ ] Day 1: I caught a Devil in real time. The Devil was: `_______________`"},{"type":"divider"},{"type":"fillable_form","form_id":"day-2-name-the-zone","title":"Day 2 — Name the Zone","fields":[],"intro":"Today, when you feel your system start to move — when something shifts in a conversation and your body responds before your mind catches up — name the Zone you''re heading toward. My system is going Yellow Hyper. I can feel the heat and the speed. Or: I''m drifting toward Yellow Hypo. Everything''s getting foggy and heavy. Say it to yourself. If you can, say it out loud — even quietly. Naming the Zone is like reading a sign on the highway: it doesn''t change where you''re going, but it tells you how far you are from home. And knowing that is how you start to turn around. - [ ] Day 2: I named my Zone during a conversation. The Zone was: `_______________`"},{"type":"divider"},{"type":"heading","content":"Day 3 — Reset Before Reacting"},{"type":"text","content":"Today, when you catch a Devil and name your Zone, add one more step: the 30-Second Reset, before you respond."},{"type":"text","content":"Hand on heart. Three slow breaths. Audible sigh."},{"type":"text","content":"This is the sequence: Catch the Devil. Name the Zone. Reset. Then respond. You are inserting a pause between the activation and the reaction — and in that pause, your CEO Brain has a chance to come back online."},{"type":"text","content":"If the Reset happens after you''ve already reacted, that''s still useful. The goal is to start shrinking the gap between activation and regulation."},{"type":"list","items":["Day 3: I used the 30-Second Reset before (or during) a moment of activation."],"ordered":false},{"type":"divider"},{"type":"fillable_form","form_id":"day-4-aim-spark-at-the-devil","title":"Day 4 — Aim SPARK at the Devil","fields":[],"intro":"Today, try a full or partial SPARK sequence aimed specifically at the Devil you caught on Day 1. If your Devil is Criticism, the SPARK is about catching the \"you always\" before it leaves your mouth and replacing it with a specific observation. See the pattern forming. Pause before you label your partner. Acknowledge what they''re actually feeling underneath the thing that frustrated you. If your Devil is Stonewalling, the SPARK is about naming the shutdown instead of disappearing. See the wall going up. Pause and check your Zone. Acknowledge out loud: \"I''m starting to shut down. I need ten minutes.\" The SPARK doesn''t change because the Devil changes. The entry point changes. Each Devil has a specific moment where SPARK is most useful — the moment just before the pattern takes over. That''s where you aim. - [ ] Day 4: I aimed SPARK at a specific Devil. The Devil was: `_______________`"},{"type":"divider"},{"type":"heading","content":"Day 5 — Reflect With Your Partner"},{"type":"text","content":"Today, share one thing you noticed this week with your partner."},{"type":"text","content":"Not everything. Not the whole audit. One thing. One pattern you caught, one Zone you named, one moment where you saw the old version of yourself show up and chose to respond differently — even slightly."},{"type":"text","content":"The share can be brief. It can be over dinner or on a walk or in the car. What matters is that you are letting your partner into the work you''re doing. That act — \"I want you to see what I''m working on\" — is an act of connection. It says: This isn''t just my project. This is about us."},{"type":"text","content":"If your partner wants to share something back, let them. If they don''t, that''s okay too. You''re not asking for a grade. You''re opening a door."},{"type":"list","items":["Day 5: I shared one observation with my partner."],"ordered":false},{"type":"divider"},{"type":"heading","content":"Day 6 — Full SPARK With Awareness"},{"type":"text","content":"Today, if a real moment comes — a real conversation where your Critter Brain starts to take over — try the full SPARK sequence with the awareness you''ve built this week."},{"type":"text","content":"See the Devil as it shows up. Name the Zone your body is heading toward. Reset if you need to. And then walk through the rest of SPARK: Acknowledge what''s happening for your partner, Reconnect with the \"us,\" and Kindle something worth carrying forward."},{"type":"text","content":"If the moment doesn''t come today, that''s fine. Sit with a recent memory and walk through what you would have done differently. That mental rehearsal still builds the neural pathway."},{"type":"list","items":["Day 6: I used SPARK with full Devil-and-Zone awareness in a real or rehearsed moment."],"ordered":false},{"type":"divider"},{"type":"fillable_form","form_id":"day-7-update-the-audit","title":"Day 7 — Update the Audit","fields":[{"id":"field_1","label":"","type":"textarea","rows":3,"placeholder":""}],"intro":"Come back to the Devil Audit from Sub-Lesson 2.4.2. Not to redo the whole thing — just to check in. After a week of watching the patterns in real time, has anything shifted? Is there a Devil you rated as \"Sometimes\" that you now realize is \"Often\"? Is there one you rated as \"Often\" that you''re starting to catch before it fully lands? Write one or two sentences about what changed. That''s your evidence — not that you''re fixed, not that the pattern is gone, but that you''re seeing it more clearly. Clarity is how this work moves forward. - [ ] Day 7: I updated my Devil Audit and noted what shifted. What I noticed this week:"},{"type":"divider"},{"type":"reflection","content":"Reflection: End of Your Module 2 Practice Week"},{"type":"text","content":"Look at the seven days you just built. This plan asked you to do something different from Module 1''s plan. Module 1 asked: Can you see the patterns? Module 2 asked: Can you catch them while they''re running, name what your body is doing, and choose a different response?"},{"type":"text","content":"That''s a harder ask. And the fact that you''re here, building this plan, tells me something about who you''re becoming in this relationship."},{"type":"text","content":"What do you want to carry into Module 3?"}]}'::jsonb),
    (mod2_id, parent_id, 'The Path Forward', 405, '{"estimated_minutes":7,"blocks":[{"type":"text","content":"We named seven Devils in Module 1. We have faced six of them together."},{"type":"text","content":"The seventh — intimacy — deserves its own conversation, deeper and more tender than a single lesson can hold. It is coming. But not yet. What lives underneath the loss of intimacy is connected to everything you''ll learn in Module 3, and I want you to have those tools before we go there."},{"type":"text","content":"For now, I want you to know: if that seventh Devil has been the quiet ache underneath everything else — if the distance, the loss of warmth, the way reaching for each other has gotten complicated — if that has been the hardest thing to name, you are not alone. And it is workable. We will get there."},{"type":"divider"},{"type":"audio","title":"2:00, Trisha & Jeff together — they share their own Devil patterns as a couple, normalize it, bridge to Module 3"},{"type":"divider"},{"type":"heading","content":"What''s Ahead"},{"type":"text","content":"You have seen the surface patterns — the words that wound, the walls that go up, the things you escape into. You can name them. You can catch them. You are learning to respond to them differently."},{"type":"text","content":"Module 3 goes underneath."},{"type":"text","content":"The Deep Roots. Why you learned to attack, or protect, or run. Not in your marriage — before your marriage. In the family you grew up in. In the earliest relationships that taught you what love looked like, what safety felt like, and what to do when either one disappeared."},{"type":"text","content":"There is a younger version of you who made certain decisions about relationships — decisions that made perfect sense at the time, decisions that kept you safe when you needed to be safe. Some of those decisions are still running your relationship today, decades later, as faithfully as the day they were made."},{"type":"text","content":"Module 3 is about meeting that younger version of yourself. Gently. With compassion. And beginning to update the decisions they made — not because they were wrong, but because you are no longer the person who needed them."},{"type":"text","content":"That work is some of the most meaningful work this program offers. It is also some of the most tender. I want you to go in with your eyes open, your tools ready, and your partner beside you if they''re willing."},{"type":"text","content":"You''re ready for it. I''ve watched you build the awareness to hold it."},{"type":"divider"},{"type":"fillable_form","form_id":"implementation-intention","title":"Implementation Intention","fields":[{"id":"field_1","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_2","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_3","label":"","type":"textarea","rows":3,"placeholder":""},{"id":"field_4","label":"","type":"textarea","rows":3,"placeholder":""}],"intro":"Before you move to Module 3, make this concrete. When will I start Module 3? (Name a day.)"},{"type":"divider"},{"type":"heading","content":"Closing Note from Trisha"},{"type":"text","content":"Hey, love."},{"type":"text","content":"I want you to hear this, because I''m not sure you''ve heard it yet — from yourself or from anyone else."},{"type":"text","content":"What you just did was hard."},{"type":"text","content":"Not the reading. Not the frameworks. Not the fill-in-the-blank parts. The hard part was the looking. The honest, unflinching looking at yourself, at your patterns, at the ways you''ve been showing up in your relationship that weren''t working — and choosing not to look away."},{"type":"text","content":"Most people never do that. Most people spend their whole relationship inside the pattern, fighting the same fight on different Tuesdays, never once stepping far enough back to see the system they''re living in. You stepped back. You named it. You started catching it in real time. And then you sat across from your partner and said, out loud, \"Here''s what I see in myself.\""},{"type":"text","content":"That''s huge."},{"type":"text","content":"I''ve been doing this work for a long time, and I still believe the bravest thing a person can do in a relationship is tell the truth about their own patterns. Not their partner''s patterns. Their own. That kind of honesty doesn''t come from a place of shame. It comes from a place of: I love this person enough to stop hiding from the thing that''s hurting us."},{"type":"text","content":"You did that. In two modules, you did that."},{"type":"text","content":"So here''s what I want you to carry with you: you are not the same person who started Module 1. You might not feel dramatically different — real growth rarely feels dramatic while it''s happening. But the person who started this program didn''t have the language, the tools, or the awareness you have right now. That person didn''t know what a Critter Brain was, or why it mattered. That person didn''t have a Pause Number or a Reset or a way to name the Zone they were in when the conversation started to slip. You have all of that now. And it''s yours. Nobody can take it back."},{"type":"text","content":"Module 3 is going to take you deeper than you''ve gone yet. I won''t pretend it''s easy — the roots run deep, and some of what you''ll find there will be tender. But you have what you need to hold it. I''ve watched you build it, lesson by lesson, practice by practice."},{"type":"text","content":"I''m proud of you. I mean that."},{"type":"text","content":"And I''ll see you in Module 3."},{"type":"divider"},{"type":"reflection","content":"Reflection: A Gratitude and a Takeaway"},{"type":"text","content":"One last time before you close Module 2."},{"type":"text","content":"What''s one thing you''re grateful for from these first two modules — something you learned, something you tried, something you noticed, a moment with your partner that went differently than it would have before?"},{"type":"text","content":"And what''s the one thing you''re taking with you into Module 3?"},{"type":"text","content":"Hold those two things. They''re yours."}]}'::jsonb);

END $$;

-- =====================================================
-- STEP 4: Verification
-- =====================================================

-- Count check: expect 8 parents + 44 sub-lessons = 52 total
DO $$
DECLARE
  total_count integer;
  parent_count integer;
  child_count integer;
BEGIN
  SELECT count(*) INTO total_count
  FROM lessons l
  JOIN modules m ON m.id = l.module_id
  JOIN courses c ON c.id = m.course_id
  WHERE m.module_number IN ('1', '2')
    AND c.slug = 'healing-hearts-journey';

  SELECT count(*) INTO parent_count
  FROM lessons l
  JOIN modules m ON m.id = l.module_id
  JOIN courses c ON c.id = m.course_id
  WHERE m.module_number IN ('1', '2')
    AND c.slug = 'healing-hearts-journey'
    AND l.parent_lesson_id IS NULL;

  child_count := total_count - parent_count;

  IF total_count != 52 THEN
    RAISE EXCEPTION 'Expected 52 lessons, got %', total_count;
  END IF;
  IF parent_count != 8 THEN
    RAISE EXCEPTION 'Expected 8 parent lessons, got %', parent_count;
  END IF;
  IF child_count != 44 THEN
    RAISE EXCEPTION 'Expected 44 sub-lessons, got %', child_count;
  END IF;

  RAISE NOTICE 'Migration 022 verified: % total (% parents, % children)',
    total_count, parent_count, child_count;
END $$;

COMMIT;